INSERT INTO public.questions VALUES ('f2987c7f-0a7e-4e35-906e-5bca3c2d6765', 'b1c799ef-3ccf-4080-bc81-a248236e8575', 'matrix', 'Questions 16-20', NULL, '<p>Label the plan below.</p>
<p>Write the correct letter,<strong> A-H</strong></p>
<p><img loading="lazy" decoding="async" src="data:image/jpeg;base64," width="516" height="594"></p>
<p> </p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Park ''n'' ride car park", "correctCategoryLetter": "A"}, {"itemText": "Bus interchange", "correctCategoryLetter": "G"}, {"itemText": "Bicycle lockers", "correctCategoryLetter": "C"}, {"itemText": "Showers ", "correctCategoryLetter": "D"}, {"itemText": "Lift ", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('cb4e31e9-1f7d-4dd7-a05c-be87a359de70', '32806294-6780-488d-b423-871a0e6397d1', 'matching', 'Questions 1-7 ', NULL, '<p>Reading Passage 1 has seven paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of heading below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Early years of Gilbert"}, {"optionText": "ii. What was new about his scientific research method"}, {"optionText": "iii. The development of chemistry"}, {"optionText": "iv. Questioning traditional astronomy"}, {"optionText": "v. Pioneers of the early science"}, {"optionText": "vi. Professional and social recognition"}, {"optionText": "vii. Becoming the president of the Royal Science Society"}, {"optionText": "viii. The great works of Gilbert"}, {"optionText": "ix. His discovery about magnetism"}, {"optionText": "x. His change of focus"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Questions 1–7: Matching Headings</strong></h3>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">1. Paragraph 1: v (Pioneers of the early science)</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;The 16th and 17th centuries saw two great <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"54\">pioneers</strong> of modern science: Galileo and Gilbert.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giới thiệu Gilbert cùng với Galileo là những người tiên phong khởi đầu cho khoa học hiện đại.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">2. Paragraph 2: i (Early years of Gilbert)</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Born in an eminent local family&#8230; 1544, he went to grammar school, and then studied medicine&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này cung cấp thông tin về gia thế, ngày sinh và quá trình học tập thời trẻ của ông.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">3. Paragraph 3: vi (Professional and social recognition)</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;election to the president of the Royal Science Society. He was also appointed personal physician to the Queen&#8230; knighted by the Queen.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Liệt kê các thành tựu nghề nghiệp (bác sĩ) và sự công nhận từ xã hội/hoàng gia (được phong hiệp sĩ, làm chủ tịch hiệp hội khoa học).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">4. Paragraph 4: x (His change of focus)</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gilbert was first interested in chemistry but <strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"58\">later changed his focus</strong>&#8230; He gradually developed his interest in physics&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô tả quá trình Gilbert từ bỏ hóa học (vì tính thần bí của thuật giả kim) để chuyển sang nghiên cứu vật lý và nam châm.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,4,0\"><strong data-path-to-node=\"3,4,0\" data-index-in-node=\"0\">5. Paragraph 5: ix (His discovery about magnetism)</strong></p>\n<ul data-path-to-node=\"3,4,1\">\n<li>\n<p data-path-to-node=\"3,4,1,0,0\"><strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gilbert’s <strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"22\">discovery</strong> was so important&#8230; He investigated the nature of magnetism&#8230; coined the word &#8216;electric&#8217;&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,4,1,1,0\"><strong data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tập trung vào các phát hiện cụ thể của ông về từ tính và điện lực sơ khai.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,5,0\"><strong data-path-to-node=\"3,5,0\" data-index-in-node=\"0\">6. Paragraph 6: iv (Questioning traditional astronomy)</strong></p>\n<ul data-path-to-node=\"3,5,1\">\n<li>\n<p data-path-to-node=\"3,5,1,0,0\"><strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;He also <strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"20\">questioned the traditional astronomical beliefs</strong>&#8230; stars are not equidistant from the earth&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,5,1,1,0\"><strong data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trình bày những quan điểm khác biệt của ông so với thiên văn học truyền thống thời bấy giờ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,6,0\"><strong data-path-to-node=\"3,6,0\" data-index-in-node=\"0\">7. Paragraph 7: ii (What was new about his scientific research method)</strong></p>\n<ul data-path-to-node=\"3,6,1\">\n<li>\n<p data-path-to-node=\"3,6,1,0,0\"><strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;His <strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"16\">research method was revolutionary</strong> in that he used <strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"66\">experiments</strong> rather than pure logic&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,6,1,1,0\"><strong data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhấn mạnh sự thay đổi mang tính cách mạng trong phương pháp nghiên cứu: dùng thực nghiệm thay vì chỉ dùng suy luận lý thuyết.</p>\n</li>\n</ul>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('80d84804-60e2-459d-ac16-c1c94b1a31cf', 'b29e4311-1d3f-4a19-a395-a97c9f902f1c', 'matrix', 'Questions 14–17', NULL, '<p>Reading Passage 2 has seven sections, <strong>A-G</strong>.</p>
<p>Which section contains the following information?</p>
<p>Choose the correct letter, <strong>A-G</strong>, in boxes 14-17.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a prediction as to the direction in which the jellyfish population may spread", "correctCategoryLetter": "E"}, {"itemText": "a description of some physical characteristics of jellyfish", "correctCategoryLetter": "A"}, {"itemText": "an account of the consequences of jellyfish as lone survivors", "correctCategoryLetter": "F"}, {"itemText": "suggestions on how to avoid further jellyfish invasions", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p><strong>14. a prediction as to the direction in which the jellyfish population may spread</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong>Đáp án: E</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “As water warms, tropical species are moving towards the poles. <strong>Many venomous jellyfish species are tropical and could move into more densely populated subtropical and temperate regions</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn E dự đoán hướng lây lan địa lý (hướng về các cực – towards the poles, và các vùng ôn đới/cận nhiệt đới) do sự nóng lên toàn cầu (climate change).</li>\n</ul>\n<p><strong>15. a description of some physical characteristics of jellyfish</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án: A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “…they <strong>lack sharp claws, piercing teeth or even a brain</strong>. Despite this, they are armed with an amazing arsenal of weapons, especially the stinging power of their <strong>tentacles</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn A mô tả các đặc điểm vật lý cơ bản (thiếu não, không có răng, có xúc tu chích).</li>\n</ul>\n<p><strong>16. an account of the consequences of jellyfish as lone survivors</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án: F</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “One can thus think of two alternate states… one dominated by fish and the other by jellyfish. Unfortunately, where there is a jellyfish-dominated state then <strong>this does not support the nutritional needs of other fish, marine mammals, and seabirds</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn F mô tả hậu quả của hệ sinh thái bị chi phối bởi sứa (“monoculture of jellyfish”)—chúng không hỗ trợ nhu cầu dinh dưỡng cho các loài khác (lone survivors).</li>\n</ul>\n<p><strong>17. suggestions on how to avoid further jellyfish invasions</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án: G</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Richardson and his colleagues <strong>propose focusing on ‘prevention rather than cure’</strong>. They <strong>recommend a halt to overfishing</strong> small fish… <strong>reducing the amount of fertilizer and sewage</strong> running off… and finally, if possible, <strong>confronting climate change</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn G đưa ra các biện pháp đề xuất để ngăn chặn (avoid further) các cuộc xâm lăng của sứa trong tương lai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('fdf35445-838f-41d8-ace1-27bedc527bbf', '060419de-7ae1-4956-a075-106f4a17f49d', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Nancy Athfield found ancient human remains in Cambodia."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The human remains found in the Cardamom mountains were in good condition."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield has taken time off from her usual job to do research in Cambodia."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Cambodian government asked Athfield to radiocarbon date the Cardamom remains."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Film-makers were researching how Angkor was rebuilt after the 1431 invasion."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield initially doubted the stories of the royal family hiding in the Cardamom mountains."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield''s research disproved the idea that the Cardamom remains were from the royal family."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Câu 1: Nancy Athfield found ancient human remains in Cambodia.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The unexplained remains, <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"37\">discovered by local people</strong> in large ceramic jars and hollowed-out logs…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nêu rõ hài cốt do người dân địa phương phát hiện, không phải do Nancy Athfield trực tiếp tìm thấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 2: The human remains found in the Cardamom mountains were in good condition.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The unexplained remains… in large ceramic jars and hollowed-out logs…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ mô tả nơi chứa hài cốt (chậu gốm, thân cây rỗng) chứ không đề cập đến tình trạng (tốt hay xấu) của chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 3: Athfield has taken time off from her usual job to do research in Cambodia.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…have increasingly <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"33\">drawn Athfield away from her regular employment</strong> at G.N.S. Science’s Rafter Laboratory… into the world of research in the field.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “drawn away from her regular employment” đồng nghĩa với việc cô ấy tạm rời xa công việc thường nhật để đi nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 4: The Cambodian government asked Athfield to radio carbon date the Cardamom remains.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…when a <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"22\">film-making company</strong> requested that she radiocarbon date bone samples…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Người yêu cầu cô thực hiện việc định tuổi carbon là một công ty làm phim, không phải chính phủ Campuchia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Câu 5: Film-makers were researching how Angkor was rebuilt after the 1431 invasion.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The film-makers had set out to investigate the idea that these human remains marked the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"100\">final resting place of people belonging to the last royal household of Angkor</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mục đích của các nhà làm phim là tìm hiểu xem liệu hài cốt có phải là của hoàng gia Angkor hay không, chứ không phải nghiên cứu việc tái thiết thành phố.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Câu 6: Athfield initially doubted the stories of the royal family hiding in the Cardamom mountains.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…many stories were told of surviving members of the royal family fleeing to seek refuge in the Cardamom Mountains.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến các câu chuyện về hoàng gia, nhưng không nói về cảm xúc hay quan điểm cá nhân (nghi ngờ hay tin tưởng) của Athfield lúc ban đầu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 7: Athfield’s research disproved the idea that the Cardamom remains were from the royal family.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Athfield dated the original Cardamom bone samples to as late as 1620, <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"82\">dashing the possibility of Angkorian royalty</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả giám định (năm 1620) đã dập tắt (dashing) khả năng đây là người của hoàng gia Angkor (vốn bị lật đổ từ năm 1431).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('bb43f88a-076c-43ae-82cd-0e1a4178b33b', '92d8da2a-515b-489e-8c21-b2b5bb0d952a', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>The bluestriped fangblenny</strong></span></p>
<p>Dr Karen Cheney studies the bluestriped fanblenny on {reefs} off Queensland’s coast. She found that the fangblenny was able to make itself resemble other fish by adjusting its colouration. The fangblenny impersonates the striped cleaner wrasse, a fish that is welcomed by other specie as it gets rid of their {parasites} The fangblenny can approach its {prey} without drawing the attention of predators or disturbing the work of the striped cleaner.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. reefs</strong></p>\n<ul data-path-to-node=\"28\">\n<li><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"16\">D</strong>: “On Queensland’s <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"36\">reefs</strong>, scientists have been studying another ocean dweller…”</li>\n<li><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiến sĩ Karen Cheney nghiên cứu loài cá Bluestriped fangblenny tại các rạn san hô (reefs).</li>\n</ul>\n<p><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. parasites</strong></p>\n<ul data-path-to-node=\"30\">\n<li><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"16\">D</strong>: “…cleaner wrasse which eats the <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"53\">parasites</strong> on larger fish.”</li>\n<li><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cá bống dọn dẹp (cleaner wrasse) giúp các loài cá lớn loại bỏ ký sinh trùng (parasites).</li>\n</ul>\n<p><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. prey</strong></p>\n<ul data-path-to-node=\"32\">\n<li><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"16\">D</strong>: “…the disguise also lets it get closer to <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"63\">prey</strong>.”</li>\n<li><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhờ giả dạng cá dọn dẹp, cá Fangblenny có thể tiếp cận con mồi (<strong data-path-to-node=\"32,1,0\" data-index-in-node=\"76\">prey</strong>) của nó một cách dễ dàng mà không bị nghi ngờ.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('b546eb18-976c-4e1d-be28-d40149894013', '44c4ef30-2cec-47f7-8de1-1d1eaf1297d0', 'matrix', 'Questions 27-32', NULL, '<p>Look at the following statements (Questions 27-32) and the list of people or groups below.</p>
<p>Choose each statement with the correct person or group, A, B, C or D.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "The elderly would benefit from drug containers that do not require force to open them.", "correctCategoryLetter": "C"}, {"itemText": "Adapting packaging for the blind may disadvantage people who can see.", "correctCategoryLetter": "D"}, {"itemText": " Specially designed containers have not been able to eliminate drugs being swallowed accidentally.", "correctCategoryLetter": "B"}, {"itemText": " Designers have to consider how drugs are used in the home.", "correctCategoryLetter": "A"}, {"itemText": "Governing bodies need to compare different drug containers rather than studying individual ones.", "correctCategoryLetter": "D"}, {"itemText": " Information provided with medicine is not listed in the right order.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Thea Swayne", "categoryLetter": "A"}, {"categoryText": "The Child Accident Prevention Trust", "categoryLetter": "B"}, {"categoryText": "Richard Mawle", "categoryLetter": "C"}, {"categoryText": "Karel van der Waarde", "categoryLetter": "D"}]}', '[{"content": "<p><strong class=\"\" data-path-to-node=\"2\" data-index-in-node=\"0\">27. The elderly would benefit from drug containers that do not require force to open them.</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">C (Richard Mawle)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"16\">Safety and compliance</em><span class=\"\">,</span><span class=\"\"> dòng 4-6:</span><span class=\"\"> &#8220;Richard Mawle&#8230;</span><span class=\"\"> feels it is not just children who are blocked by child-proof closures.</span><span class=\"\"> ‘Many child-resistant packs are based on strength but </span><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"192\">older people may have the same level of strength as a child</strong><span class=\"\">,</span><span class=\"\">’ he explained&#8230;</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Richard Mawle nhận định các thiết kế nắp chống trẻ em hiện nay dựa quá nhiều vào sức mạnh cơ bắp (lực mở),</span><span class=\"\"> điều này vô tình gây khó khăn cho người già vì thể lực của họ có thể suy giảm xuống mức tương đương trẻ em.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">28. Adapting packaging for the blind may disadvantage people who can see.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">D (Karel van der Waarde)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"16\">Design principles and guidelines</em><span class=\"\">,</span><span class=\"\"> dòng 10-12:</span><span class=\"\"> &#8220;&#8230;</span><span class=\"\">according to Karel van der Waarde&#8230;</span><span class=\"\"> ‘it is not known how much visually impaired patients will benefit nor </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"173\">how much the reading of visually able patients will be impaired</strong><span class=\"\">’.</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Van der Waarde hoài nghi về quy định in chữ Braille lên bao bì,</span><span class=\"\"> vì việc này có thể gây cản trở hoặc làm khó khăn cho việc đọc thông tin của những người có thị lực bình thường.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">29. Specially designed containers have not been able to eliminate drugs being swallowed accidentally.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">B (The Child Accident Prevention Trust)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"16\">Safety and compliance</em><span class=\"\">,</span><span class=\"\"> dòng 2-3:</span><span class=\"\"> &#8220;According to the Child Accident Prevention Trust&#8230;</span> <strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">although child-resistant lids have helped, they are not yet fully effective</strong><span class=\"\">.</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tổ chức này đưa ra dữ liệu thực tế cho thấy các loại hộp được thiết kế đặc biệt (nắp chống trẻ em) vẫn chưa thể loại bỏ hoàn toàn việc trẻ em vô tình nuốt nhầm thuốc.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">30. Designers have to consider how drugs are used in the home.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">A (Thea Swayne)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"16\">Design considerations</em><span class=\"\">,</span><span class=\"\"> dòng cuối:</span><span class=\"\"> &#8220;&#8230;</span><span class=\"\">real situations in which medicines are used include a parent giving a cough medicine to a child in the middle of the night; </span><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"178\">packaging should be designed for moments such as these</strong><span class=\"\">&#8230;</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thea Swayne cho rằng nhà thiết kế cần tính đến bối cảnh sử dụng thuốc tại gia đình (ví dụ:</span><span class=\"\"> uống thuốc trong bóng tối lúc nửa đêm) thay vì chỉ thiết kế cho môi trường lý tưởng như bệnh viện.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">31. Governing bodies need to compare different drug containers rather than studying individual ones.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">D (Karel van der Waarde)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"16\">Design principles and guidelines</em><span class=\"\">,</span><span class=\"\"> dòng 14-15:</span><span class=\"\"> &#8220;‘They [regulatory authorities] do not look at the use of packaging in a practical context – </span><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"155\">they only see one box at a time and not several together</strong><span class=\"\"> as pharmacists would do,</span><span class=\"\">’ he said.</span><span class=\"\">&#8220;</span></li>\n<li><strong class=\"\" data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Van der Waarde phê phán các cơ quan quản lý vì họ chỉ kiểm tra từng hộp thuốc đơn lẻ mà thiếu việc đặt chúng cạnh nhau để so sánh độ nhiễu/nhầm lẫn thông tin như trong thực tế.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">32. Information provided with medicine is not listed in the right order.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">C (Richard Mawle)</strong></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <em data-path-to-node=\"13,1,0\" data-index-in-node=\"16\">Safety and compliance</em>, dòng cuối: &#8220;Mawle&#8230; said: ‘There can be an awful lot of junk at the beginning of PILs. For example, <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"140\">why are company details towards the beginning&#8230; when what might be more vital for the patient is&#8230;</strong>’&#8221;</li>\n<li><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Mawle chỉ ra rằng thứ tự thông tin trong tờ hướng dẫn sử dụng đang bị ngược, đưa những thông tin ít quan trọng (như chi tiết công ty) lên đầu thay vì các cảnh báo an toàn cấp thiết cho bệnh nhân.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('59c2c960-9164-4331-ba40-94306527403e', '619fba5b-6c8a-4832-b674-507928c622a3', 'fillup', 'Questions 37–40', '<p>Complete the summary below.<br />Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"> Unintended ecological effects of using guard dogs</h3>
<p>In Namibia, livestock guard dogs have been used to protect domestic animals from attacks by cheetahs.</p>
<p>This has led to a rise in the deaths of other predators, particularly {jackals}. In addition, it has been suggested that the dogs could have {diseases} which may affect other species, and that they may reduce the amount of {food} available to certain wild animals.</p>
<p>On the other hand, these dogs may help birds by protecting their nests. These might otherwise be threatened by predators such as {foxes}.</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>37. jackals<br />(Đoạn F: “&#8230;the number of jackals killed by dogs and people actually increased.”)<br />→ Chó bảo vệ giúp giảm số lượng cheetah bị giết, nhưng số lượng chó rừng (jackals) bị giết lại tăng. → jackals.</p>\n<p> <br />38. diseases<br />(Đoạn F: “They have been found to spread diseases to wild animals&#8230;”)<br />→ Chó bảo vệ có thể lây bệnh sang động vật hoang dã. → diseases.</p>\n<p> <br />39. food<br />(Đoạn F: “They may also compete with other carnivores for food.”)<br />→ Chó bảo vệ tranh giành nguồn thức ăn với các loài săn mồi khác. → food.</p>\n<p> <br />40. foxes<br />(Đoạn G: “&#8230;protect bird species&#8230; where foxes would normally raid them.”)<br />→ Sự có mặt của chó giúp chim tránh bị cáo (foxes) tấn công. → foxes.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('59a37dbe-7625-48ae-b619-73d8e1716bf7', 'de3dcc6f-c470-4d29-9183-b5b42227c2b2', 'fillup', ' Questions 14–17', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>Malaria in 19th-century Italy</strong></p>
<p class="ql-align-justify">Up until the late nineteenth century, experts failed to make the connection between malaria and {insects}. The most popular belief at the time was the {miasma} theory, which upheld the idea that diseases were carried by unclean air. Another common idea was that malaria was a {hereditary} disease, and as a result people from certain parts of the country were often held responsible for the spread of epidemics. Malaria was particularly widespread in rural regions, where {life expectancy} could be extremely short.</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Câu 14: …experts failed to make the connection between malaria and {insects}.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> insects</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Others made a link between swamps, water and malaria, but did not make the further leap towards <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"108\">insects</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nêu rõ các chuyên gia thời đó chưa thể kết nối mối liên hệ giữa bệnh và côn trùng (cụ thể là muỗi).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Câu 15: The most popular belief at the time was the {miasma} theory…</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> miasma</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But in the 19th century most experts subscribed to the theory of ‘<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"78\">miasma</strong>‘ or ‘poisoning of the air’.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý thuyết phổ biến nhất thời bấy giờ về nguyên nhân gây bệnh là thuyết “miasma” (khí độc).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Câu 16: Another common idea was that malaria was a {hereditary} disease…</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> hereditary</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…given the widespread belief that malaria was <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"60\">hereditary</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một niềm tin sai lầm khác là bệnh sốt rét có tính di truyền.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Câu 17: …where {life expectancy} could be extremely short.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> life expectancy</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In warm, damp, malarial zones, the <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"47\">life expectancy</strong> of land workers was a terrifying 22.5 years.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tại các vùng nông thôn bị ảnh hưởng, tuổi thọ trung bình của người dân rất thấp.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('1a87e040-6551-45e0-b414-5ba937f0ec64', 'fe110040-9bd9-4b3e-a043-a7975f07dd37', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Historical patterns of interrupted sleep</strong></p>
<p>Historical evidence seems to show that humans had common sleep patterns which were quite unlike today’s eight hours of unbroken sleep each night. People habitually went to bed early, soon after {sunset} slept for a while, then woke up for a few hours of activity or perhaps to consider, for example, the meaning of {dreams} There was little else to do at home in the dark, since what little means of lighting they had, such as using candles, was costly. In 16th-century Europe, people tended to stay at home at night because they feared {thieves} on large unit city. Once urban street lighting improved, night life in cities became popular, and recreational spots, like coffee houses came to be considered fashionable. Consequently, sleeping patterns also began to change.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>24. People habitually went to bed early, soon after sunset…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>sunset</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) Mô hình ngủ chia đoạn có “a first sleep which began <strong>not long following sunset</strong>.”</li>\n</ul>\n<p><strong>25. …perhaps to consider, for example, the meaning of dreams…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>dreams</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “…people used the time that they were awake between periods of sleep to think about and attempt to analyse their <strong>dreams</strong>.”</li>\n</ul>\n<p><strong>26. In 16th-century Europe, people tended to stay at home at night because they feared thieves…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>thieves</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “the streets of cities and towns at night were often populated by <strong>thieves</strong> or worse.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('c63470fd-b6a8-4d07-9f74-4a59f304fdff', '77a79df9-6818-44df-8e3e-e0aec627992d', 'radio', 'Questions 1–7', '', '<p data-start="18" data-end="220">Choose <strong data-start="25" data-end="33">TRUE</strong> if the statement agrees with the information given in the text, choose <strong data-start="105" data-end="114">FALSE</strong> if the statement contradicts the information, or choose <strong data-start="171" data-end="184">NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The cranberry requires a specific soil type to enable it to grow successfully"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "A layer of clay protects kettle ponds from harmful substances which could affect the water quality"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the past, the Wampanoag people had to consume most cranberries shortly after picking them"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Wampanoag people took advantage of the medicinal properties of cranberries"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The first settlers in North America brought European varieties of cranberry with them when they arrived"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Captain Hall tried growing other fruit crops before cultivating cranberries"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It took a long time for Captain Hall’s methods of cultivation to become popular among other cranberry producers"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. TRUE — The cranberry requires a specific soil type to enable it to grow successfully.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“These small, crimson berries thrive only in very unique environmental conditions, particularly in soil that is both sandy and acidic.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói quả nam việt quất đòi hỏi một loại đất cụ thể (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"71\">a specific soil type</em>) để có thể phát triển thành công. Bài đọc xác nhận loài quả này chỉ phát triển mạnh (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"177\">thrive only</em>) trong điều kiện môi trường rất độc đáo, cụ thể là đất phải vừa có cát vừa có tính axit (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"278\">sandy and acidic</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. TRUE — A layer of clay protects kettle ponds from harmful substances which could affect the water quality.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“The clay bottom acts as a protective barrier, preventing harmful substances from entering the pond and preserving the clean water essential for healthy vines.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói một lớp đất sét bảo vệ các ao kettle khỏi các chất độc hại gây ảnh hưởng chất lượng nước. Bài đọc khẳng định phần đáy bằng đất sét đóng vai trò như một rào cản bảo vệ (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"192\">protective barrier</em>), ngăn chặn các chất có hại (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"240\">harmful substances</em>) xâm nhập vào ao để bảo vệ nguồn nước sạch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. FALSE — In the past, the Wampanoag people had to consume most cranberries shortly after picking them.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“The fruit''s sharp taste lent itself to preservation techniques; communities developed methods of drying and combining cranberries with other foods to extend their usefulness during months when fresh plants were scarce.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói trong quá khứ người Wampanoag phải tiêu thụ hầu hết quả nam việt quất ngay sau khi hái (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"112\">shortly after picking them</em>). Ngược lại, bài đọc chỉ ra họ đã phát triển các kỹ thuật bảo quản (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"207\">preservation techniques</em>), sấy khô (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"242\">drying</em>) để kéo dài thời gian sử dụng (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"280\">extend their usefulness</em>) vào những tháng khan hiếm. Thông tin mâu thuẫn trực tiếp nên chọn <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"371\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. TRUE — The Wampanoag people took advantage of the medicinal properties of cranberries.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“In addition to dietary uses, the Wampanoag also employed the berry in first-aid traditions: crushed fruit was applied to sores and minor wounds, reflecting a practical knowledge of its cleansing properties.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói người Wampanoag đã tận dụng các đặc tính chữa bệnh/dược tính (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"86\">medicinal properties</em>) của quả nam việt quất. Bài đọc viết họ áp dụng loại quả này vào truyền thống sơ cứu (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"193\">first-aid traditions</em>), đắp quả giã nát lên các vết loét và vết thương nhỏ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"268\">applied to sores and minor wounds</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. FALSE — The first settlers in North America brought European varieties of cranberry with them when they arrived.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“Rather than attempting to transplant European varieties, the newcomers adopted the native species already adapted to regional conditions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định những người định cư đầu tiên mang theo các giống việt quất châu Âu (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"99\">brought European varieties</em>) khi họ đến. Ngược lại, bài đọc viết rằng thay vì cố gắng cấy ghép các giống châu Âu, những người mới đến đã tiếp nhận và dùng luôn các loài bản địa (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"276\">adopted the native species</em>) sẵn có. Thông tin bị trái ngược hoàn toàn nên chọn <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"355\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. NOT GIVEN — Captain Hall tried growing other fruit crops before cultivating cranberries.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“One Massachusetts grower, Captain Henry Hall, observed that windblown sand reaching his beds improved fruit quality and yield.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ giới thiệu Captain Henry Hall là một người trồng trọt ở Massachusetts và ông đã tình cờ phát hiện ra việc rải cát giúp cải thiện chất lượng quả việt quất. Bài viết <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"188\">hoàn toàn không có thông tin</strong> nào nói về việc trước đó ông ấy có từng thử trồng các loại cây ăn quả khác (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"293\">tried growing other fruit crops</em>) hay chưa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. NOT GIVEN — It took a long time for Captain Hall’s methods of cultivation to become popular among other cranberry producers.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“He began deliberately applying sand to his plots and found that the practice changed both soil texture and pest incidence for the better.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói hành động rải cát của Hall là một bước tiến quan trọng hướng tới việc canh tác nam việt quất có hệ thống, nhưng <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"139\">không hề đề cập</strong> đến việc mất bao lâu để phương pháp của ông trở nên phổ biến (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"217\">become popular</em>) đối với các nhà sản xuất khác.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('706ef43c-9db9-4b35-9b1b-77da85bfed72', '77a79df9-6818-44df-8e3e-e0aec627992d', 'fillup', 'Questions 8–13', '<h3 data-section-id="1i6hwlk" data-start="999" data-end="1028">Complete the notes below.</h3>
<p data-start="1029" data-end="1069"><strong data-start="1029" data-end="1069">Write ONE WORD ONLY for each answer.</strong></p>
<h3 data-section-id="cbrkp1" data-start="1071" data-end="1108">The Cycle of Cranberry Production</h3>
<p data-start="1110" data-end="1120"><strong data-start="1110" data-end="1120">Winter</strong></p>
<ul data-start="1121" data-end="1294">
<li data-section-id="1hmw1tk" data-start="1121" data-end="1168">Growers {flood} the bogs to protect vines.</li>
<li data-section-id="lrh3e3" data-start="1169" data-end="1235">Sand is put on bogs to increase {drainage} and encourage growth.</li>
<li data-section-id="x1swfl" data-start="1236" data-end="1294">Trees are removed to promote the movement of {air}.</li>
</ul>
<p data-start="1296" data-end="1306"><strong data-start="1296" data-end="1306">Spring</strong></p>
<ul data-start="1307" data-end="1396">
<li data-section-id="1nqmfp1" data-start="1307" data-end="1357">{water} is supplied to protect against frost.</li>
<li data-section-id="1ss8529" data-start="1358" data-end="1396">{maintenance} is done to control pests.</li>
</ul>
<p data-start="1398" data-end="1408"><strong data-start="1398" data-end="1408">Summer</strong></p>
<ul data-start="1409" data-end="1447">
<li data-section-id="1y2ew4j" data-start="1409" data-end="1447">Growers check for {weed} growth.</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. flood — {Growers flood the bogs to protect vines.}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“In winter farmers often choose to flood the bogs, forming a protective layer that freezes and insulates the vines from extreme cold and drying winds.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa đông, các nông dân thường chọn cách bơm nước làm ngập (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"75\">flood</strong>) các đầm lầy để tạo lớp bảo vệ cho các tổ dây leo. Từ cần điền là động từ phù hợp với chủ ngữ số nhiều <em data-path-to-node=\"21,1,0\" data-index-in-node=\"184\">Growers</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. drainage — {Sand is put on bogs to increase drainage and encourage growth.}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“On the frozen surface, sand is sometimes scattered so that, when thawed, the particles work into the bed and improve overall drainage, encouraging fresh shoots to establish.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"increase\" (tăng cường) trong câu hỏi đồng nghĩa với từ \"improve\" (cải thiện) trong bài đọc. Việc rải cát giúp cải thiện/tăng cường khả năng thoát nước (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"168\">drainage</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. air — {Trees are removed to promote the movement of air.}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“To reduce disease risk and improve crop vigour, farmers also remove trees and scrub beside the bogs so that air can move through the site more freely...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"promote the movement of...\" (thúc đẩy sự chuyển động của...) đồng nghĩa với cụm \"...can move through the site more freely\" (có thể di chuyển tự do hơn qua khu vực). Thứ di chuyển ở đây chính là không khí (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"225\">air</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. water — {water is supplied to protect against frost.}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"27,0,0\" data-index-in-node=\"26\">“With the coming of spring, the frozen cover is managed and water levels are adjusted; controlled water applications may be used at vulnerable times to shield budding shoots from sudden frosts.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa xuân, từ \"supplied\" (cung cấp) tương ứng với cụm \"water applications\" (việc áp dụng/bơm nước). Nước (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"121\">water</strong>) được cấp vào nhằm bảo vệ chồi non khỏi sương giá đột ngột (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"187\">shield budding shoots from sudden frosts</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. maintenance — {maintenance is done to control pests.}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“During this phase growers perform routine maintenance on channels, pumps and irrigation lines and take steps to reduce pest pressure before the plants enter full growth.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để kiểm tra và giảm áp lực sâu bệnh (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"49\">reduce pest pressure / control pests</em>), những người trồng trọt tiến hành thực hiện việc bảo trì định kỳ (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"153\">maintenance</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. weed — {Growers check for weed growth.}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“Farmers inspect beds for any sign of weed emergence that would compete with the crop for nutrients and light, removing intruders promptly to protect potential yields.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa hè, từ \"check for\" (kiểm tra) đồng nghĩa với động từ \"inspect\" (thanh tra, xem xét). Từ \"growth\" (sự phát triển) tương ứng với danh từ \"emergence\" (sự xuất hiện/nhô lên). Thứ mà người nông dân cần kiểm tra xem có mọc lên không là cỏ dại (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"258\">weed</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('7d72f90f-c4e9-4bde-820f-44f821f9877b', '44c4ef30-2cec-47f7-8de1-1d1eaf1297d0', 'radio', 'Questions 38-40', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "a printing error"}, {"content": "the style of print"}, {"content": "an incorrect label"}, {"content": "the shape of the bottle"}], "question": "In the accident mentioned in the passage, what was the ‘design consideration’ that caused a drug to be given incorrectly?"}, {"correct": 2, "options": [{"content": "Consumers would dislike this option."}, {"content": "Drug containers would all look too similar."}, {"content": "People would pay more attention to label information."}, {"content": "Partially sighted people would find these colours more helpful."}], "question": "What do some people say about the use of only black and white as a design feature?"}, {"correct": 0, "options": [{"content": "to show that progress is being made in pharmaceutical packaging design"}, {"content": "to give an example of pharmaceutical design problems that can cause accidents"}, {"content": "to prove that a lot of work still needs to be done to improve pharmaceutical packaging design"}, {"content": "to point out that patients need to be more informed about pharmaceutical products"}], "question": "Why does the writer refer to ‘the popper’ and ‘Pluspoint’?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">38. In the accident mentioned in the passage, what was the ‘design consideration’ that caused a drug to be given incorrectly?</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: the style of print</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"16\">Design considerations</strong>, dòng 6-7: &#8220;Investigations following this tragedy attributed some blame to the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"117\">poor choice of typescript</strong> used on the drug container.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> &#8220;Typescript&#8221; chính là kiểu chữ hay phong cách in ấn (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"65\">style of print</strong>). Cuộc điều tra vụ tai nạn (tiêm nhầm thuốc vào tủy sống thay vì tĩnh mạch) đã chỉ ra rằng việc lựa chọn kiểu chữ không phù hợp trên nhãn thuốc là một nguyên nhân gây nhầm lẫn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">39. What do some people say about the use of only black and white as a design feature?</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: People would pay more attention to label information.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"16\">Design principles and guidelines</strong>, dòng 4-6: &#8220;One argument is that if all packaging was white with black lettering, <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"131\">people would have no choice but to read every box carefully</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số ý kiến cho rằng nếu tất cả bao bì chỉ có hai màu đen trắng, người dùng sẽ không bị xao nhãng bởi màu sắc và bắt buộc phải đọc kỹ các thông tin ghi trên nhãn (<strong data-path-to-node=\"5,2,0\" data-index-in-node=\"177\">pay more attention to label information</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">40. Why does the writer refer to ‘the popper’ and ‘Pluspoint’?</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: to show that progress is being made in pharmaceutical packaging design</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"16\">Innovation</strong>, dòng 1-2: &#8220;On a <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"44\">positive note</strong>, a recent <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"68\">innovation</strong> exhibition revealed several <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"107\">new designs</strong>. ‘The popper’ aims to&#8230; and ‘Pluspoint’ is&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhắc đến &#8220;The popper&#8221; (dụng cụ giúp người đau khớp lấy thuốc) và &#8220;Pluspoint&#8221; (bút tiêm adrenaline nhỏ gọn) trong phần &#8220;Innovation&#8221; (Sự đổi mới) để chứng minh rằng ngành thiết kế bao bì dược phẩm đang có những bước tiến triển tích cực (<strong data-path-to-node=\"7,2,0\" data-index-in-node=\"255\">progress is being made</strong>).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('25c755c4-1357-4b2e-b3b3-dbcdbfc98b25', 'ecfde2e6-658b-42aa-8c35-d814b69f025e', 'fillup', 'Questions 14–17', '<p data-section-id="1lzk6qv" data-start="17" data-end="48">Complete the summary below.</p>
<p data-start="49" data-end="106">Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-section-id="gfztrg" data-start="108" data-end="130"><span style="font-size: 14pt;"><strong>Insomnia in the USA</strong></span></p>
<p data-start="132" data-end="523">Last year the high number of {prescriptions} doctors gave their patients highlights the fact that insomnia is a serious issue in the USA. It is evidently responsible for a number of serious traffic {accidents} and has a considerable effect on company {productivity}. A lack of sleep can also have a harmful effect on different relationships, although there are no statistics on this.</p>
<p data-start="525" data-end="710">Unfortunately, there is insufficient official funding given to research into sleep problems, and the {training} given at medical school is also insufficient to deal with insomnia.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. prescriptions — {...the high number of prescriptions doctors gave...}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Fifty-six million prescriptions for sleeping medication were handed out by doctors in America last year.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn tóm tắt nói về số lượng lớn thứ mà bác sĩ đưa cho bệnh nhân vào năm ngoái. Bài đọc chỉ ra đó là 56 triệu đơn thuốc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"137\">prescriptions</strong>) cho các loại thuốc ngủ được phân phát bởi các bác sĩ ở Mỹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. accidents — {...responsible for a number of serious traffic accidents...}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“The Institute of Medicine... estimates nearly 20 percent of all major accidents on the road are associated with driver sleepiness.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"traffic accidents\" (tai nạn giao thông) tương ứng với cụm từ \"accidents on the road\" (tai nạn trên đường phố) trong bài đọc do tình trạng buồn ngủ của tài xế gây ra. Từ cần điền là danh từ số nhiều <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"218\">accidents</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. productivity — {...has a considerable effect on company productivity.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“The loss in terms of productivity within the workplace is even higher, costing billions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Effect on company...\" (ảnh hưởng tới... của công ty) tương ứng với cụm từ \"loss in terms of productivity within the workplace\" (sự tổn thất về mặt năng suất tại nơi làm việc). Từ cần điền là danh từ <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"212\">productivity</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. training — {...and the training given at medical school is also insufficient...}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“Currently most medical school students get no more than four hours of training on sleep disorders; some get none.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói về thứ được cung cấp ở trường y bị thiếu thốn, không đủ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"81\">insufficient</em>). Bài đọc viết các sinh viên trường y hiện chỉ nhận được không quá 4 tiếng tập huấn/đào tạo (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"187\">training</strong>) về các chứng rối loạn giấc ngủ.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f31ed908-db0e-4851-a298-c6812ef2c706', 'ecfde2e6-658b-42aa-8c35-d814b69f025e', 'matrix', 'Questions 18–23', '', '<p data-section-id="1723hv1" data-start="866" data-end="921">Which paragraph contains the following information?</p>
<p data-start="923" data-end="958">Choose the correct letter, <strong>A</strong><strong data-start="950" data-end="957">–</strong><strong>I</strong>.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a mention of different cultural approaches to dealing with insomnia", "correctCategoryLetter": "H"}, {"itemText": "indications that sleep has a positive effect on health", "correctCategoryLetter": "E"}, {"itemText": "the effects of different kinds of sleep on mental performance", "correctCategoryLetter": "C"}, {"itemText": "reasons why various species of animal sleep in different ways", "correctCategoryLetter": "B"}, {"itemText": "the suggestion that sleep allows us to get rid of insignificant information", "correctCategoryLetter": "D"}, {"itemText": "a description of how the brain responds when a person stops breathing", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">18. H — a mention of different cultural approaches to dealing with insomnia</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“Acupuncture may help. It has long had this role in Asian medicine and is being studied at the University of Pittsburgh sleep center now. Typically in the US, insomnia is treated in two ways.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Different cultural approaches\" (các phương pháp tiếp cận văn hóa khác nhau) được thể hiện qua việc đoạn H đối chiếu giữa châm cứu của y học phương Đông/Châu Á (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"173\">Asian medicine</em>) và các biện pháp dùng thuốc ngủ Tây y thông thường tại Mỹ (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"248\">Typically in the US</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">19. E — indications that sleep has a positive effect on health</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“Some researchers have found that sleep deprivation impedes wound healing in rats, and others have suggested that sleep helps boost the immune system and control infection.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Positive effect on health\" (tác động tích cực tới sức khỏe) tương ứng với việc giấc ngủ giúp thúc đẩy hệ thống miễn dịch và kiểm soát nhiễm trùng (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"160\">boost the immune system and control infection</em>), còn thiếu ngủ sẽ làm cản trở quá trình lành vết thương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. C — the effects of different kinds of sleep on mental performance</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“They found that those who had engaged in REM sleep subsequently performed better in pattern recognition tasks, such as grammar, while those who slept deeply were better at memorization.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C chỉ ra tác động của các loại giấc ngủ khác nhau (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"68\">different kinds of sleep</em> bao gồm giấc ngủ REM và ngủ sâu <em data-path-to-node=\"19,1,0\" data-index-in-node=\"125\">deeply</em>) đối với hiệu suất trí tuệ (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"160\">mental performance</em> bao gồm làm nhiệm vụ nhận diện cấu trúc ngữ pháp và khả năng ghi nhớ <em data-path-to-node=\"19,1,0\" data-index-in-node=\"248\">memorization</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. B — reasons why various species of animal sleep in different ways</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“We know that all mammals sleep, and that there are some insects and reptiles that only half sleep, in order to remain aware of their environment and predators.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Various species of animal\" tương ứng với động vật có vú, côn trùng và bò sát (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"91\">mammals, insects and reptiles</em>). \"Sleep in different ways\" (ngủ theo cách khác nhau) là có loài ngủ hết, có loài chỉ ngủ một nửa (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"220\">only half sleep</em>). Lý do (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"245\">reasons</em>) cho việc này là để duy trì nhận biết về môi trường và tránh kẻ săn mồi (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"326\">remain aware of their environment and predators</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. D — the suggestion that sleep allows us to get rid of insignificant information</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“So the purpose of sleep may be to help us remember what''s important, by letting us forget what''s not.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Get rid of insignificant information\" (loại bỏ thông tin không quan trọng) đồng nghĩa hoàn toàn với cụm từ cho phép chúng ta quên đi những thứ không quan trọng (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"174\">letting us forget what''s not [important]</strong>) dựa trên nghiên cứu xóa bỏ các khớp thần kinh thừa thãi của Giulio Tononi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">23. G — a description of how the brain responds when a person stops breathing</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“When the brain realizes it is not getting oxygen, it sends a signal to the body to wake up.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Stops breathing\" (ngừng thở) tương ứng với hiện tượng tắt đường thở trong chứng ngưng thở khi ngủ (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"112\">apnea</em>). Khi đó, phản ứng của não bộ (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"149\">how the brain responds</strong>) được mô tả rõ: khi nhận ra không có oxy (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"214\">not getting oxygen</em>), não sẽ phát tín hiệu bắt cơ thể phải tỉnh giấc (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"283\">sends a signal to the body to wake up</em>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1d759426-ecec-4b0d-b4ec-e7bd79f72577', 'ecfde2e6-658b-42aa-8c35-d814b69f025e', 'matching', 'Questions 24–26', '', '<p>Look at the following statements (Questions 11–13) and the list of people below.</p>
<p>Match each statement with the correct person, <strong>A</strong>–<strong>E</strong>.</p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "optionsTitle": "List of People", "answerOptions": [{"optionText": "A. Giulio Tononi"}, {"optionText": "B. William Dement"}, {"optionText": "C. Clete Kushida"}, {"optionText": "D. Charles Czeisler"}, {"optionText": "E. John Winkelman"}], "matchingItems": [{"questionPart": "Research tells us that we sleep as reaction to our body''s signals", "correctAnswer": "B"}, {"questionPart": "People suffering from insomnia are easily recognisable", "correctAnswer": "C"}, {"questionPart": "Therapy does not always enable people to achieve good quality sleep", "correctAnswer": "E"}]}', 'null', '[{"content": "<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">24. B (William Dement) — Research tells us that we sleep as reaction to our body''s signals.</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“''As far as I know,'' he said, ''the only reason we need to sleep that is really, really solid is because we get sleepy.''”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Body''s signals\" (tín hiệu của cơ thể) tương ứng với trạng thái chúng ta cảm thấy buồn ngủ (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"104\">we get sleepy</em>). Giáo sư William Dement khẳng định lý do vững chắc nhất của việc ngủ đơn giản là vì cơ thể phát tín hiệu buồn ngủ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">25. C (Clete Kushida) — People suffering from insomnia are easily recognisable.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“However, Clete Kushida, the clinic director, told me he can spot most people''s sleep problems right at the intake interview.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Easily recognisable\" (dễ dàng nhận ra) đồng nghĩa với cụm từ \"can spot most people''s sleep problems right at the intake interview\" (có thể phát hiện ra ngay từ vòng phỏng vấn tiếp nhận bệnh nhân đầu tiên). Người đưa ra khẳng định này là Clete Kushida.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">26. E (John Winkelman) — Therapy does not always enable people to achieve good quality sleep.</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“''Some people continue in my experience to struggle,'' says John Winkelman, another sleep center director. ''They''re not super-satisfied with their sleep.''”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Therapy\" (liệu pháp điều trị) ở đây đang nói đến liệu pháp hành vi nhận thức (CBT) ở đoạn I. John Winkelman chỉ ra thực tế là phương pháp này không phải lúc nào cũng mang lại hiệu quả tuyệt đối, một số bệnh nhân vẫn phải vật lộn (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"243\">continue to struggle</em>) và không cực kỳ thỏa mãn với giấc ngủ của mình (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"313\">not super-satisfied</em>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('bb4da291-81fd-44e0-af02-74f8a2c16e5b', '434607f4-d01e-4b26-9fa0-17e0039b5e45', 'matrix', 'Question 27-32', '', '<p>Write the correct letter <strong data-path-to-node="2" data-index-in-node="40">A</strong> to <strong data-path-to-node="2" data-index-in-node="45">F</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Strizic worked with him to produce a book about Melbourne.", "correctCategoryLetter": "A"}, {"itemText": "He edited the art book Involvement.", "correctCategoryLetter": "B"}, {"itemText": "He designed the cover of Melbourne: A Portrait.", "correctCategoryLetter": "C"}, {"itemText": "His book on Zagreb inspired Strizic’s Melbourne: A Portrait.", "correctCategoryLetter": "D"}, {"itemText": "He collaborated with Strizic to combine photochromes with infrared photography.", "correctCategoryLetter": "E"}, {"itemText": "He wrote the text for Involvement, which was considered pretentious.", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "David Saunders", "categoryLetter": "A"}, {"categoryText": "Andrew Grimwade", "categoryLetter": "B"}, {"categoryText": "Leonard French", "categoryLetter": "C"}, {"categoryText": "Strizic’s father", "categoryLetter": "D"}, {"categoryText": "Stanislav Ostoja-Kotkowski", "categoryLetter": "E"}, {"categoryText": "Geoffrey Dutton", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Strizic worked with him to produce a book about Melbourne. — {A. David Saunders}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“One of his most enduring achievements was his <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"67\">partnership with the critic and historian David Saunders</strong>, with whom he produced <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"147\">Melbourne: A Portrait</strong> in 1960.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mark Strizic đã hợp tác (partnership/worked with) với David Saunders để tạo ra cuốn sách về thành phố Melbourne.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. He edited the art book Involvement. — {B. Andrew Grimwade}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“A more prestigious venture was <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"52\">Involvement (1968)</strong>, a limited-edition art book <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"99\">edited by Andrew Grimwade</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản chỉ đích danh Andrew Grimwade là người biên tập (edited) cho cuốn sách nghệ thuật này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. He designed the cover of Melbourne: A Portrait. — {C. Leonard French}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“The book’s bright and cheerful <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"52\">cover, designed by Leonard French</strong>, contributed to its appeal.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Leonard French là người chịu trách nhiệm thiết kế phần bìa (cover) cho tác phẩm về Melbourne của Strizic.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. His book on Zagreb inspired Strizic’s Melbourne: A Portrait. — {D. Strizic’s father}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Strizic later admitted that the idea for Melbourne: A Portrait had been shaped by <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"103\">his father’s earlier work</strong>. His father, an architect in <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"158\">Zagreb</strong>, had published Light and Shade in 1955…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuốn sách về thành phố Zagreb của người cha (Strizic’s father) đã truyền cảm hứng và định hình (inspired/shaped) ý tưởng cho cuốn sách của Strizic tại Úc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. He collaborated with Strizic to combine photochromes with infrared photography. — {E. Stanislav Ostoja-Kotkowski}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“A notable example was his <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"47\">collaboration with Stanislav Ostoja-Kotkowski</strong> in 1970… which <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"110\">merged infrared photography with Strizic’s experimental prints [photochromes]</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai người đã hợp tác (collaboration/collaborated) để kết hợp (merged/combine) kỹ thuật ảnh hồng ngoại và các bản in thực nghiệm (photochromes).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. He wrote the text for Involvement, which was considered pretentious. — {F. Geoffrey Dutton}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“The accompanying <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"38\">text, written by Geoffrey Dutton</strong>, sought to place the collaboration in a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"111\">grand cultural framework</strong>. Yet the book was <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"154\">widely regarded as unsatisfactory</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Geoffrey Dutton là người viết phần nội dung chữ (wrote the text). Cụm từ “grand cultural framework” (khung cảnh văn hóa vĩ đại) trong bài đọc tương ứng với tính từ “pretentious” (tự phụ/khoa trương) trong câu hỏi, dẫn đến việc cuốn sách bị coi là không thỏa đáng.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('804b4c67-68c0-4209-a3e1-f9bcce79033d', 'fa9f37de-0f2b-445c-b341-16c9ba71722b', 'radio', 'Questions 27–31', '', '<p>Choose the correct letter, <strong data-start="48" data-end="64">A, B, C or D</strong>.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A. They usually have hearing problems"}, {"option_text": "B. Some can play a musical instrument very well"}, {"option_text": "C. Some may be able to sing well-known melodies"}, {"option_text": "D. They have several inabilities in regard to music"}], "question": "What does the writer tell us about people with tone deafness (amusia) in the first paragraph?"}, {"correct": 1, "options": [{"option_text": "A. outlining some of the factors that cause amusia"}, {"option_text": "B. summarising some findings about people with amusia"}, {"option_text": "C. suggesting that people with amusia are disadvantaged"}, {"option_text": "D. comparing the singing ability of amusics with their sense"}], "question": "What is the writer doing in the second paragraph?"}, {"correct": 0, "options": [{"option_text": "A. People who are unable to speak can sometimes sing"}, {"option_text": "B. People with amusia usually have language problems too"}, {"option_text": "C. Speakers of tonal languages like Chinese rarely have amusia"}, {"option_text": "D. People with amusia have difficulty recognizing people by their voices"}], "question": "What does the writer say about the relationship between language ability and musical ability?"}, {"correct": 2, "options": [{"option_text": "A. learn how to sing in tune"}, {"option_text": "B. identify a song by its tune"}, {"option_text": "C. distinguish a sad tone from a happy tune"}, {"option_text": "D. recognise when a singer is not singing in tune"}], "question": "In the third paragraph, the writer notes that most amusics are able to"}, {"correct": 1, "options": [{"option_text": "A. claiming that amusics have problems in the auditory cortex"}, {"option_text": "B. outlining progress in understanding the brains of amusics"}, {"option_text": "C. proving that amusia is located in the temporal lobes"}, {"option_text": "D. explaining why studies of hearing are difficult"}], "question": "What is the writer doing in the fourth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. D — They have several inabilities in regard to music.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"4,0,0\" data-index-in-node=\"26\">“It is not simply that people with tone deafness (or ‘amusia’) are unable to sing in tune, they are also unable to discriminate between tones or recognize familiar melodies.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 1 liệt kê một chuỗi các điểm yếu của người mắc chứng amusia: không thể hát đúng nhạc điệu (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"108\">unable to sing in tune</em>), không thể phân biệt giữa các tông nhạc (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"173\">unable to discriminate between tones</em>) và không nhận ra các giai điệu quen thuộc (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"254\">recognize familiar melodies</em>). Cụm từ \"several inabilities\" (nhiều sự bất lực/không thể) khái quát hoàn hảo cho các thông tin này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. B — summarising some findings about people with amusia</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"6,0,0\" data-index-in-node=\"26\">“According to the research of Dr. Isabelle Peretz of the University of Montreal, amusia is more complicated than the inability to distinguish pitches.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong toàn bộ đoạn 2, tác giả liên tục liệt kê các kết quả từ nghiên cứu của Tiến sĩ Peretz: họ không phân biệt được quãng âm nhỏ hơn nửa cung, không nhận ra một nốt nhạc bị đổi lệch tông, và hát hoặc vỗ tay theo nhịp rất tệ. Việc tổng hợp các thông tin này chính là hành động tóm tắt lại các phát hiện khoa học (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"325\">summarising some findings</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. A — People who are unable to speak can sometimes sing.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"8,0,0\" data-index-in-node=\"26\">“People with brain damage in areas critical to language are often still able to sing, despite being unable to communicate through speech.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi chứng minh năng lực ngôn ngữ và âm nhạc độc lập với nhau, tác giả đưa ra một thực tế: những người bị tổn thương vùng não ngôn ngữ dù không thể giao tiếp bằng lời nói (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"183\">unable to communicate through speech / unable to speak</em>) nhưng họ thường vẫn có thể hát được (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"276\">still able to sing</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. C — distinguish a sad tone from a happy tune</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"10,0,0\" data-index-in-node=\"26\">“Amusics are also successful most of the time at detecting the mood of a melody, can identify a speaker based on his or her voice and can discriminate and identify environmental sounds.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 3 khẳng định người mù nhạc phần lớn thời gian đều thành công trong việc nhận biết tâm trạng của một giai điệu (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"128\">detecting the mood of a melody</em>). Việc phân biệt giữa một tông màu buồn và một giai điệu vui vẻ (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"224\">distinguish a sad tone from a happy tune</strong>) chính là biểu hiện cụ thể của khả năng nhận biết tâm trạng âm nhạc này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. B — outlining progress in understanding the brains of amusics</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"12,0,0\" data-index-in-node=\"26\">“New studies, however, have suggested that the deficits in amusia are located outside the auditory cortex.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 4 phác họa lại hành trình nghiên cứu của giới khoa học qua từng giai đoạn: ban đầu họ nghi ngờ thùy thái dương (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"129\">temporal lobes</em>), sau đó chuyển sang vùng vỏ não thính giác mới (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"193\">temporal neocortex</em>), và cuối cùng các nghiên cứu mới phát hiện ra tổn khuyết thực chất nằm ngoài vỏ não thính giác. Sự sắp xếp thông tin này nhằm phác thảo tiến trình thấu hiểu cấu trúc não bộ của người mù nhạc (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"405\">outlining progress in understanding the brains</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('788bd703-1d81-4f74-b5c5-ca7ecbd31c00', 'da6d2547-4430-4e29-9c84-b2c1b983f9e4', 'radio', 'Questions 7–13', NULL, '<p>Choose, <strong>TRUE </strong>if the statement agrees with the information. <strong>FALSE </strong>if the statement contradicts the information<br /><strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "West Indian manatees can be found in a variety of different aquatic habitats."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The Florida manatee lives in warmer waters than the Antillean manatee."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The African manatee’s range is limited to coastal waters between the West African countries of Mauritania and Angola."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The extent of the loss of Amazonian manatees in the mid-twentieth century was only revealed many years later."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "It is predicted that West Indian manatee populations will fall in the coming decades."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The risk to manatees from entanglement and plastic consumption increased significantly in the period 2009–2020."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "There is some legislation in place which aims to reduce the likelihood of boat strikes on manatees in Florida."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>7. TRUE<br />(Đoạn 6: “It moves between fresh water and salt water, taking advantage of coastal mangroves and coral reefs, rivers, lakes and inland lagoons.”)<br />→ West Indian manatees sống được ở nhiều môi trường nước khác nhau, nên câu này TRUE.</p>\n<p> <br />8. NOT GIVEN<br />→ Không có thông tin trực tiếp so sánh nhiệt độ nước giữa Florida và Antillean manatee.</p>\n<p> <br />9. FALSE<br />(Đoạn 7: “The African manatee… found in the sea along the west coast of Africa, from Mauritania down to Angola. The species also makes use of rivers.”)<br />→ Không chỉ giới hạn ở ven biển, mà còn sống trong sông nội địa → nên câu này FALSE.</p>\n<p> <br />10. NOT GIVEN<br />→ Không nói “nhiều năm sau mới phát hiện mức độ suy giảm” của Amazonian manatee → NOT GIVEN.</p>\n<p> <br />11. TRUE<br />(Đoạn 9: “Both are also expected to undergo a decline of 20% over the next 40 years.”)<br />→ Dự đoán số lượng West Indian manatees sẽ giảm → TRUE.</p>\n<p> <br />12. NOT GIVEN<br />→ Không có thông tin cụ thể rằng nguy cơ từ rác nhựa tăng mạnh trong giai đoạn 2009–2020, chỉ nói “700 ca liên quan” → NOT GIVEN.</p>\n<p> <br />13. TRUE<br />(Đoạn cuối: “However, laws in certain parts of Florida now limit boat speeds during winter, allowing slow-moving manatees more time to respond.”)<br />→ Có luật nhằm giảm nguy cơ va chạm tàu với manatee → TRUE.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('c71875b9-7c94-42f8-b3d9-3f9113f5944c', 'de3dcc6f-c470-4d29-9183-b5b42227c2b2', 'radio', 'Questions 18–20', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The volunteers in Giovanni Battista Grassi''s research came from all parts of Italy."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Experiments in Italy proved that it was possible to remain healthy despite being in malarial zones."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the early twentieth century, quinine was successfully administered to all inhabitants of vulnerable regions."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Câu 18: The volunteers in Giovanni Battista Grassi’s research came from all parts of Italy.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Grassi was able to make the direct link between the insects and the disease… healthy human volunteers…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nhắc đến việc có các tình nguyện viên tham gia, nhưng không nêu rõ họ đến từ khắp nơi trên nước Ý hay chỉ ở một vùng nhất định.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Câu 19: Experiments in Italy proved that it was possible to remain healthy despite being in malarial zones.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…extraordinary series of experiments in Italy, where healthy people were introduced into malarial zones but kept free of mosquito bites – and <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"156\">remained well</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm chứng minh nếu không bị muỗi đốt, con người vẫn khỏe mạnh dù ở trong vùng có dịch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Câu 20: In the early twentieth century, quinine was successfully administered to all inhabitants of vulnerable regions.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…peasants were often suspicious… and doctors were frequently met with hostility and <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"100\">stubborn refusal</strong> to accept the treatment offered.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong data-path-to-node=\"19,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù kế hoạch là phát quinine cho tất cả mọi người, nhưng thực tế nhiều người dân đã từ chối quyết liệt, nên không thể nói là “tất cả cư dân” đều đã uống thuốc thành công.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('6789ad44-8159-4c7c-b330-cec82f326adc', '5d546afa-600e-4da2-a724-e9db3583616a', 'radio', 'Questions 1–8', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information. <strong>FALSE</strong> if the statement contradicts the information. <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Harvard and Yale were the first universities to benefit from philanthropy."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Merchants liked to donate to the same universities they attended themselves."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The first gift to the University of Auckland came in 1884."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Otago University often received larger gifts than Gillies’ gift to Auckland."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the 1930s the government wanted to close Auckland’s engineering school."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "After raising $6,500, Crookes returned to academic life."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the 1950s the best lecturers chose to work in Britain or Australia rather than Auckland."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "A single philanthropist was responsible for the new Medical School."}]', 'null', 'null', 'null', '[{"content": "<p>1. (Đoạn 1: “…from some of the oldest universities such as Bologna, Oxford and Cambridge in the twelfth century, to relative newcomers like the universities of Harvard and Yale in the seventeenth century.”)<br />\n→ Các trường được hưởng lợi đầu tiên là Bologna, Oxford và Cambridge, không phải Harvard và Yale.<br />\n→ FALSE</p>\n<p>2. (Đoạn 1: “Wealthy merchants gave young institutions money, land, libraries and rare items.”)<br />\n→ Bài chỉ nói thương nhân quyên góp cho đại học, không đề cập họ từng học ở đó hay không.<br />\n→ NOT GIVEN</p>\n<p>3. (Đoạn 2: “In 1884 Mr Justice Gillies made history when he gave $3,000 to the then very young University of Auckland.”)<br />\n→ Gillies là người đầu tiên quyên góp cho Đại học Auckland.<br />\n→ TRUE</p>\n<p>4. (Đoạn 2: “Gillies’ gift was more generous even than those regularly given to New Zealand’s older University of Otago.”)<br />\n→ Khoản tặng của Gillies lớn hơn các khoản thường tặng cho Otago.<br />\n→ FALSE</p>\n<p>5. (Đoạn 2: “…the state was determined to see discontinued.”)<br />\n→ Chính phủ muốn đóng cửa khoa Kỹ thuật, nên Crookes mới gây quỹ cứu.<br />\n→ TRUE</p>\n<p>6. (Đoạn 2: “…raised over $6,500 in three years.”)<br />\n→ Không có chi tiết nào nói Crookes quay lại giảng dạy.<br />\n→ NOT GIVEN</p>\n<p>7. (Đoạn 3: “…the strongest candidates tended to be recruited to those countries.”)<br />\n→ Các giảng viên giỏi chọn làm việc ở Anh và Úc vì lương cao hơn.<br />\n→ TRUE</p>\n<p>8. (Đoạn 3: “…from an unusually wide range of donors, including individuals, trusts, charitable foundations, societies and community groups.”)<br />\n→ Có nhiều nhà tài trợ khác nhau, không phải một người.<br />\n→ FALSE</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('eef83a61-564d-4acf-a639-aa01967603e2', '1a17c47a-6a8d-4aef-aa6d-f45bb3014b3f', 'checkbox', 'Questions 22 and 23', '', '<p data-path-to-node="16">Choose <strong data-path-to-node="16" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="16" data-index-in-node="20">A–E</strong>.</p>
<p data-path-to-node="17">Write the correct letters in boxes 22 and 23 on your answer sheet.</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A The state estimated that very few people were involved in piracy."}, {"correct": false, "option_text": "B Attitudes towards piracy changed shortly after the Iliad and the Odyssey were written."}, {"correct": true, "option_text": "C Important officials were known to occasionally take part in piracy."}, {"correct": false, "option_text": "D Every citizen regarded pirate attacks on cities as unacceptable."}, {"correct": true, "option_text": "E A favourable view of piracy is evident in certain ancient Greek texts."}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">22.C. Important officials were known to occasionally take part in piracy. — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"21\">Even high-ranking members of the state</strong> were not beyond engaging in such activities. According to... Demosthenes... <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"136\">Athenian ambassadors</strong> made a detour... to capture a ship... taking the wealth found onboard for themselves!\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"High-ranking members of the state\" (thành viên cấp cao của nhà nước) chính là các quan chức quan trọng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"117\">important officials</strong>). Ví dụ cụ thể trong bài là các đại sứ (ambassadors) đã tự mình đi cướp tàu để lấy tài sản.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">23.E. A favourable view of piracy is evident in certain ancient Greek texts. — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"In his works the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"38\">Iliad and the Odyssey</strong>, the ancient Greek writer <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"86\">Homer not only condones, but praises</strong> the lifestyle and actions of pirates.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm \"not only condones, but praises\" (không chỉ bỏ qua mà còn ca ngợi) thể hiện một quan điểm ủng hộ/thuận lợi (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"124\">favourable view</strong>) đối với hải tặc. \"Ancient Greek texts\" ở đây chính là hai tác phẩm kinh điển Iliad và Odyssey.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('6167f746-2426-4395-b96f-7d0ff852bdf3', '5d546afa-600e-4da2-a724-e9db3583616a', 'fillup', 'Questions 9–13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Fund-raising campaigns</strong></span></p>
<p><strong>The first modern appeals</strong></p>
<p>• an appeal was made in the 1960s to help build the Student Union buildings</p>
<p>• Henry Cooper’s campaign marked the {centenary} of the University</p>
<p>• modern campaigns have focused on raising money from businesses and individuals</p>
<p><strong>‘Leading the Way’</strong></p>
<p>• this appeal is raising money to invest in the University’s {staff}</p>
<p>• gifts are being sought from graduates who are located {overseas}</p>
<p>• John Taylor believes research at the University helps the whole country</p>
<p><strong>Financial matters</strong></p>
<p>• some donations had not been {recorded} by the University</p>
<p>• there is a new financial {target} for the campaign</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>9. (Đoạn 4: “…raised $800,000 to celebrate the University’s centenary.”)<br />\n→ Chiến dịch của Henry Cooper nhằm kỷ niệm 100 năm thành lập trường.<br />\n→ centenary</p>\n<p>10. (Đoạn 5: “…with a focus on generating funds to recruit, support and retain the very best staff for the University.”)<br />\n→ Chiến dịch Leading the Way đầu tư để giữ chân nhân viên giỏi.<br />\n→ staff</p>\n<p>11. (Đoạn 5: “…targeting alumni, or former students now living overseas.”)<br />\n→ Trường nhắm đến cựu sinh viên ở nước ngoài để gây quỹ.<br />\n→ overseas</p>\n<p>12. (Đoạn 7: “…giving to the University that has not been previously recorded through our Advancement Office.”)<br />\n→ Một số khoản quyên góp chưa được ghi nhận trong hồ sơ.<br />\n→ recorded</p>\n<p>13. (Đoạn 7: “…the campaign target was now being increased from $100 million to $150 million.”)<br />\n→ Mục tiêu tài chính mới được nâng lên 150 triệu đô.<br />\n→ target</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('6a944d5c-ad42-4e50-869a-715ae039c89f', '060419de-7ae1-4956-a075-106f4a17f49d', 'fillup', 'Questions 8–13', '<div class="exams-tab hilightJs">
<div id="hilight_panel_0" class="exams-tab-panel hilightItemJs active">
<div class="exams-block">
<div class="exams-inner HilightInnerJs resizeJs">
<div class="exams-quest resizeIt highlightQuest">
<div class="exams-quest-inner">
<div class="quests fill quests-history">
<div class="quests-inner">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the flow-chart below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>Nancy Athfield’s career</strong></p>
<p class="ql-align-center" style="text-align: center;">In her mid-teens, Athfield did not expect to attend {university} .</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Wally Brocker taught Athfield how to develop the mind of a scientist.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Athfield’s PhD investigated when a type of {rat} arrived in New Zealand.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Her PhD research found that the subject’s diet accounted for previous inaccurate results.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">She worked as a professional {archaeologist} before going to Cambodia in 2003.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Inadequate {funding} prevented further research in Cambodia.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Later, she helped to compile a {database} dating across Cambodia of radiocarbon</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">The lack of a detailed {map} of Cambodia’s geology has made her team’s research harder.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="exams-gr">
<div class="exams-step prev disable"></div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Câu 8: In her mid-teens, Athfield did not expect to attend …</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> university</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…before a friend suggested she sit the entrance exam for <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"71\">university</strong>. She did, and to her <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"103\">surprise</strong> she was accepted.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc cô ấy thấy “ngạc nhiên” khi được nhận vào học cho thấy trước đó cô không hề mong đợi (did not expect) sẽ đi học đại học.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Câu 9: Athfield’s PhD investigated when a type of … arrived in New Zealand.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> rat</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…suggest rằng a <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"30\">rat</strong> species had arrived in New Zealand as early as 100 AD… Her PhD was based on five years of research exploring this issue…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đề tài tiến sĩ của cô nghiên cứu về thời điểm một loài chuột (rat) đến New Zealand.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Câu 10: She worked as a professional … before going to Cambodia in 2003.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> archaeologist</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She then… started working as a fully qualified <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"61\">archaeologist</strong> in the UK… But it was the call from those film-makers in 2003 that…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi nhận cuộc gọi từ các nhà làm phim năm 2003, cô đang làm việc như một nhà khảo cổ học chuyên nghiệp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Câu 11: Inadequate … prevented further research in Cambodia.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> funding</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…she and her colleagues were hampered by that universal problem for researchers, a <strong data-path-to-node=\"28,1,0\" data-index-in-node=\"97\">lack of funding</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Inadequate” đồng nghĩa với “lack of”. Việc thiếu kinh phí (funding) đã cản trở nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Câu 12: Later, she helped to compile a … dating across Cambodia of radiocarbon.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> database</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as part of a larger project to create a Cambodia-wide radiocarbon <strong data-path-to-node=\"30,1,0\" data-index-in-node=\"81\">database</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cô tham gia vào một dự án lớn hơn để tạo ra một cơ sở dữ liệu (database) về carbon phóng xạ trên toàn Campuchia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Câu 13 The lack of a detailed … of Cambodia’s geology has made her team’s research harder.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> map</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it has been no easy task because the country doesn’t have an extensive geological <strong data-path-to-node=\"32,1,0\" data-index-in-node=\"97\">map</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc thiếu một bản đồ (map) địa chất chi tiết đã khiến công việc của đội nghiên cứu gặp khó khăn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('bdd5fc9f-3f2f-45e8-a780-87552afa7db5', '32806294-6780-488d-b423-871a0e6397d1', 'radio', 'Questions 8-10 ', NULL, '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
</div>
</div>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": " He is less famous than he should be."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "He was famous as a doctor before he was employed by the Queen."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "He lost faith in the medical theories of his time."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">8. He is less famous than he should be: TRUE</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;However, he is <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"27\">less well known than he deserves</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ &#8220;less well known&#8221; tương ứng với &#8220;less famous&#8221;, và &#8220;than he deserves&#8221; (hơn mức ông xứng đáng) tương ứng với &#8220;than he should be&#8221;. Tác giả khẳng định tầm quan trọng của ông chưa được công nhận rộng rãi như lẽ ra phải thế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">9. He was famous as a doctor before he was employed by the Queen: TRUE</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3 và đoạn 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;He was a <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"21\">very successful and eminent doctor</strong>. All this <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"66\">culminated</strong> in his election to the president of the Royal Science Society. He was <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"147\">also</strong> appointed personal physician to the Queen&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> * Bài đọc mô tả ông là một bác sĩ &#8220;rất thành công và lỗi lạc&#8221; (<em data-path-to-node=\"4,2,0\" data-index-in-node=\"75\">very successful and eminent</em>).</p>\n<ul data-path-to-node=\"4,2,1\">\n<li>\n<p data-path-to-node=\"4,2,1,0,0\">Từ <strong data-path-to-node=\"4,2,1,0,0\" data-index-in-node=\"3\">&#8220;culminated&#8221;</strong> (đỉnh điểm/kết quả của một quá trình) cho thấy những thành tựu và sự nổi danh trong ngành y của ông đã diễn ra trước.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,1,1,0\">Việc được bầu làm Chủ tịch Hội Khoa học Hoàng gia và việc được bổ nhiệm làm bác sĩ cho Nữ hoàng là những sự kiện nối tiếp sự nghiệp lừng lẫy đó. Trong logic IELTS, &#8220;eminent&#8221; (lỗi lạc/nổi tiếng trong lĩnh vực chuyên môn) đi kèm với một chuỗi thành tựu trước khi phục vụ hoàng gia chính là bằng chứng xác nhận ông đã danh tiếng từ trước.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">10. He lost faith in the medical theories of his time: NOT GIVEN</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gilbert was first interested in chemistry but later changed his focus due to the large portion of mysticism of alchemy involved&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói ông từ bỏ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"38\">hóa học/thuật giả kim</strong> (chemistry/alchemy) vì nó mang tính thần bí. Về mảng <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"113\">y học</strong> (medical), bài đọc vẫn nói ông là một bác sĩ rất thành công và phục vụ hoàng gia cho đến khi qua đời. Không có thông tin nào cho thấy ông mất niềm tin vào các lý thuyết y học đương thời.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('ca23240b-4fb4-485c-b108-348c489f0f1d', 'fa9f37de-0f2b-445c-b341-16c9ba71722b', 'radio', 'Questions 32–35', '', '<p>Choose <strong data-start="1774" data-end="1781">YES</strong> – if the statement agrees with the views of the writer, <strong data-start="1839" data-end="1845">NO</strong> – if the statement contradicts the views of the writer, <strong data-start="1903" data-end="1916">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Peretz’s research suggesting that amusia is a disorder is convincing"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with musical ability are happier than those without this ability"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It is inappropriate to consider amusia as a real disorder"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with amusia often have bad handwriting"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. NO</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“Looking only at the research of Peretz in the field of neuropsychology of music, it would appear that amusia is some sort of disorder. As a student of neurobiology, however, I am skeptical.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói nghiên cứu của Peretz cho rằng amusia là một chứng rối loạn rất thuyết phục (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"101\">convincing</em>). Ngược lại, tác giả khẳng định mình cảm thấy hoài nghi (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"169\">I am skeptical</strong>) về quan điểm đó. Vì quan điểm của tác giả mâu thuẫn trực tiếp với câu hỏi nên đáp án là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"273\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"18,0,0\" data-index-in-node=\"26\">“Musical ability is culturally valued, and may have been a factor in survival at one point in human history, but it does not seem likely that it is being selected for on an evolutionary scale any longer.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói năng lực âm nhạc mang giá trị văn hóa và từng đóng vai trò trong lịch sử tiến hóa, chứ <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"114\">hoàn toàn không có thông tin</strong> nào so sánh hoặc khẳng định người có năng khiếu âm nhạc thì sẽ sống hạnh phúc hơn (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"226\">happier</em>) người không có.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. YES</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"20,0,0\" data-index-in-node=\"26\">“Just because we recognize that basic musical ability is something that the vast majority of people have, this doesn’t mean that the lack of it is abnormal.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi cho rằng không thích hợp khi coi amusia là một chứng rối loạn thực sự (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"91\">inappropriate to consider amusia as a real disorder</em>). Điều này đồng nhất với góc nhìn của tác giả khi khẳng định việc thiếu năng lực âm nhạc không có nghĩa là bất thường (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"262\">not abnormal</em>), và việc quy chụp nó như một hội chứng rối loạn là đi quá xa (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"338\">going too far</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"22,0,0\" data-index-in-node=\"26\">“If no disadvantages can be found of having amusia, then it is no more a disability than having poor fashion sense or bad handwriting.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra một phép so sánh giả định: nếu không tìm thấy tác hại nào của amusia thì nó cũng không hẳn là khuyết tật, giống như việc có gu thời trang kém hay có chữ viết tay xấu (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"194\">bad handwriting</em>). Bài viết <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"221\">không hề khẳng định</strong> một sự thật là người mù nhạc thì thường có chữ viết tay xấu ngoài đời thực.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('bd3df8ba-fb00-4373-a470-6e18e54725a1', 'b1dda976-6c05-49e7-9bb7-6c84fb553004', 'matrix', 'Questions 14–19', NULL, '<p>Reading Passage 2 has nine paragraphs, A–I.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, A–I</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a reference to studies based on the use of low calorie reduction with different animals", "correctCategoryLetter": "B"}, {"itemText": "a comment on some monkeys which had a higher age than normal for their species", "correctCategoryLetter": "G"}, {"itemText": "an explanation of why one set of findings may have led to a contrast in findings", "correctCategoryLetter": "E"}, {"itemText": "examples of health problems that affected monkeys on unrestricted diets were less likely to get", "correctCategoryLetter": "C"}, {"itemText": "a researcher’s negative opinion of a calorie-restricted diet", "correctCategoryLetter": "A"}, {"itemText": "a reference to the stage in the monkeys’ lives at which research commenced in one study", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p><strong>14. a reference to studies based on the same level of calorie reduction with different animals</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) “In <strong>mice</strong>, many experiments had come to the same finding: feed them a diet with <strong>30% fewer calories</strong>… The monkey trials were set up in a similar way: researchers… <strong>cut it by 30%</strong>…”</p>\n</li>\n</ul>\n<p><strong>15. a comment that some control monkeys in one study reached an older age than normal for animals of their kind</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>G</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn G) “Indeed, Anderson points out that several of the NIA control monkeys have lived past the age of 40, <strong>far exceeding the 27-year average lifespan</strong> for captive rhesus monkeys.”</p>\n</li>\n</ul>\n<p><strong>16. distinctions between the types of food in each study that may have led to a contrast in findings</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn E) “The Wisconsin monkeys were given highly processed food high in <strong>sucrose</strong>… the NIA diet was based on <strong>whole grains, fish oils, and was very low in sugar</strong>.”</p>\n</li>\n</ul>\n<p><strong>17. examples of health problems which monkeys on calorie-restricted diets were less likely to get</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>C</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn C) “…the lean monkeys were living longer and suffering less from the diseases of ageing: <strong>diabetes, heart disease and brain diseases</strong>.”</p>\n</li>\n</ul>\n<p><strong>18. a researcher’s negative opinion of a calorie-restricted diet</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn A) “Rozalyn Anderson… says the research is not intended as a recommendation of calorie restriction. ‘I find the idea <strong>monumentally unattractive</strong>!’ she says.”</p>\n</li>\n</ul>\n<p><strong>19. a reference to the stage in the monkeys’ lives at which research commenced in one study</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn D) “The Wisconsin study began with monkeys in <strong>early adulthood</strong>.”</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('099dd706-15e8-4f13-965b-f5a28b00bfef', 'b1dda976-6c05-49e7-9bb7-6c84fb553004', 'matrix', 'Questions 20–23', NULL, '<p>Look at the following statements (Questions 20–23) and the list of researchers below.</p>
<p>Match each statement with the correct researcher, A, B or C.</p>
<p>Choose the correct letter, A, B or C, in boxes 20–23.</p>
<p>NB You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "It is good that the two studies took dissimilar approaches.", "correctCategoryLetter": "A"}, {"itemText": "Neither study used diets that are typical for monkeys.", "correctCategoryLetter": "C"}, {"itemText": "Calorie restriction is a method of finding out about health issues connected with ageing.", "correctCategoryLetter": "A"}, {"itemText": "Calorie reduction will have a positive effect on people who have unhealthy diets.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Rozalyn Anderson", "categoryLetter": "A"}, {"categoryText": "Julie Mattison", "categoryLetter": "B"}, {"categoryText": "Leonie Heilbronn", "categoryLetter": "C"}]}', '[{"content": "<p><strong>20. It is good that the two studies took dissimilar approaches.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>A</strong> (Rozalyn Anderson)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn I) “The fact the two studies were set up differently… — <strong>I think we will gain maximally from that</strong>.’”</p>\n</li>\n</ul>\n<p><strong>21. Neither study used diets that are typical for monkeys.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>C</strong> (Leonie Heilbronn)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn H) “However, <strong>neither group had the right notion of a standard diet</strong> according to Leonie Heilbronn…”</p>\n</li>\n</ul>\n<p><strong>22. Calorie restriction is a method of finding out about health issues connected with ageing.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>A</strong> (Rozalyn Anderson)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn A) “‘We study it because it is so effective at delaying ageing and <strong>the onset of age-related disease</strong>.’”</p>\n</li>\n</ul>\n<p><strong>23. Calorie reduction will have a positive effect on people who have unhealthy diets.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>B</strong> (Julie Mattison)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn F) “Julie Mattison… observes that <strong>an overweight person who goes to a fast food restaurant every day will obviously benefit</strong> if their calories are cut back by 30%.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('71822b42-4da4-499e-bb1a-8c465af1a9d4', 'b1dda976-6c05-49e7-9bb7-6c84fb553004', 'fillup', 'Questions 24–26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
<p><strong>Agreement between the two studies on calorie restriction in rhesus monkeys</strong></p>
<p>The two studies were in agreement that it is beneficial to cut calories, in terms of health. Monkeys whose calories were restricted suffered fewer diseases that are associated with the {ageing} process. Anderson and Mattison have undertaken research to determine if a calorie-restricted diet increases primates’ {lifespan}. Although there is a {conflict} between the two sets of data, Anderson believes they will help researchers reach a better understanding.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>24. Monkeys whose calories were restricted suffered fewer diseases that are associated with the ageing process.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>ageing</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn I) “…fewer diseases that are associated with the <strong>ageing</strong> process.”</p>\n</li>\n</ul>\n<p><strong>25. Anderson and Mattison have undertaken research to determine if a calorie-restricted diet increases primates’ lifespan.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>lifespan</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn I) “As to the question of whether calorie restriction extends <strong>lifespan</strong> in primates…”</p>\n</li>\n</ul>\n<p><strong>26. Although there is a conflict between the two sets of data, Anderson believes they will help researchers reach a better understanding.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>conflict</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn I) “The current data <strong>conflict</strong> will ultimately provide deeper insights…”</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('a6acf828-9b8f-4093-b418-8fb5093c3bc2', '1a17c47a-6a8d-4aef-aa6d-f45bb3014b3f', 'fillup', 'Questions 24–26', '<p id="p-rc_87dbc31b71979e46-105" data-path-to-node="22"><span class="citation-9840">Complete the summary </span><span class="citation-9838 citation-9839 citation-9840 citation-end-9840">below.<sup class="superscript" data-turn-source-index="50"><!----></sup></span><span class="citation-9838 citation-9839 citation-end-9839"><sup class="superscript" data-turn-source-index="51"><!----></sup></span><span class="citation-9838 citation-end-9838"><sup class="superscript" data-turn-source-index="52"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_87dbc31b71979e46-106" data-path-to-node="23"><span class="citation-9835 citation-9836 citation-9837">Choose </span><strong><span class="citation-9835 citation-9836 citation-9837">ONE WORD ONLY</span></strong><span class="citation-9835 citation-9836 citation-9837 citation-end-9837"> from the passage for each answer.<sup class="superscript" data-turn-source-index="53"><!----></sup></span><span class="citation-9835 citation-9836 citation-end-9836"><sup class="superscript" data-turn-source-index="54"><!----></sup></span><span class="citation-9835 citation-end-9835"><sup class="superscript" data-turn-source-index="55"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_87dbc31b71979e46-107" data-path-to-node="24"><span class="citation-9832 citation-9833 citation-9834 citation-end-9834">Write your answer<sup class="superscript" data-turn-source-index="56"><!----></sup></span><span class="citation-9832 citation-9833 citation-end-9833">s in boxes 24–26 on your answer sheet.</span></p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: center;" data-path-to-node="25,0"><strong data-path-to-node="25,0" data-index-in-node="0"><span class="citation-9830 citation-9831 citation-end-9831"><span style="font-size: 12pt;"><strong>Ancient Rome and piracy</strong></span><sup class="superscript" data-turn-source-index="59"><!----></sup></span><span class="citation-9830 citation-end-9830"><sup class="superscript" data-turn-source-index="60"><!----></sup></span></strong></p>
<p id="p-rc_87dbc31b71979e46-108" data-path-to-node="25,1"><span class="citation-9828 citation-9829 citation-end-9829">Piracy was an issue ancient Rome had to deal with, but it also brought some benefits for Ro<sup class="superscript" data-turn-source-index="61"><!----></sup></span><span class="citation-9828">me. </span><span class="citation-9826 citation-9827 citation-9828 citation-end-9828">For example, pirates <sup class="superscript" data-turn-source-index="62"><!----></sup></span><span class="citation-9826 citation-9827">supplied slaves that were important for Rome’s industries. However, attacks on vessels transporting {grain}</span><span class="citation-9826 citation-9827"> to Rome resulted in calls for {punishment}</span><span class="citation-9826 citation-9827"> for the pirates responsible. Nevertheless, piracy continued, with some pirates demanding a {ransom}</span><span class="citation-9826 citation-9827 citation-end-9827"> for the return o<sup class="superscript" data-turn-source-index="63"><!----></sup></span><span class="citation-9826 citation-end-9826">f the Roman officials they ca<sup class="superscript" data-turn-source-index="64"><!----></sup></span>ptured.</p>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="24"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. grain — {attacks on vessels transporting grain to Rome}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"Pirate attacks on <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"39\">grain</strong> ships, which were essential to Roman citizens, led to angry voices in the Senate...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những con tàu chở ngũ cốc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"39\">grain</strong>) đóng vai trò sống còn với người dân La Mã. Khi hải tặc tấn công những con tàu này, nó đã gây ra làn sóng phẫn nộ trong Viện Nguyên lão.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. punishment — {resulted in calls for punishment for the pirates responsible}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"...led to angry voices in the Senate, demanding <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"69\">punishment</strong> of the culprits.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Calls for\" (kêu gọi/yêu cầu) tương ứng với \"demanding\" trong bài. \"Culprits\" (kẻ thủ ác/tội phạm) chính là những tên hải tặc chịu trách nhiệm cho các vụ tấn công. Họ yêu cầu phải trừng phạt (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"204\">punishment</strong>) những kẻ này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. ransom — {demanding a ransom for the return of the Roman officials they captured}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"...emboldened pirates kidnapped prominent Roman dignitaries, asking for a large <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"101\">ransom</strong> to be paid.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Roman officials\" (quan chức La Mã) tương ứng với \"Roman dignitaries\" (nhân vật quyền quý). Hải tặc bắt cóc họ và yêu cầu một khoản tiền chuộc (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"156\">ransom</strong>) mới chịu thả người (return).</p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('23db972e-d4ca-4419-9ebe-e744d52cd955', '241ff6c4-b920-44a6-93be-c58d32c2d576', 'fillup', 'Questions 1–7', '<p>Complete the notes below.<br />Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>The history of frozen food</strong></p>
<p><strong>2,000 years ago, South America</strong></p>
<p>People conserved the nutritional value of {potatoes}, using a method of freezing then drying.</p>
<p><strong>1851, USA</strong></p>
<p>{butter} was kept cool by ice during transportation in specially adapted trains.</p>
<p><strong>1880, Australia</strong></p>
<p>Two kinds of {meat} were the first frozen food shipped to England.</p>
<p><strong>1917 onwards, USA</strong></p>
<p>Clarence Birdseye introduced innovations including:</p>
<p>quick-freezing methods, so that {crystals} did not spoil the food.<br />packaging products with {cellophane}, so the product was visible.</p>
<p><strong>Early 1940s, USA</strong></p>
<p>Frozen food became popular because of a shortage of {tin}.<br /><strong>1950s, USA</strong></p>
<p>A large number of homes now had a {refrigerator}.</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. potatoes<br />(Đoạn 1: “They froze them overnight, then trampled them to squeeze out the moisture, then dried them in the sun. This preserved their nutritional value…”)<br />→ Người dân vùng Andes bảo quản giá trị dinh dưỡng của khoai tây (potatoes) bằng cách đông rồi phơi khô. → potatoes.</p>\n<p> <br />2. butter<br />(Đoạn 2: “In 1851, railroads first began putting blocks of ice in insulated rail cars to send butter from Ogdensburg, New York, to Boston.”)<br />→ Năm 1851, bơ (butter) được giữ lạnh bằng đá trong tàu hỏa cách nhiệt. → butter.</p>\n<p> <br />3. meat<br />(Đoạn 4: “In 1880, a shipment of Australian beef and mutton was sent, frozen, to England.”)<br />→ Hai loại thịt (meat) đầu tiên được đông lạnh và gửi sang Anh là bò và cừu. → meat.</p>\n<p> <br />4. crystals<br />(Đoạn 4: “During the freezing process, crystals formed within the cells of the food, and when the ice expanded…the cells burst.”)<br />→ Birdseye sau này tìm ra cách làm đông nhanh để tinh thể băng (crystals) không phá hủy thực phẩm. → crystals.</p>\n<p> <br />5. cellophane<br />(Đoạn 6: “He also introduced the use of cellophane, the first transparent material for food packaging.”)<br />→ Birdseye sử dụng cellophane để khách hàng có thể nhìn thấy sản phẩm bên trong. → cellophane.</p>\n<p> <br />6. tin<br />(Đoạn 7: “Sales increased in the early 1940s, when World War II gave a boost… because tin was being used for munitions. Canned foods were rationed to save tin.”)<br />→ Đông lạnh phổ biến nhờ thiếu hụt thiếc (tin) dùng cho đồ hộp thời chiến. → tin.</p>\n<p> <br />7. refrigerator<br />(Đoạn 8: “By 1953, 33 million US families owned a refrigerator, and manufacturers were gradually increasing the size of the freezer compartments.”)<br />→ Tới thập niên 1950, nhiều gia đình sở hữu tủ lạnh (refrigerator) → refrigerator.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('559d33a7-ce9e-4adc-999a-dd2f024534c1', '2016adb7-4086-4724-8024-d3853e8aae2c', 'radio', 'Questions 1-6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple-choice', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Egyptian singer Har-Mole was an excellent tanbur player."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Cairo Archaeological Museum contains many historic musical instruments."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar"}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The different instruments that appeared in medieval literature had the same number of strings."}]', 'null', 'null', 'null', '[{"content": "<p>1. The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp.</p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The <strong>earliest stringed instruments currently known</strong> to archaeologists are bowl harps… Around 2500-2000 BC more advanced harps, such as the beautifully carved 11-stringed instrument <strong>found in the tomb of Queen Shub-Ad</strong>… <strong>started to appear</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong>Giải thích:</strong> Bowl harps là những nhạc cụ dây được biết đến sớm nhất. Cây đàn trong lăng mộ Queen Shub-Ad là một ví dụ về harp <strong>tiên tiến hơn</strong> (more advanced) và <strong>chỉ bắt đầu xuất hiện</strong> khoảng 2500-2000 TCN, trong khi bowl harps đã có từ hàng thiên niên kỷ trước.</p>\n</li>\n</ul>\n<p>2. Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Archaeologists have also found <strong>many similar relics amongst the ruins of the ancient Mesopotamian civilisation</strong>. <span class=\"citation-9\">Many of these instruments have </span><strong><span class=\"citation-9\">survived into modern times in almost unchanged form</span></strong><span class=\"citation-9\">, for example folk instruments of the region such as the Turkish saz and Afghan </span><strong><span class=\"citation-9\">panchtar</span></strong><span class=\"citation-9 citation-end-9\">.”</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Văn bản khẳng định panchtar ngày nay rất giống (almost unchanged form) với các di vật cổ của Lưỡng Hà (Mesopotamian).</p>\n</li>\n</ul>\n<p>3. The Egyptian singer Har-Mole was an excellent tanbur player.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong><span class=\"citation-8\"> (Đoạn C) “At 3,500 years old, the tanbur which belonged to the Egyptian </span><strong><span class=\"citation-8\">singer Har-Mose</span></strong><span class=\"citation-8 citation-end-8\"> is the earliest known example of this instrument.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Har-Mose được biết đến là ca sĩ, nhưng <strong>không có thông tin</strong> đánh giá khả năng chơi tanbur của ông.</p>\n</li>\n</ul>\n<p>4. <span class=\"citation-7 citation-end-7\">Cairo Archaeological Museum contains many historic musical instruments.</span></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “It can be seen today at the <strong>Archaeological Museum in Cairo</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Văn bản chỉ nói chiếc tanbur của Har-Mose được trưng bày ở đó, <strong>không đề cập</strong> đến số lượng nhạc cụ lịch sử nói chung.</p>\n</li>\n</ul>\n<p>5. The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar.</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “Dr Michael Kasha defines a guitar as having ‘a long, fretted neck, flat wooden soundboard, ribs, and a <strong>flat back, most often with sides that curve inwards</strong>‘… The oldest known visual representation… shows a 3,300-year-old instrument with a long neck and <strong>sides that clearly curve inwards</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mô tả về nhạc cụ ở Alaca Huyuk (“long neck and sides that clearly curve inwards”) <strong>phù hợp</strong> (consistent) với phần định nghĩa quan trọng của Kasha.</p>\n</li>\n</ul>\n<p>6. The different instruments that appeared in medieval literature had the same number of strings.</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “The earliest guitar-like instruments to arrive in Europe had, most often, <strong>four strings</strong>. Many such instruments, and <strong>variations with from three to five strings</strong>, can be seen in mediaeval illustrated manuscripts.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Các nhạc cụ này có số lượng dây khác nhau (từ ba đến năm), mâu thuẫn với việc có cùng số lượng dây.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('b2c5aa39-591e-4a65-aa74-d1e8c5864b68', 'fd10158d-9220-4a87-be0a-e46253c9962b', 'matching', 'Questions 27–33', NULL, '<p>Complete each sentence with the correct ending, A–I, below.</p>
<p>Choose the correct letter, A–I</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. can dominate its surroundings with a single plant."}, {"optionText": "B. explodes as a result of internal pressure."}, {"optionText": "C. has seeds which have a feature that increases the distance they travel."}, {"optionText": "D. colonises a new spot when it can no longer survive in another."}, {"optionText": "E. moves along close to the ground."}, {"optionText": "F. produces a loud noise when it distributes its seeds."}, {"optionText": "G. relies on human activity to distribute its seeds."}, {"optionText": "H. requires water every day."}, {"optionText": "I. produces branches that spread out very quickly into the air."}], "matchingItems": [{"questionPart": "The blackberry", "correctAnswer": "I. produces branches that spread out very quickly into the air.", "sectionContent": null}, {"questionPart": "The silverweed", "correctAnswer": "E. moves along close to the ground.", "sectionContent": null}, {"questionPart": "Fescue grass", "correctAnswer": "A. can dominate its surroundings with a single plant.", "sectionContent": null}, {"questionPart": "The bird-cage plant", "correctAnswer": "D. colonises a new spot when it can no longer survive in another.", "sectionContent": null}, {"questionPart": "The Mediterranean squirting cucumber", "correctAnswer": "B. explodes as a result of internal pressure.", "sectionContent": null}, {"questionPart": "Monkey’s dinner-bell", "correctAnswer": "F. produces a loud noise when it distributes its seeds.", "sectionContent": null}, {"questionPart": "The sycamore", "correctAnswer": "C. has seeds which have a feature that increases the distance they travel.", "sectionContent": null}]}', 'null', '[{"content": "<p>27. (I)<br />\n(Đoạn 2: “&#8230;the blackberry puts out exploratory stems, which curve upwards, waving slowly as though searching… around five centimetres a day.”)<br />\n→ Cành của cây blackberry vươn ra nhanh, uốn cong lên không trung như đang tìm kiếm.<br />\n→ Đáp án: I – produces branches that spread out very quickly into the air.</p>\n<p>28. (E)<br />\n(Đoạn 3: “The silverweed is equally effective, putting out travelling stems that advance horizontally, creeping at low level through the mat of rootlets and dead vegetation formed by other plants.”)<br />\n→ Cây silverweed bò ngang sát mặt đất, len qua rễ và thảm thực vật khác.<br />\n→ Đáp án: E – moves along close to the ground.</p>\n<p>29. (A)<br />\n(Đoạn 4: “The genetic fingerprints of its leaves and stems taken two hundred metres apart have proved… to be identical… it has become the largest plant in the entire meadow.”)<br />\n→ Một cá thể fescue grass có thể lan rộng và chiếm lĩnh toàn bộ khu vực, trở thành cây lớn nhất.<br />\n→ Đáp án: A – can dominate its surroundings with a single plant.</p>\n<p>30. (D)<br />\n(Đoạn 5: “&#8230;the wind blows it across the sand for several kilometres. Eventually it rolls into a sheltered site, allowing the seeds inside to germinate.”)<br />\n→ Khi chết, bird-cage plant bị gió thổi đi xa, đến chỗ mới và nảy mầm ở đó.<br />\n→ Đáp án: D – colonises a new spot when it can no longer survive in another.</p>\n<p>31. (B)<br />\n(Đoạn 6: “&#8230;the cucumber bursts off its stalk and shoots off six metres through the air, leaving a trail of slime and seeds behind it.”)<br />\n→ Squirting cucumber nổ tung do áp lực bên trong và bắn hạt ra xa.<br />\n→ Đáp án: B – explodes as a result of internal pressure.</p>\n<p>32. (F)<br />\n(Đoạn 7: “&#8230;causing an explosion which can hurl the seeds over twelve metres. The bang is enough to convince nervous strangers in the forest that they’re under attack.”)<br />\n→ Khi vỏ hạt nổ, phát ra tiếng lớn, khiến người nghe tưởng bị tấn công.<br />\n→ Đáp án: F – produces a loud noise when it distributes its seeds.</p>\n<p>33. (C)<br />\n(Đoạn 8: “Sycamore seeds have a single large wing, so a single spin makes it easy for them to travel far.”)<br />\n→ Hạt cây sycamore có cánh giúp bay xa hơn.<br />\n→ Đáp án: C – has seeds which have a feature that increases the distance they travel.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('073900d6-fd93-433d-8a5c-c8fd8486a2df', '32806294-6780-488d-b423-871a0e6397d1', 'checkbox', 'Questions 11–13', NULL, '<p>Choose <strong>THREE </strong>correct answers.</p>
<p>Which <strong>THREE </strong>of the following are parts of Gilbert’s discovery?</p>
', 'multiple_choice_many', 'null', '[{"option": "Metal can be transformed into another.", "correct": false}, {"option": "Garlic can remove magnetism.", "correct": false}, {"option": "Metals can be magnetised.", "correct": true}, {"option": "Stars are at different distances from the earth.", "correct": true}, {"option": "The earth wobbles on its axis.", "correct": true}, {"option": "There are two charges of electricity.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">C. Metals can be magnetised.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 10–12.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gilbert also found that <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"36\">metals can be magnetised</strong> by rubbing materials such as fur, plastic or the like on them.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định trực tiếp rằng Gilbert đã phát hiện ra kim loại có thể được từ hóa bằng cách chà xát với các vật liệu khác. Đây là một phần quan trọng trong các thí nghiệm về từ tính của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">D. Stars are at different distances from the earth.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 3–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;he believed that <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"32\">stars are not equidistant</strong> from the earth but have their own earth-like planets orbiting around them.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thuật ngữ &#8220;not equidistant&#8221; có nghĩa là không cách đều. Điều này đồng nghĩa với việc các ngôi sao nằm ở những khoảng cách khác nhau (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"145\">different distances</strong>) so với Trái Đất. Đây là quan điểm tiến bộ của ông so với thiên văn học truyền thống thời bấy giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">E. The earth wobbles on its axis.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 8–12.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Thus a perfectly spherical lodestone&#8230; would <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"58\">wobble all by itself in 24 hours</strong>. Further, he also believed that the sun and other stars <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"147\">wobble just like the earth does</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Gilbert sử dụng mô hình quả cầu từ tính để chứng minh rằng Trái Đất tự quay và có hiện tượng &#8220;đảo&#8221; (wobble) quanh trục của nó. Ông xây dựng toàn bộ triết lý từ tính dựa trên sự tương đồng này giữa nam châm và Trái Đất.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('8a08c474-7c58-41d5-92b5-10c8a2de20fe', '199a1fa7-a405-4e6b-9451-ffcd18ae18fa', 'radio', 'Questions 14–16', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 3, "options": [{"content": "A the curiosity of historians about the original purpose of these ruins."}, {"content": "B the vast geographical areas covered by these structures."}, {"content": "C their profound impact on the field of archaeological research"}, {"content": "D the mixture of beauty and mystery these sites represent."}], "question": "In describing the appeal of monumental ruins, the writer highlights"}, {"correct": 2, "options": [{"content": "A upended established theories."}, {"content": "B Triggered a heated debate among scientists."}, {"content": "C emerged from a range of disciplines."}, {"content": "D confirmed a major cause of environmental destruction."}], "question": "Recent findings regarding lost civilisations have"}, {"correct": 0, "options": [{"content": "A the pace of collapse showed some resemblance across societies."}, {"content": "B the decline of societies was usually a slow and predictable process"}, {"content": "C all societies peaked in terms of population and power before collapsing."}, {"content": "D ordinary people could occasionally affect the course of events."}], "question": "In discussing how previous societies fell, the writer mentions that"}]', 'null', 'null', 'null', '[{"content": "<p><strong>14. In describing the appeal of monumental ruins, the writer highlights</strong></p>\n<ul>\n<li><strong>Đáp án: D. the mixture of beauty and mystery these sites represent.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 2) “We are drawn to their <strong>magnificent and haunting beauty, as well as the enigmas they present</strong>.”</li>\n<li><strong>Giải thích:</strong> Tác giả nhấn mạnh sự pha trộn giữa vẻ đẹp và sự bí ẩn (enigmas/mystery).</li>\n</ul>\n<p><strong>15. Recent findings regarding lost civilisations have</strong></p>\n<ul>\n<li><strong>Đáp án: C. emerged from a range of disciplines.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) “This suspicion… has been <strong>substantiated by discoveries made in recent decades by archaeologists, climatologists, historians, palaeontologists, and palynologists</strong>…”</li>\n<li><strong>Giải thích:</strong> Các khám phá đến từ nhiều lĩnh vực khác nhau (a range of disciplines).</li>\n</ul>\n<p><strong>16. In discussing how previous societies fell, the writer mentions that</strong></p>\n<ul>\n<li><strong>Đáp án: A. the pace of collapse showed some resemblance across societies.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “Historical collapses generally <strong>followed similar patterns</strong> resembling variations on a theme.”</li>\n<li><strong>Giải thích:</strong> Sự sụp đổ thường theo những khuôn mẫu tương tự (similar patterns), cho thấy sự tương đồng (resemblance) về tốc độ/quá trình.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('0706a847-c489-48f5-a84e-61d100201071', 'de3dcc6f-c470-4d29-9183-b5b42227c2b2', 'matrix', 'Questions 21–26', NULL, '<p>Reading Passage 2 has eight paragraphs, <strong>A-H</strong>.</p>
<p>Which paragraph contains the following information?</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": " a figure showing the dramatic results of an anti-malarial drug programme", "correctCategoryLetter": "E"}, {"itemText": "an important discovery about how malaria is spread", "correctCategoryLetter": "C"}, {"itemText": " mention of an expert''s decision not to halt the spread of the disease", "correctCategoryLetter": "F"}, {"itemText": " the significance of the malaria story for today''s readers", "correctCategoryLetter": "H"}, {"itemText": "examples of false assumptions which held back scientific understanding of malaria", "correctCategoryLetter": "B"}, {"itemText": "reference to legislation to support the fight against malaria", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Câu 21: a figure showing the dramatic results of an anti-malarial drug programme</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> E</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Deaths from malaria fell by some <strong data-path-to-node=\"23,1,0\" data-index-in-node=\"45\">80%</strong> in the first decade of the 20th century…”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E đưa ra con số (80%) minh chứng cho hiệu quả của chương trình dùng thuốc quinine.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Câu 22: an important discovery about how malaria is spread</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C</p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Grassi demonstrated that the micro-organisms causing the disease were carried in the <strong data-path-to-node=\"25,1,0\" data-index-in-node=\"100\">digestive tract of the mosquito</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong data-path-to-node=\"25,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả khám phá quan trọng về việc muỗi là vật trung gian truyền bệnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Câu 23: mention of an expert’s decision not to halt the spread of the disease</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Đáp án:</strong> F</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Alberto Missiroli <strong data-path-to-node=\"27,1,0\" data-index-in-node=\"33\">refused to order the distribution of quinine</strong>, so allowing the epidemic to spread unchecked.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong data-path-to-node=\"27,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Chuyên gia Alberto Missiroli đã quyết định không phát thuốc quinine để tạo điều kiện cho một thí nghiệm mới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Câu 24: the significance of the malaria story for today’s readers</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Đáp án:</strong> H</p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As there are still more than 1m deaths every year… Snowden’s book also has <strong data-path-to-node=\"29,1,0\" data-index-in-node=\"89\">contemporary relevance</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong data-path-to-node=\"29,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn H nhấn mạnh ý nghĩa của câu chuyện đối với độc giả ngày nay khi bệnh sốt rét vẫn còn tồn tại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Câu 25: examples of false assumptions which held back scientific understanding of malaria</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…theory of ‘miasma’… belief that malaria was hereditary.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong data-path-to-node=\"31,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B liệt kê các giả thuyết sai lầm (khí độc, di truyền) đã cản trở việc hiểu đúng về bệnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Câu 26: reference to legislation to support the fight against malaria</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D</p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Italy introduced a <strong data-path-to-node=\"33,1,0\" data-index-in-node=\"31\">quinine law</strong> and a <strong data-path-to-node=\"33,1,0\" data-index-in-node=\"49\">quinine tax</strong> in 1904…”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong data-path-to-node=\"33,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nhắc đến việc ban hành luật và thuế liên quan đến quinine để hỗ trợ chống dịch.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('28c3fa9a-7b50-4ba0-979e-223c6274a535', '677f54f1-5801-4951-ae40-b2a57b129495', 'fillup', 'Questions 21–26', '<p>Complete the sentences below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>A small number of unusual cars are still produced by the {craft|craft production} method. Lean production requires staff who are {multi-skilled} Lean production employs fewer people, and uses less {manufacturing space} equipment and time. Storage facilities are not needed if a procedure known as {just-in-time} is implemented in the lean production method. Autonamation is a procedure for spotting any {abnormalities} in the products on a production line.At Toyota factories, {lights} are suspended above manual production lines in order to show where production has to be halted.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>21. A small number of unusual cars are still produced by the craft production method.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>craft production</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “A present day example of this method is the customised production of a few exotic sports cars… The concept of <strong>craft production</strong> remains very popular…”</li>\n</ul>\n<p><strong>22. Lean production requires staff who are multi-skilled.”</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>multi-skilled</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “…companies appoint teams of <strong>multi-skilled</strong> workers to all levels of the organisation…”</li>\n</ul>\n<p><strong>23. Lean production employs fewer people, and uses less manufacturing space equipment and time.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>manufacturing space</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…it uses less of everything – half the human effort in the factory, <strong>half the manufacturing space</strong>, half the investment in tools…”</li>\n</ul>\n<p><strong>24. Storage facilities are not needed if a procedure known as just-in-time is implemented in the lean production method.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>just-in-time</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “If <strong>just-in-time</strong> is fully realised throughout the company, then superfluous inventories are completely eliminated from the factory, making stores or warehouses unnecessary.”</li>\n</ul>\n<p><strong>25. Autonamation is a procedure for spotting any abnormalities in the products on a production line.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>abnormalities</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>Autonamation</strong> is the automatic checking for <strong>abnormalities</strong> in the production process.”</li>\n</ul>\n<p><strong>26. At Toyota factories, lights are suspended above manual production lines in order to show where production has to be halted.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>lights</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “…the worker pushes a button to stop the whole line, and <strong>lights</strong>, which are hung so high in the factory that they are visible to everyone, indicate the position of the problem.”</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('6da41d28-b19e-41c6-be9f-944436cdb5e4', '199a1fa7-a405-4e6b-9451-ffcd18ae18fa', 'radio', 'Questions 17–21', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the views of the writer. <strong>NO </strong>if the statement contradicts what the writer thinks. <strong>NOT GIVEN </strong>if it is impossible to know what the writer’s point of view is.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The impressive relics of ancient societies were influenced by Shelley''s sonnet Ozymandias."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "There is a widespread belief that environmental issues pose the principal hazard to the contemporary world"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Scientists have reached a consensus about how severe the present ecological concerns are"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The presence of poisonous substances in high concentrations is a relatively modern issue"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "We should reflect cautiously when comparing the past with the present."}]', 'null', 'null', 'null', '[{"content": "<p><strong>17. The impressive relics of ancient societies were influenced by Shelley’s sonnet <em>Ozymandias</em>.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 1) “…leaving behind grand ruins <strong>reminiscent of</strong> what poet Shelley described in his sonnet <em>Ozymandias</em>.”</li>\n<li><strong>Giải thích:</strong> Các tàn tích <strong>gợi nhớ</strong> (reminiscent of) bài thơ, không phải chúng bị bài thơ <strong>ảnh hưởng</strong> (influenced).</li>\n</ul>\n<p><strong>18. There is a widespread belief that environmental issues pose the principal hazard to the contemporary world.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “<strong>Currently, many individuals believe that environmental problems eclipse other global threats</strong>.”</li>\n<li><strong>Giải thích:</strong> “Eclipses other global threats” (che khuất các mối đe dọa khác) đồng nghĩa với việc là mối nguy hiểm chính (principal hazard).</li>\n</ul>\n<p><strong>19. Scientists have reached a consensus about how severe the present ecological concerns are.</strong></p>\n<ul>\n<li><strong>Đáp án: NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “<strong>However, the seriousness of these modern environmental dilemmas is vigorously debated among the scientific community</strong>.”</li>\n<li><strong>Giải thích:</strong> Các nhà khoa học đang tranh luận sôi nổi (“vigorously debated”), tức là chưa đạt được sự đồng thuận (consensus).</li>\n</ul>\n<p><strong>20. The presence of poisonous substances in high concentrations is a relatively modern issue.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “…plus <strong>four new ones</strong>: human-induced climate change, <strong>the accumulation of toxic chemicals</strong>…”</li>\n<li><strong>Giải thích:</strong> Việc tích tụ hóa chất độc hại được liệt kê là một trong bốn yếu tố “mới” (new ones) so với các vấn đề cổ đại, ám chỉ đây là vấn đề hiện đại.</li>\n</ul>\n<p><strong>21. We should reflect cautiously when comparing the past with the present.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “<strong>Perhaps we can still learn from the past, but only if we carefully contemplate its lessons</strong>.”</li>\n<li><strong>Giải thích:</strong> “Carefully contemplate” (cân nhắc cẩn thận) đồng nghĩa với “reflect cautiously” (phản ánh thận trọng).</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('03ab57b8-2e09-4da7-a6e9-52b84c7a0f42', '2016adb7-4086-4724-8024-d3853e8aae2c', 'fillup', 'Questions 7–13', '<p>Complete the table below.</p>
<p>Write<strong> ONE WORD ONLY </strong>from the passage for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The development of the guitar</strong></span></p>
<table class="MsoNormalTable" style="border-collapse: collapse; border: 1px solid #000000; width: 100%; height: 350.938px;" border="1" cellpadding="0">
<thead>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%; text-align: center;"><strong>Date</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%; text-align: center;"><strong>Type of instrument</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%; text-align: center;"><strong>Notes</strong></td>
</tr>
</thead>
<tbody>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>13th–19th century</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Chitarra</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">was a development of an earlier instrument called the {Chartar} • extra strings added in 16th century in Italy</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>from around the 1850s</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Classical guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">its shape a result of modifications including a larger {body} introduced by Antonio Torres • changes produced better tone and greater {volume}</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">X-braced top guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">first made in {America} in mid-19th century • strings made of {steel} became available around 1900</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>1920s onwards</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Electric guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">in the 1920s, {pickups} added to guitars • a well-known version brought out by {Gibson}</td>
</tr>
</tbody>
</table>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>7. Chitarra… was a development of an earlier instrument called the <strong>chartar</strong>.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>chartar</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong><span class=\"citation-6\">Dẫn chứng:</span></strong><span class=\"citation-6\"> (Đoạn G) “When the four-stringed Persian </span><strong><span class=\"citation-6\">chartar</span></strong><span class=\"citation-6 citation-end-6\"> arrived in Spain, however, it changed in form and construction…</span> It became known as the <strong>chitarra</strong>.</p>\n</li>\n</ul>\n<p>8. Classical guitar… modifications including a larger <strong>body</strong> introduced by Antonio Torres.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>body</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong><span class=\"citation-5\">Dẫn chứng:</span></strong><span class=\"citation-5\"> (Đoạn H) “…the Spanish guitar maker Antonio Torres </span><strong><span class=\"citation-5\">increased the size of the body</span></strong><span class=\"citation-5 citation-end-5\">…”</span></p>\n</li>\n</ul>\n<p>9. Classical guitar… changes produced better tone and greater <strong>volume</strong>.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>volume</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “His design radically increased the <strong>volume</strong> and improved the tone of the instrument…”</p>\n</li>\n</ul>\n<p>10. X-braced top guitar… first made in <strong>America</strong> in mid-19th century.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>America</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “German immigrants to <strong>America</strong> – among them Christian Fredrich Martin – began making guitars with X-braced tops.”</p>\n</li>\n</ul>\n<p>11. X-braced top guitar… strings made of <strong>steel</strong> became available around 1900.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>steel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “<strong>Steel</strong> strings, which became widely available several decades later in the early 1900s…”</p>\n</li>\n</ul>\n<p>12. Electric guitar… in the 1920s, <strong>pickups</strong> added to guitars.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>pickups</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “The electric guitar was born when <strong>pickups</strong> were fitted to Hawaiian and jazz guitars in the late 1920s…”</p>\n</li>\n</ul>\n<p>13. Electric guitar… a well-known version brought out by <strong>Gibson</strong>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjP3Z24ivKQAxUAAAAAHQAAAAAQ5gE\"></button></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>Gibson</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “…met with little success until 1836, when <strong>Gibson</strong> introduced its famous ES150 model.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('906d74d1-6267-4136-b3ed-f3ee842dcadc', '199a1fa7-a405-4e6b-9451-ffcd18ae18fa', 'matching', 'Questions 22–26', NULL, '<p>Complete each sentence with the correct ending, A-F, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A are not implacable to all socities.   "}, {"optionText": "B provide a hopeful perspective."}, {"optionText": "C is embodied all physical features"}, {"optionText": "D is potentially both positive and negative"}, {"optionText": "E will not address current issues directly."}, {"optionText": "F have increased compared to the past "}], "matchingItems": [{"questionPart": "Evidence of remarkable achievements of certain past civilisations ", "correctAnswer": "C is embodied all physical features", "sectionContent": null}, {"questionPart": "Analogies between the development of an individual and that of a society ", "correctAnswer": "A are not implacable to all socities.   ", "sectionContent": null}, {"questionPart": "The environmental challenges that societies encounter ", "correctAnswer": "F have increased compared to the past ", "sectionContent": null}, {"questionPart": "In modern society, powerful technology ", "correctAnswer": "D is potentially both positive and negative", "sectionContent": null}, {"questionPart": "Reflections on ancient events and tendencies ", "correctAnswer": "E will not address current issues directly.", "sectionContent": null}]}', 'null', '[{"content": "<p><strong>22. Evidence of remarkable achievements of certain past civilisations <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> C. is embodied all physical features</strong></p>\n<ul>\n<li><strong>Dẫn chứng:</strong> (Đoạn 2) “The grandeur of these ruins <strong>attests to the previous wealth and power</strong> of their builders…”</li>\n<li><strong>Giải thích:</strong> Sự vĩ đại của các tàn tích (physical features/grandeur) chứng minh (attests/embodied) cho sự giàu có và quyền lực trước đây.</li>\n</ul>\n<p><strong>23. Analogies between the development of an individual and that of a society <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> A. are not implacable to all socities.</strong></p>\n<ul>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “However, <strong>this metaphor proves inaccurate for many past societies</strong>… It is evident that <strong>not all past societies followed this trajectory uniformly</strong>…”</li>\n<li><strong>Giải thích:</strong> Phép ẩn dụ này không chính xác cho nhiều xã hội (not implacable to all societies).</li>\n</ul>\n<p><strong>24. The environmental challenges that societies encounter <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> F. have increased compared to the past</strong></p>\n<ul>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “These environmental problems encompass the same eight factors that contributed to past societies’ downfalls, <strong>plus four new ones</strong>…”</li>\n<li><strong>Giải thích:</strong> Các thách thức hiện đại bao gồm 8 yếu tố cũ cộng thêm 4 yếu tố mới, tức là đã gia tăng.</li>\n</ul>\n<p><strong>25. In modern society, powerful technology <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> D. is potentially both positive and negative</strong></p>\n<ul>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “We have certain advantages over past societies that reduce our risks, including our <strong>powerful technology (i.e. its beneficial effects)</strong>… At the same time… again, our <strong>potent technology (i.e. its unintended destructive effects)</strong>…”</li>\n<li><strong>Giải thích:</strong> Công nghệ có cả tác động có lợi và gây hủy hoại.</li>\n</ul>\n<p><strong>26. Reflections on ancient events and tendencies <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> E. will not address current issues directly.</strong></p>\n<ul>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “It would be naive to assume that studying the past will yield <strong>straightforward answers directly applicable to today’s world</strong>.”</li>\n<li><strong>Giải thích:</strong> Bài học từ quá khứ không cung cấp câu trả lời trực tiếp cho các vấn đề hiện tại.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('a459e15b-4537-4ea6-bb0f-d1d81540250e', '5ba7073c-bae2-4d19-b9ca-68c74456b5b8', 'fillup', 'Questions 1-10', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body"><span style="font-size: 12pt;"><strong>Rental Property Application Form</strong></span></div>
<div class="s-component-content s-font-body"> </div>
<div class="s-component-content s-font-body">
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Phone number:</strong> {614381997} (mobile)</p>
<p><strong>Email address:</strong> Susansmith@ {post.com}</p>
<p><strong>Current address: </strong>234 Becketts Road, Brisbane, 4054</p>
<p><strong>New Zealand Employer:</strong> Auckland Hospital</p>
<p><strong>Occupation:</strong> a {chemist}</p>
<p><strong>Rental start date:</strong> 8th February</p>
<p><strong>Preferred property type:</strong></p>
<ul>
<li>First preference: a house with a {garden}</li>
<li>Second preference: an apartment with a big {balcony}</li>
</ul>
<p><strong>Bedrooms:</strong> two</p>
<p><strong>Furnishings:</strong> a {fridge} is required</p>
<p><strong>Maximum rent:</strong> {400} $ per week</p>
<p><strong>Preferred location:</strong> near the {beach}</p>
<p><strong>Other requirements:</strong></p>
<ul>
<li>Must have {parking} nearby</li>
<li>Would like {electricity} included in the rent</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text "> </div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 1: RENTAL PROPERTY APPLICATION FORM</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Good morning, McMurray’s Real Estate, Peter speaking. How may I help you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Susan:</strong> Hi Peter. My name is Susan. I’m calling from Australia. I’ll be moving to New Zealand soon and I was hoping you could help me find somewhere to live in Auckland.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> Would be pleased to. I just need to get some information about what you want so we can find the perfect place.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Susan:</strong> Sounds good.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> Let’s start with some personal details. What’s your last name?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Susan:</strong> It’s Smith.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Agent:</strong> And your phone number?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Susan:</strong> I only have a mobile, is that okay?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> That’s fine.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Susan:</strong> Okay, it’s <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"18\">(1) 614381997</strong></span>. But if you want to contact me, usually the best way is by email.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> OK, what’s your email address then?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Susan:</strong> It’s susansmith@<span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"23\">(2) post.com</strong></span>. Thanks.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> Now, you said you’re living in Australia, right? In Brisbane?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Susan:</strong> OK. What’s your address in Brisbane then?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Susan:</strong> 234 Becketts—that’s B-E-C-K-E-double T-S Road, Brisbane, 4-0-5-4.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Agent:</strong> Right. Will you be working in New Zealand?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Susan:</strong> Yes, I have a job at Auckland Hospital.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Agent:</strong> Oh, are you a nurse?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Susan:</strong> Most people assume that or think I’m a doctor, but actually I’m a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"73\">(3) chemist</strong>.</span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Agent:</strong> Oh, sorry.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Susan:</strong> That’s OK.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Agent:</strong> When will you need the accommodation from?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Susan:</strong> Well, I don’t start work until February 25th, but I’d like to give myself some time to settle in. A couple of weeks would be nice. Let’s say from February 10th.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Agent:</strong> Our leases start from a Monday, and the Monday closest to that is February 8th. Would that suit?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Susan:</strong> That’s fine.</p>\n<hr data-path-to-node=\"28\">\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Agent:</strong> Okay, let’s talk about what kind of place you’d like to rent.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Susan:</strong> Hmm, I like the outdoors, so my dream would be a house that has its own <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"79\">(4) garden</strong>.</span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Agent:</strong> Is there anything else you’d consider? An apartment, for example?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Susan:</strong> I don’t know, they usually don’t have an outdoor area, but I guess as an alternative, if you could find me one with a large <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"131\">(5) balcony</strong></span>, I’d be happy.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Agent:</strong> How many rooms do you want?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Susan:</strong> Usually one-bedroom places are too small. Two would be ideal.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Agent:</strong> Now, what would you like to have in the place when you move in?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Susan:</strong> I’m bringing most of what I need with me. I have beds and sofas and a television, all that sort of stuff, so none of that is necessary.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Agent:</strong> Sounds like you want a partially furnished house. With a washing machine?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Susan:</strong> Actually, I’m bringing that too. All I really need in the place is a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"38\" data-index-in-node=\"76\">(6) fridge</strong></span>. I don’t have one, so we’ll definitely need one.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Agent:</strong> Okay. Can you find something like that for around $350 a week?</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Susan:</strong> Well, I’ll certainly try. I’ll start looking for places that cost around $300 and see if there’s anything suitable. You definitely won’t need to pay more than <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"40\" data-index-in-node=\"166\">(7) 400</strong> </span>for something like that.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Susan:</strong> Oh, that’s good. I couldn’t pay more than that.</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Agent:</strong> Alright, I’ll see what I can find. You’re working at the hospital—do you want to live somewhere near there?</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Susan:</strong> Most people think it’s strange, but I don’t like living close to work. But I’m a mad keen surfer, so it’s important for me to be close to the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"43\" data-index-in-node=\"149\">(8) beach</strong>.</span></p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Agent:</strong> Okay. Do you need to be near public transport?</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Susan:</strong> No, I usually drive to work because I work a lot of shift work. So wherever I live, we’ll need to have <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"45\" data-index-in-node=\"110\">(9) parking</strong></span> close to the door, so I won’t have to walk far at night.</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Agent:</strong> Anything else?</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Susan:</strong> I’ve heard that power bills can get quite expensive, especially in the winter. It would be great if <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"47\" data-index-in-node=\"107\">(10) electricity</strong></span> was part of the rent.</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Agent:</strong> OK, just one last question for our records: where did you hear about us?</p>"}]', 0);
INSERT INTO public.questions VALUES ('775f79f6-13df-43c4-9d01-8e56ed7fd825', '5886a9bd-50fd-4e04-9a10-3c65407c6767', 'matrix', 'Questions 27–31', '', '<p>Reading Passage 3 has eight paragraphs, A–H.</p>
<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, A–H, in boxes 27–31 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "A strategy to avoid being attacked", "correctCategoryLetter": "D"}, {"itemText": "How fish are able to keep afloat naturally", "correctCategoryLetter": "C"}, {"itemText": "The physical process by which fish propel themselves ahead", "correctCategoryLetter": "G"}, {"itemText": "A list of reasons why different creatures move from one place to another", "correctCategoryLetter": "A"}, {"itemText": "How the medium of water both restricts and aids movement", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">27. D — {A strategy to avoid being attacked}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">\"Species that live below the level where sunlight reaches, nightly swim hundreds of meters up to the surface to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"123\">feed in the relative safety of darkness</strong>. At dawn, they sink back down <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"193\">in an effort to escape predators</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chiến thuật di chuyển lên bề mặt vào ban đêm để ăn dưới sự bảo vệ của bóng tối và lặn xuống vào ban ngày chính là chiến thuật giúp sinh vật phù du trốn thoát khỏi kẻ săn mồi (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"187\">escape predators / avoid being attacked</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">28. C — {How fish are able to keep afloat naturally}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">\"Most fishes have <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"29\">swim bladders to help them offset the density of their bodies and so maintain neutral buoyancy with minimal effort</strong>... The ability to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"162\">remain indefinitely at a constant depth without expending energy</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích cơ chế sinh lý của bóng hơi (swim bladders) giúp cá giữ được trạng thái nổi cân bằng và ở một độ sâu cố định một cách tự nhiên mà hầu như không tốn năng lượng (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"192\">keep afloat naturally / without expending energy</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">29. G — {The physical process by which fish propel themselves ahead}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">\"Strong W-shaped muscles along the side of the body progressively contract and relax in sequence... creating a traveling horizontal wave. The body is thrown into a series of curves that press sideways and back against the water, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"240\">producing a forward thrust</strong>.\"</em>*</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này mô tả chi tiết quá trình vật lý/cơ học (co duỗi cơ chữ W, tạo sóng ngang, ép vào nước) để tạo ra lực đẩy về phía trước (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"141\">producing a forward thrust / propel themselves ahead</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">30. A — {A list of reasons why different creatures move from one place to another}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“...but the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"23\">basic requirements are the same—finding food, avoiding predation, seeking a mate or a safe place to have young, or migrating</strong> to an area with more favorable conditions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn liệt kê một loạt các lý do/nhu cầu thiết yếu khiến sinh vật phải di chuyển: tìm thức ăn, tránh kẻ thù, tìm bạn đời, sinh con, di cư. Ý này khớp hoàn toàn với cụm \"a list of reasons\".</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. B — {How the medium of water both restricts and aids movement}</strong></p>\n<ul>\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> * <em data-path-to-node=\"15,0,0\" data-index-in-node=\"13\">Gây hạn chế:</em> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">\"Consequently, there is <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"50\">much more resistance to movement than on land</strong>...\"</em></p>\n</li>\n<li data-path-to-node=\"15,0,1,0,0\"><em data-path-to-node=\"15,0,1,0,0\" data-index-in-node=\"0\">Hỗ trợ:</em> <em data-path-to-node=\"15,0,1,0,0\" data-index-in-node=\"8\">\"However, with density comes <strong data-path-to-node=\"15,0,1,0,0\" data-index-in-node=\"37\">much greater buoyancy, so that organisms need spend relatively little energy to stay afloat</strong>.\"</em></li>\n<li data-path-to-node=\"15,0,1,1,0\"><strong data-path-to-node=\"15,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B chỉ ra môi trường nước vừa gây cản trở/hạn chế di chuyển (do mật độ và độ nhớt tạo ra nhiều lực cản - <em data-path-to-node=\"15,0,1,1,0\" data-index-in-node=\"121\">resistance</em>) nhưng đồng thời cũng hỗ trợ/giúp ích (lực nổi giúp sinh vật giữ cơ thể nổi mà ít tốn năng lượng - <em data-path-to-node=\"15,0,1,1,0\" data-index-in-node=\"231\">buoyancy</em>).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2886515e-d3e5-4a8f-92ef-4ee3e9c1395a', '5886a9bd-50fd-4e04-9a10-3c65407c6767', 'fillup', 'Questions 32–35', '<p data-start="520" data-end="550">Complete the flow chart below.</p>
<p data-start="552" data-end="619">Choose <strong data-start="559" data-end="585">NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p data-start="621" data-end="676">Write your answers in boxes 32–35 on your answer sheet.</p>
<div class="TyagGW_tableContainer">
<div class="group TyagGW_tableWrapper flex flex-col-reverse w-fit" tabindex="-1">
<table class="w-fit min-w-(--thread-content-width)" style="border-collapse: collapse; width: 88.9657%; height: 331.506px; border-spacing: 1px; border: 1px solid rgb(0, 0, 0);" border="1" data-start="698" data-end="1008">
<thead data-start="698" data-end="744">
<tr style="height: 57.0028px;">
<th style="border-color: #000000; border-width: 1px; padding: 1px; width: 99.9885%;" colspan="2">
<p style="text-align: center;"><strong><span style="font-size: 14pt;">Specialisation</span></strong></p>
</th>
</tr>
<tr style="height: 50.483px;" data-start="698" data-end="744">
<th class="last:pe-10" style="border-color: #000000; width: 54.0007%; border-width: 1px; padding: 1px; text-align: center;" data-start="698" data-end="720" data-col-size="md">
<p>Specialised ability</p>
</th>
<th class="last:pe-10" style="border-color: #000000; width: 45.9878%; border-width: 1px; padding: 1px; text-align: center;" data-start="720" data-end="744" data-col-size="sm">
<p>Example fish species</p>
</th>
</tr>
</thead>
<tbody data-start="755" data-end="1008">
<tr style="height: 70.0852px;" data-start="755" data-end="837">
<td style="border-color: #000000; width: 54.0007%; border-width: 1px; padding: 1px;" data-start="755" data-end="824" data-col-size="md">
<p>Ability to maintain the same {speed} over long distances</p>
</td>
<td style="border-color: #000000; width: 45.9878%; border-width: 1px; padding: 1px;" data-start="824" data-end="837" data-col-size="sm">
<p>Swordfish</p>
</td>
</tr>
<tr style="height: 50.483px;" data-start="838" data-end="877">
<td style="border-color: #000000; width: 54.0007%; border-width: 1px; padding: 1px;" data-start="838" data-end="864" data-col-size="md">
<p>Rapid {acceleration}</p>
</td>
<td style="border-color: #000000; width: 45.9878%; border-width: 1px; padding: 1px;" data-start="864" data-end="877" data-col-size="sm">
<p>Barracuda</p>
</td>
</tr>
<tr style="height: 52.9688px;" data-start="878" data-end="957">
<td style="border-color: #000000; width: 54.0007%; border-width: 1px; padding: 1px;" data-start="878" data-end="936" data-col-size="md">
<p>Sudden attack on prey following period of lying in wait</p>
</td>
<td style="border-color: #000000; width: 45.9878%; border-width: 1px; padding: 1px;" data-start="936" data-end="957" data-col-size="sm">
<p>{freshwater pike| pike}</p>
</td>
</tr>
<tr style="height: 50.483px;" data-start="958" data-end="1008">
<td style="border-color: #000000; width: 54.0007%; border-width: 1px; padding: 1px;" data-start="958" data-end="987" data-col-size="md">
<p>Rapid changes of direction</p>
</td>
<td style="border-color: #000000; width: 45.9878%; border-width: 1px; padding: 1px;" data-start="987" data-end="1008" data-col-size="sm">
<p>{butterfly fishes}</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">32. speed — {Ability to maintain the same cruising speed over long distances / Example: Swordfish}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">\"Tuna, <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"27\">swordfish</strong>, and mackerel all specialize in <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"69\">fast, steady cruising</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cá kiếm (swordfish) thuộc nhóm chuyên về bơi đường trường nhanh và ổn định. Cụm từ \"maintain the same... over long distances\" (duy trì sự ổn định trên khoảng cách dài) đồng nghĩa với từ bơi đường trường ổn định (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"224\">speed</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">33. acceleration — {Rapid acceleration / Example: Barracuda}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"20\">\"This formidable predator [<strong data-path-to-node=\"21,0,0\" data-index-in-node=\"47\">barracuda</strong>] specializes in <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"73\">swift acceleration</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Swift\" đồng nghĩa với \"rapid\" (nhanh chóng). Cá nhồng (barracuda) là loài cá chuyên về khả năng tăng tốc nhanh chóng (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"131\">acceleration</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">34. freshwater pike / pike — {Sudden attack on prey following period of lying in wait / Example: freshwater pike / pike}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">\"The <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"25\">freshwater pike</strong>, which <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"48\">lurks in the shadows until its quarry is within striking distance and then lunges with great rapidity</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Hành động ẩn nấp trong bóng tối chờ con mồi (</span><em class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"57\">lurks in the shadows</em><span class=\"\">) tương ứng với cụm \"lying in wait\" (phục kích),</span><span class=\"\"> và lao ra rất nhanh (</span><em class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"147\">lunges with great rapidity</em><span class=\"\">) tương ứng với \"sudden attack\" (tấn công bất ngờ).</span><span class=\"\"> Tên loài cá cần điền là </span><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"249\">freshwater pike</strong><span class=\"\"> (hoặc </span><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"271\">pike</strong><span class=\"\">).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">35. butterfly fishes — {Rapid changes of direction / Example: butterfly fishes}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">\"The third specialization is maneuverability, best demonstrated by the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"91\">butterfly fishes</strong>. These have disk-shaped bodies that <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"144\">permit abrupt changes of track</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> \"Abrupt changes of track\" (thay đổi đường đi đột ngột) chính là cách viết khác của \"rapid changes of direction\".</span><span class=\"\"> Loài cá minh họa cho khả năng này là cá bướm (</span><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"171\">butterfly fishes</strong><span class=\"\">).</span></p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('dd502cb3-3d05-47c0-8456-45dc35a48605', 'b3ed8ffa-14a8-468d-adc8-5ac3bab65a16', 'matching', 'Questions 14–19', '', '<p>The text has six paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "Evidence that man’s ancestors had a concept of the future"}, {"optionText": "Research into the relation between brain size and memory"}, {"optionText": "Animals that can remember places and time"}, {"optionText": "Research into various animals’ capacity for future planning"}, {"optionText": "A memory type described with reference to brain damage"}, {"optionText": "Conflicting experimental results concerning animal memory"}, {"optionText": "Research evidence of memory loss in various animals"}, {"optionText": "Experimental evidence of a relation between past and future in human mental processes"}, {"optionText": "Research into ways to improve episodic memory"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. A memory type described with reference to brain damage</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Clues about different kinds of memory can be discovered from research conducted on <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"95\">people with certain brain injuries</strong>… A man known as <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"148\">KC</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giới thiệu về <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"35\">episodic memory</strong> (trí nhớ tình tiết) thông qua ví dụ về bệnh nhân KC — người bị chấn thương não (<em data-path-to-node=\"4,2,0\" data-index-in-node=\"131\">brain damage/injuries</em>) dẫn đến việc mất đi khả năng nhớ các sự kiện cá nhân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. Animals that can remember places and time</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…test American birds called <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"42\">western scrub jays</strong>… The birds that waited only <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"91\">four hours</strong> tended to dig up larvae, while the birds that had to wait for <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"164\">five days</strong>… dug up peanuts instead.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm chứng minh loài chim này không chỉ nhớ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"62\">vị trí</strong> (<em data-path-to-node=\"6,2,0\" data-index-in-node=\"70\">places/location</em>) giấu đồ ăn mà còn nhớ cả <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"112\">thời gian</strong> (<em data-path-to-node=\"6,2,0\" data-index-in-node=\"123\">time/how long ago</em>) để biết khi nào sâu bướm sẽ bị hỏng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. Conflicting experimental results concerning animal memory</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Research with other animals… has had <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"51\">mixed results</strong>. When experimental <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"84\">rats</strong>… seem to be able to recall… <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"121\">hummingbirds</strong>… show that they remember… Tests using <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"176\">Rhesus monkeys</strong> have found that they can remember where… but <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"238\">not how long ago</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Mixed results” ở đây chính là các kết quả trái chiều (<em data-path-to-node=\"8,2,0\" data-index-in-node=\"67\">conflicting</em>). Trong khi chuột và chim ruồi có vẻ có trí nhớ tình tiết, thì khỉ Rhesus lại thất bại trong việc ghi nhớ yếu tố thời gian.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Evidence that man’s ancestors had a concept of the future</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…discovery of <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"28\">stone tools</strong> which <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"46\">primitive humans</strong> used… 1.6 million years ago. …the only reason you’re going to take a tool with you is if you <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"160\">anticipate using it in the future</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tổ tiên loài người mang theo công cụ đá đi xa nơi sản xuất là bằng chứng cho thấy họ có khả năng dự tính cho nhu cầu trong tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. Experimental evidence of a relation between past and future in human mental processes</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"12\">Recent brain scanning studies</strong>… many parts of the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"63\">same episodic memory networks</strong> become active again [when thinking about the future]… suggesting an <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"163\">inter-connection</strong> between the processing of the past and future.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các cuộc quét não cung cấp bằng chứng thực nghiệm (<em data-path-to-node=\"12,2,0\" data-index-in-node=\"63\">experimental evidence</em>) cho thấy vùng não nhớ về quá khứ và vùng não tưởng tượng tương lai có liên quan chặt chẽ với nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. Research into various animals’ capacity for future planning</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…look for evidence that <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"38\">animals can also think ahead</strong>. …<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"71\">Cebus monkeys</strong>… will eat until they are full and throw the rest… [but] <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"145\">squirrel monkeys</strong>… learned to choose one [to get water sooner].”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này tập trung vào các nghiên cứu trên các loài động vật khác nhau (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"84\">various animals</em>) để xem chúng có khả năng lập kế hoạch cho tương lai (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"154\">future planning/think ahead</em>) hay không.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('1f91c60d-647e-49af-a636-caf0a1ab2c68', 'ca1c622c-a77f-4ba5-a395-9bfe5e8e298b', 'matching', 'Questions 14–19', NULL, '<p>Reading Passage has six paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, i-vii, in boxes <strong>14-19</strong>.</p>
', 'matching', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The effect of man-made imitations on insects"}, {"optionText": "ii The need to instruct additional insect guides"}, {"optionText": "iii Signals used by certain insects to indicate a discovery"}, {"optionText": "iv How urgency can affect the process of finding a new home"}, {"optionText": "v The use of trained insects in testing scientific theories"}, {"optionText": "vi The use of virtual scenarios in the study of insect behaviour"}, {"optionText": "vii How the number of decision-makers affects the decision"}], "matchingItems": null}', 'null', '[{"content": "<p>14. Paragraph 1</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>vii. How the number of decision-makers affects the decision</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “The idea goes back to the ‘jury theorem’ of Nicolas de Condorcet… The probability of a correct decision <strong>increases with the size of the jury</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn này giới thiệu lý thuyết của Condorcet, nói về việc <strong>quy mô nhóm</strong> (số lượng người đưa ra quyết định) ảnh hưởng đến tính chính xác của quyết định (Condorcet’s jury theorem).</p>\n</li>\n</ul>\n<p>15. Paragraph 2</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>iii. Signals used by certain insects to indicate a discovery</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) Các nhà nghiên cứu quan sát bầy ong mật tìm kiếm tổ mới và <strong>sử dụng điệu nhảy waggle</strong> (<em>“waggle dance”</em>) để <strong>báo cáo</strong> (<em>“indicate”</em>) cho những con ong khác về địa điểm phù hợp mà chúng đã tìm thấy.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Đoạn này mô tả cách ong mật sử dụng tín hiệu vật lý (“waggle dance”) để thông báo về việc tìm thấy tổ mới.</p>\n</li>\n</ul>\n<p>16. Paragraph 3</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>vi. The use of virtual scenarios in the study of insect behaviour</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “Dr List and his colleagues used a <strong>computer generated model</strong> of the decision-making process.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn này mô tả việc sử dụng <strong>mô hình máy tính</strong> (<em>computer generated model / virtual scenarios</em>) để mô phỏng và nghiên cứu quá trình ra quyết định của ong.</p>\n</li>\n</ul>\n<p>17. Paragraph 4</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>i. The effect of man-made imitations on insects</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) José Halloy of the Free University of Brussels in Belgium used <strong>robotic cockroaches</strong> to subvert the behaviour of living cockroaches and control their decision-making process.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn này mô tả việc sử dụng <strong>bản sao do con người tạo ra</strong> (<em>robotic cockroaches / man-made imitations</em>) để thao túng quyết định của côn trùng sống.</p>\n</li>\n</ul>\n<p>18. Paragraph 5</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>iv. How urgency can affect the process of finding a new home</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Franks and his associates reported how the insects reduce the problems associated with making a <strong>necessarily swift choice</strong>. If the ants’ existing nest become <strong>suddenly threatened</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Đoạn này tập trung vào việc kiến phải đưa ra <strong>lựa chọn nhanh chóng</strong> (<em>swift choice</em>) khi tổ bị đe dọa đột ngột (urgency).</p>\n</li>\n</ul>\n<p>19. Paragraph 6</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án:</strong> <strong>ii. The need to instruct additional insect guides</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “Once the suitable new nest is identified, the <strong>chosen ants begin to lead others</strong>… <strong>and simultaneously show the way to those ants</strong> which have been left behind to guard the old nest.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Đoạn này mô tả cách các con kiến được chọn làm người dẫn đường (<em>lead others / instruct guides</em>) để chuyển tổ nhanh chóng và hiệu quả.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('3745952b-0689-4207-b048-d75f812ab2fe', 'bbf91301-5bb1-4a15-8465-c0a0f209930a', 'radio', 'Questions 27–30', '', '<p>Choose the correct letter, <strong data-path-to-node="3" data-index-in-node="27">A, B, C</strong> or <strong data-path-to-node="3" data-index-in-node="38">D</strong>.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A. Misinformation is a relatively recent phenomenon."}, {"option_text": "B. Some people find it easy to identify misinformation."}, {"option_text": "C. Misinformation changes as it is passed from one person to another."}, {"option_text": "D. There may be a number of reasons for the spread of misinformation."}], "question": "What point does the writer make about misinformation in the first paragraph?"}, {"correct": 0, "options": [{"option_text": "A. It may at some point provide us with a solution to misinformation."}, {"option_text": "B. It could fundamentally alter the way in which people regard information."}, {"option_text": "C. It has changed the way in which organisations use misinformation."}, {"option_text": "D. It has made it easier for people to check whether information is accurate."}], "question": "What does the writer say about the role of technology?"}, {"correct": 2, "options": [{"option_text": "A. comparing the different opinions people have of misinformation"}, {"option_text": "B. explaining how the effects of misinformation have changed over time"}, {"option_text": "C. outlining which issues connected with misinformation are significant today"}, {"option_text": "D. describing the attitude of policy makers towards misinformation in the media"}], "question": "What is the writer doing in the fourth paragraph?"}, {"correct": 3, "options": [{"option_text": "A. The guidelines issued by the FDA need to be simplified."}, {"option_text": "B. Regulation does not affect people’s opinions of new prescription drugs."}, {"option_text": "C. The USA has more regulatory bodies than most other countries."}, {"option_text": "D. Regulation fails to prevent misinformation from appearing in the media."}], "question": "What point does the writer make about regulation in the USA?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">27. What point does the writer make about misinformation in the first paragraph? — {D. There may be a number of reasons for the spread of misinformation.}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">\"...Deceiving others can offer an apparent opportunity to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"69\">gain strategic advantage</strong>, to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"98\">motivate others to action</strong>, or even to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"136\">protect interpersonal bonds</strong>. Moreover, people <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"182\">inadvertently</strong> [vô tình] have been sharing...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê nhiều lý do (a number of reasons) dẫn đến tin giả: để giành lợi thế, thúc đẩy hành động, bảo vệ mối quan hệ, hoặc thậm chí là chia sẻ vô ý. Điều này khớp với phương án D.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">28. What does the writer say about the role of technology? — {A. It may at some point provide us with a solution to misinformation.}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">\"Yet the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">means to correct misinformation might</strong>, over time, <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"70\">be found in those same patterns of mass communication</strong> and of the facilitated spread of information.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho rằng công nghệ (mass communication) dù làm lây lan tin giả nhưng cũng chính là nơi có thể tìm thấy phương tiện (means) để khắc phục/giải quyết (solution) vấn đề này trong tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">29. What is the writer doing in the fourth paragraph? — {C. outlining which issues connected with misinformation are significant today}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">\"At least <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"21\">three observations</strong> related to misinformation in the contemporary mass-media environment <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"109\">warrant the attention</strong> of researchers, policy makers, and really everyone...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra 3 quan sát (3 vấn đề chính) cần được chú ý trong môi trường truyền thông hiện đại. Việc \"outline\" (phác thảo/nêu ra) các vấn đề này chính là nội dung trọng tâm của đoạn 4.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">30. What point does the writer make about regulation in the USA? — {D. Regulation fails to prevent misinformation from appearing in the media.}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">\"Such programs [FDA''s programs]... <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"46\">do not keep false advertising off the airwaves</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các quy định của cơ quan như FDA dù hữu ích nhưng không giữ được quảng cáo sai sự thật khỏi sóng truyền hình (off the airwaves). Nghĩa là hệ thống quản lý hiện tại thất bại trong việc ngăn chặn (fails to prevent) tin giả xuất hiện trên truyền thông.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('3734efb3-21d6-4058-8e52-83c228dce011', 'aac63b35-48f6-4960-811a-ca521dccb2b5', 'fillup', 'Questions 6–13', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>LUCY</strong></span></p>
<p><strong>Physical features</strong></p>
<p>– jaws and skull like those of an ape</p>
<p>– braincase similar in size to that of a chimp</p>
<p>– long arms</p>
<p><strong>Movement</strong></p>
<p>– the positioning and shape of her pelvis made it clear that she walked like a human</p>
<p>– upright movement possibility started among the {branches}<span class="fill-history-correct"> </span>of trees</p>
<p>– probably moved to the {ground} in search of food</p>
<p><strong>Diet and eating habits</strong></p>
<p>– analysis of food in the {teeth} of the skeletons of early humans shows changes in their diet</p>
<p>– it is likely that meat and grasses were substituted for {fruit}</p>
<p>– {Eggs } that were located close to Lucy suggest these were also part of her diet</p>
<p>– {Bones} that were found had marks on them, possibly made by tools used for eating</p>
<p><strong>Comparisons with modern-day humans</strong></p>
<p>– modern-day humans have a longer {childhood} than Lucy did</p>
<p>– the {brains }of modern-day humans appear to develop later than Lucy’s did</p>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h3 data-path-to-node=\"1\">Câu 6: branches</h3>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 2-3.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It may be that upright walking evolved in the trees, as a way to walk along <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"88\">branches</strong>…”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đề cập rằng việc đi thẳng có thể đã tiến hóa từ trên cây, như một cách để di chuyển dọc theo các “nhành cây” (branches).</li>\n</ul>\n<h3 data-path-to-node=\"3\">Câu 7: ground</h3>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But hunting for food may have been the real reason for heading to the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"82\">ground</strong>…”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra giả thuyết rằng việc tìm kiếm thức ăn là lý do thực sự khiến loài người cổ đại rời bỏ cây để đi xuống “mặt đất” (ground).</li>\n</ul>\n<h3 data-path-to-node=\"5\">Câu 8: teeth</h3>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 1-2.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Studies of the remains of food trapped on preserved human <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"70\">teeth</strong> indicate…”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà khoa học đã phân tích những mảnh vụn thức ăn còn sót lại trên “răng” (teeth) hóa thạch để tìm hiểu về sự thay đổi trong chế độ ăn.</li>\n</ul>\n<h3 data-path-to-node=\"7\">Câu 9: fruit</h3>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 3-4.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Instead of mostly eating <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"37\">fruit</strong> from trees, they began to include grasses and possibly meat.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì chủ yếu ăn “trái cây” (fruit), chế độ ăn của họ đã thay đổi bằng cách bổ sung thêm cỏ và thịt.</li>\n</ul>\n<h3 data-path-to-node=\"9\">Câu 10: eggs</h3>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 5-6.</li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Fossilised crocodile and turtle <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"44\">eggs</strong> were found near her skeleton…”</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tìm thấy hóa thạch “trứng” (eggs) cá sấu và rùa gần bộ xương Lucy gợi ý rằng đây cũng là một phần thức ăn của cô ấy.</li>\n</ul>\n<h3 data-path-to-node=\"11\">Câu 11: bones</h3>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 3-4.</li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…archaeologists uncovered animal <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"47\">bones</strong> with scratches that seem to have been made by stone tools.”</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những chiếc “xương” (bones) động vật được tìm thấy có các vết trầy xước, cho thấy chúng có thể đã bị tác động bởi các công cụ dùng để ăn thịt.</li>\n</ul>\n<h3 data-path-to-node=\"13\">Câu 12: childhood</h3>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 9, dòng 1-2.</li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It also seems that Lucy’s <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"38\">childhood</strong> was much briefer than ours…”</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc so sánh và cho biết “tuổi thơ” (childhood) của Lucy ngắn hơn (briefer) so với người hiện đại chúng ta.</li>\n</ul>\n<h3 data-path-to-node=\"15\">Câu 13: brains</h3>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 9, dòng 5-6.</li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a recent study of a 3-year-old early human suggested that their <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"79\">brains</strong> matured much earlier than ours do.”</li>\n<li><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu chỉ ra rằng “bộ não” (brains) của loài người cổ đại trưởng thành sớm hơn so với sự phát triển não bộ của người hiện đại.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('3474183f-2b20-49d5-9289-400ab23e9c44', '048a5c56-7bf6-4aa4-8ebd-4b78544ba306', 'matching', 'Questions 1-8', '', '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Write the correct number, <strong data-path-to-node="4" data-index-in-node="149">i-x</strong>, in boxes 1-8 on your answer sheet.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i  Not enough tea to meet demand"}, {"optionText": "ii  Religious objections"}, {"optionText": "iii In and sometimes out of fashion"}, {"optionText": "iv A connection between tea and religion"}, {"optionText": "v A luxury item"}, {"optionText": "vi News of tea reaches another continent"}, {"optionText": "vii Is tea a good or a bad thing?"}, {"optionText": "viii A chance discover"}, {"optionText": "ix Tea-making as a ritual"}, {"optionText": "x Difficulties in importing tea"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1: {viii. A chance discovery}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Dried leaves from a nearby bush <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"44\">fell into the boiling water</strong>… the Emperor was intrigued by the new liquid, drank some, and found it very refreshing.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc lá trà rơi vào nồi nước sôi là một sự kiện ngẫu nhiên (by chance). Hoàng đế không chủ ý pha trà từ đầu, nên đây được coi là một cuộc <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"150\">phát kiến tình cờ</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2: {iv. A connection between tea and religion}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…reflecting <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">Zen Buddhist philosophy</strong>… brought to Japan by a returning <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"85\">Buddhist priest</strong>… enhancing <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"114\">meditation</strong>… linked with Zen Buddhism.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này lặp đi lặp lại các thuật ngữ liên quan đến tôn giáo như: Phật giáo Thiền tông (Zen Buddhism), thầy tu (priest), thiền định (meditation).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3: {ix. Tea-making as a ritual}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tea was elevated to an <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"35\">art form in the Japanese tea ceremony</strong>… most perfect, most polite, most graceful… manner possible.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ceremony” (nghi lễ) và cách thức pha trà tỉ mỉ, lịch sự chính là biểu hiện của một <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">nghi thức (ritual)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4: {vi. News of tea reaches another continent}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…information concerning the then-unknown beverage began to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"73\">filter back to Europe</strong>… The first European to personally encounter tea…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trà vốn ở châu Á, đoạn này kể về việc thông tin về trà bắt đầu truyền sang <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"87\">châu Âu</strong> (một lục địa khác – <em data-path-to-node=\"11,1,0\" data-index-in-node=\"115\">another continent</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5: {v. A luxury item}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…due in part to tea being <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"40\">very expensive (over $100 per pound)</strong>, which immediately made it the domain of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"122\">wealthy</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì giá trà rất đắt đỏ và chỉ dành cho người giàu nên nó được coi là một <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"84\">mặt hàng xa xỉ (luxury item)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6: {vii. Is tea a good or a bad thing?}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…doctors and university authorities in Holland <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"61\">argued as to its benefits or drawbacks</strong>… the controversy lasted…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tranh luận về lợi ích (benefits) hay tác hại (drawbacks) chính là đang xem xét trà là <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"103\">thứ tốt hay xấu</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7: {iii. In – and sometimes out – of fashion}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tea remained popular in France for only about fifty years, <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"71\">being replaced by a preference for wine, chocolate and exotic coffees</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trà từng rất được ưa chuộng (in fashion) nhưng sau đó lại bị thay thế bởi các thức uống khác (out of fashion) tại Pháp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8: {x. Difficulties in importing tea}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Still, the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"23\">journey was not easy</strong>. The average caravan consisted of 200 to 300 camels and the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"104\">18,000-kilometre trip took over 16 months</strong> to complete.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này mô tả sự khắc nghiệt của quãng đường vận chuyển trà từ Trung Quốc sang Nga, tức là những <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"110\">khó khăn trong việc nhập khẩu</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b3228272-ff0e-495f-bb95-6e008898635d', '048a5c56-7bf6-4aa4-8ebd-4b78544ba306', 'matrix', 'Questions 9–13', '', '<p>Look at the following statements (Question 9–13) and the list of countries below.</p>
<p>Match each statement with the correct country, A–G.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of countries", "matrixItems": [{"itemText": "Claims that tea might be harmful failed to affect its popularity.", "correctCategoryLetter": "D"}, {"itemText": "Tea lost favour to other drinks.", "correctCategoryLetter": "E"}, {"itemText": "Special buildings were constructed in which to drink tea.", "correctCategoryLetter": "B"}, {"itemText": "Animals were involved in importing tea.", "correctCategoryLetter": "G"}, {"itemText": "A ruler’s specialist knowledge led to an interest in tea.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "China", "categoryLetter": "A"}, {"categoryText": "Japan", "categoryLetter": "B"}, {"categoryText": "Portugal", "categoryLetter": "C"}, {"categoryText": "Holland", "categoryLetter": "D"}, {"categoryText": "France", "categoryLetter": "E"}, {"categoryText": "England", "categoryLetter": "F"}, {"categoryText": "Russia", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">9. Claims that tea might be harmful failed to affect its popularity. — {D: Holland}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">doctors and university authorities in </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"53\">Holland</strong><span class=\"\"> argued as to its benefits or </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"90\">drawbacks</strong><span class=\"\">.</span><span class=\"\"> The </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"105\">public largely ignored the scholarly debate</strong><span class=\"\"> and continued to enjoy their new beverage…</span><span class=\"\">” (Đoạn 6)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Harmful” tương ứng với “drawbacks” (tác hại).</span><span class=\"\"> Việc công chúng phớt lờ các cuộc tranh luận và tiếp tục thưởng thức trà cho thấy những lời cảnh báo không làm ảnh hưởng đến sự phổ biến của nó tại Hà Lan.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">10. Tea lost favour to other drinks. — {E: France}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Tea remained popular in </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"36\">France</strong><span class=\"\"> for only about fifty years,</span> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"71\">being replaced by a preference for wine, chocolate and exotic coffees</strong><span class=\"\">.</span><span class=\"\">” (Đoạn 7)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Lost favour” (không còn được ưa chuộng) tương ứng với việc bị thay thế bởi rượu vang,</span><span class=\"\"> sô-cô-la và cà phê tại Pháp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">11. Special buildings were constructed in which to drink tea. — {B: Japan}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">prompted the creation of a </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">particular form of architecture for tea houses</strong><span class=\"\"> [in </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"93\">Japan</strong><span class=\"\">],</span><span class=\"\"> duplicating the simplicity of a forest cottage.</span><span class=\"\">” (Đoạn 3)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Special buildings” chính là các “tea houses” (trà thất) với lối kiến trúc riêng biệt được xây dựng tại Nhật Bản.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">12. Animals were involved in importing tea. — {G: Russia}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “The average </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"24\">caravan</strong><span class=\"\"> consisted of </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"45\">200 to 300 camels</strong><span class=\"\"> and the 18,</span><span class=\"\">000-kilometre trip [to </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"97\">Russia</strong><span class=\"\">] took over 16 months to complete.</span><span class=\"\">” (Đoạn 8)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc sử dụng lạc đà (camels) để vận chuyển trà sang Nga chính là sự tham gia của động vật trong quá trình nhập khẩu.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">13. A ruler’s specialist knowledge led to an interest in tea. — {A: China}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">the </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"19\">Emperor Shen Nung [of China]</strong><span class=\"\"> was a skilled ruler,</span> <strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"69\">creative scientist</strong><span class=\"\">…</span><span class=\"\"> As a scientist,</span><span class=\"\"> the Emperor was </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"123\">intrigued by the new liquid</strong><span class=\"\">,</span><span class=\"\"> drank some,</span><span class=\"\"> and found it very refreshing.</span><span class=\"\">” (Đoạn 1)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong class=\"\" data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Ruler” là Hoàng đế Thần Nông,</span><span class=\"\"> “specialist knowledge” tương ứng với vai trò nhà khoa học (scientist) của ông.</span><span class=\"\"> Chính sự tò mò và kiến thức của ông đã dẫn đến việc khám phá ra trà.</span></p>\n</li>\n</ul>"}]', 1);
