INSERT INTO public.questions VALUES ('d4a976fd-76b3-4d0b-9a4f-3282cc001708', 'b6ab50b8-ac9f-4a3b-b1e4-a267c6b6981f', 'fillup', 'Questions 9-13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Marc Brunel’s tunnel</strong></span></p>
<p><strong>Preparing to build the tunnel</strong></p>
<ul>
<li>Brunel noticed how a kind of {worm} made its tunnels in wood.</li>
<li>Brunel created a device called a tunnelling shield, to protect people working under the river.</li>
<li>Brunel planned to build a shallow tunnel so the earth would have a higher content of {clay} .</li>
</ul>
<p><strong>Problems faced by miners</strong></p>
<ul>
<li>There were frequent floods caused by mechanical breakdowns.</li>
<li>The miners suffered from {headaches} because of pollution in the tunnels.</li>
<li>Lighting problems led to several {accidents}.</li>
<li>Some workers quit because of the high temperatures in the tunnel.</li>
</ul>
<p><strong>After the tunnel was finished</strong></p>
<ul>
<li>The tunnel was finally completed in 1841.</li>
<li>Brunel did not have enough money to repay his debt to the {government}.</li>
<li>The tunnel was abandoned until the 1880s.</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-heading"></div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">9. worm</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"8\">worm</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…he observed it was infested with something that looked like a worm… Brunel realised that the worm’s digging technique could be adapted to produce a new way of tunnelling.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong data-path-to-node=\"21,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Marc Brunel đã lấy cảm hứng từ cách một loài sâu đục gỗ tạo ra đường hầm trong gỗ để phát minh ra thiết bị đào hầm chuyên dụng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">10. clay</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"8\">clay</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…decided to dig the tunnel close to the muddy river bottom, where he could expect to find clay. This would be a more solid and safe substance to dig through…”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Brunel chọn đào ở tầng đất sét vì đây là vật liệu vững chắc và an toàn hơn so với lớp cát ở sâu bên dưới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">11. headaches</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"8\">headaches</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “They also complained of frequent headaches and dizziness, caused by the poor air quality.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong data-path-to-node=\"25,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Do thiếu hệ thống thông gió, không khí ô nhiễm trong hầm đã khiến công nhân gặp các vấn đề sức khỏe như đau đầu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">12. accidents</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"8\">accidents</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Lamps give off only a very weak glow, and there were a number of accidents because the miners could not see what they were doing.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong data-path-to-node=\"27,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Ánh sáng yếu từ nến và đèn dầu khiến thợ mỏ không nhìn rõ, dẫn đến nhiều tai nạn xảy ra trong quá trình làm việc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">13. government</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"8\">government</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and the government loan he had required to complete the project had to be paid back with interest.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong data-path-to-node=\"29,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Brunel đã phải vay tiền từ chính phủ để hoàn thành dự án, và khoản nợ kèm lãi suất này là gánh nặng tài chính lớn sau khi hầm hoàn tất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\">\n"}]', 1);
INSERT INTO public.questions VALUES ('c622ea1a-616f-464e-9a88-88c6d209de2d', 'b29e4311-1d3f-4a19-a395-a97c9f902f1c', 'checkbox', 'Questions 18–19', NULL, '<p>The list below gives some effects that jellyfish have had on the world.</p>
<p>Which <strong>TWO</strong> of these effects are mentioned by the writer of the text?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. They have damaged the tourism industry in some areas.", "correct": false}, {"option": "B. They have led to a reduction in the oceans'' oxygen levels.", "correct": false}, {"option": "C. They have contributed to the decline in the Black Sea anchovy population.", "correct": true}, {"option": "D. They have caused the shrimp business in the Gulf of Mexico to shut down.", "correct": false}, {"option": "E. They have created financial hardship in the fishing industry.", "correct": true}]', 'null', 'null', '[{"content": "<p><strong>18–19. Which TWO of these effects are mentioned by the writer of the text?</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong>Đáp án: C (They have contributed to the decline in the Black Sea anchovy population.) và E (They have created financial hardship in the fishing industry.)</strong></li>\n<li><strong>Dẫn chứng cho C:</strong> (Đoạn B) “…a huge number of jellyfish… <strong>devastated the Black Sea</strong>, an ecosystem already weakened by <strong>overfishing of anchovies</strong>.” (Sứa ăn trứng cá cơm).</li>\n<li><strong>Dẫn chứng cho E:</strong> (Đoạn F) “One result of large jellyfish populations is the <strong>economic effect it has had on the fishing industry</strong>. In the Gulf of Mexico, shrimp fishermen are struggling with a jellyfish boom that fills nets, causing them to break and resulting in <strong>millions of dollars in losses</strong>.” (Thiệt hại kinh tế/tài chính).</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2dc1b86c-dd19-49d4-8ddf-6ac82fc9db86', '792bccfb-b70b-41b5-9fe5-dadbbe64ec7b', 'fillup', ' Questions 1–4', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the note below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> for each answer.</p>
<p class="ql-align-center" style="text-align: center;"><strong>HOMECARE CLEANING AGENCY</strong></p>
<p class="ql-align-center" style="text-align: center;"><strong>House Details</strong></p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-color: #000000;" border="1">
<tbody>
<tr data-row="row-tr7e">
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-tr7e">
<p class="qlbt-cell-line" data-row="row-tr7e" data-cell="cell-wcp9" data-rowspan="1" data-colspan="1"><strong>Customer referred by:</strong></p>
</td>
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-tr7e">
<p class="qlbt-cell-line" data-row="row-tr7e" data-cell="cell-mavg" data-rowspan="1" data-colspan="1">friend</p>
</td>
</tr>
<tr data-row="row-b56s">
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-b56s">
<p class="qlbt-cell-line" data-row="row-b56s" data-cell="cell-wwm4" data-rowspan="1" data-colspan="1"><strong>Location:</strong></p>
</td>
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-b56s">
<p class="qlbt-cell-line" data-row="row-b56s" data-cell="cell-ob8f" data-rowspan="1" data-colspan="1">in the {Southwest}</p>
</td>
</tr>
<tr data-row="row-7n3b">
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-7n3b">
<p class="qlbt-cell-line" data-row="row-7n3b" data-cell="cell-sjb7" data-rowspan="1" data-colspan="1"><strong>Type of cleaning:</strong></p>
</td>
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-7n3b">
<p class="qlbt-cell-line" data-row="row-7n3b" data-cell="cell-nksq" data-rowspan="1" data-colspan="1">regular</p>
</td>
</tr>
<tr data-row="row-y50o">
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-y50o">
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-7fxw" data-rowspan="1" data-colspan="1"><strong>Rooms:</strong></p>
</td>
<td style="border-color: #000000;" colspan="1" rowspan="1" data-row="row-y50o">
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">– two {double} bedrooms</p>
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">(third bedroom used as {an office})</p>
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">– kitchen/diner</p>
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">{lounge}</p>
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">– family room</p>
<p class="qlbt-cell-line" data-row="row-y50o" data-cell="cell-upaa" data-rowspan="1" data-colspan="1">– two bathrooms</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h3 data-path-to-node=\"2\">PART 1</h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Representative:</strong> Good Morning Home Care Cleaning Agency.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Customer:</strong> Oh hello, I’d like to arrange to have some cleaning done please.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Representative:</strong> Certainly, have you used our services before?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Customer:</strong> No I haven’t, but a friend of mine has often used your company and suggested I phone you.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Representative:</strong> Oh, that’s great. I’ll just take some details from you and then you can let me know exactly what you would like done okay. First of all what area are you in?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Customer:</strong> I’m in the<span style=\"background-color: #ffe786;\"> <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"8\" data-index-in-node=\"21\">(1) Southwest</strong>.</span></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Representative:</strong> Okay, and are you interested in having a regular cleaner or is this a one off clean?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Customer:</strong> No, I’d like to arrange to have someone come in once a week.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Representative:</strong> Right now, let’s just get a bit of information about the house. How many bedrooms does it have?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Customer:</strong> 3.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Representative:</strong> Are they all double bedrooms?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Customer:</strong> Well one of the bedrooms is quite small, so it’s probably really <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"14\" data-index-in-node=\"75\">(2) two double</strong></span></span> rooms.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Representative:</strong> Right.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Customer:</strong> We have the small bedroom set up as <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"16\" data-index-in-node=\"46\">(3) an office</strong>.</span></p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Representative:</strong> Okay and just a standard kitchen lounge, dining room and bathroom?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Customer:</strong> Well actually we don’t have a separate dining room, it’s a kitchen diner. Then there’s the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"18\" data-index-in-node=\"101\">(4) lounge</strong></span> and as well as that we have a family room, oh and two bathrooms.</p>\n<hr data-path-to-node=\"19\" />\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Representative:</strong> Right that’s all I need to know about the house itself. Now what we do is we offer a basic cleaning service and then you let us know about anything extra you’d like cleaned.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Customer:</strong> Right and uh, what does the basic service include?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Representative:</strong> We clean all the floors and surfaces and do a basic clean in the kitchen and bathroom.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Customer:</strong> Okay that sounds good. And do you clean windows?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Representative:</strong> Well I’m afraid we don’t do that due to health and safety regulations, but we do offer other special services. We can put clean sheets on the beds for example.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Customer:</strong> Uh huh.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Representative:</strong> Or we can clean out your fridge, a lot of people like that done.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Customer:</strong> Yeah I’m not so worried about that, but <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"27\" data-index-in-node=\"50\">(5) I would like the sheets changed</strong>.</span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Representative:</strong> That’s no problem we can do that. <strong><span style=\"background-color: #ffe786;\">(6) </span><span style=\"text-decoration: underline; background-color: #ffe786;\">W</span><span style=\"text-decoration: underline; background-color: #ffe786;\">hat about the carpet?</span></strong> As well as the standard vacuum we can shampoo it if you want.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Customer:</strong> Right, we’ve got young children so it gets pretty dirty. I haven’t had it done for 6 months.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Representative:</strong> It really needs doing more often than that. You can have it done every month if you like, but 3 months is what we usually recommend.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Customer:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"31\" data-index-in-node=\"10\">(6) That sounds good</strong></span> (the carpet).</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Representative:</strong> The only other thing is the washing, do you do laundry work?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Customer:</strong> Yes we do, that’s no problem. What exactly would you like done?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Customer:</strong> Well, it’s no problem to put a load of washing in the machine, I can do that, but<strong> <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">(7) I would like to have the ironing done.</span></span></strong></p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Representative:</strong> That’s fine and would you like the washing put away in drawers or wardrobes?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Customer:</strong> No it’s OK, you can just leave everything out and fold it up.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Representative:</strong> OK right now, I’ll just set up an account for you and I’ll take down some of your details. Uh first of all, what’s your full name?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Customer:</strong> It’s Rose Kelly.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Representative:</strong> And could I have your home address please Mrs Kelly?</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Customer:</strong> Yes it’s 48 <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"40\" data-index-in-node=\"22\">(8) AMYES</strong></span> Road. That’s A-M-Y-E-S.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Representative:</strong> And that’s in Mount Eden. OK, now what day of the week would you like the property cleaned?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Customer:</strong> It doesn’t really matter, not Monday but any other day.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Representative:</strong> OK let’s see, we have a cleaner in your area later on <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"43\" data-index-in-node=\"70\">(9) Thursday</strong></span>, so shall we go for that day? We could have someone there by about 9:30 in the morning, does that suit you?</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Customer:</strong> Yes that’s fine.</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Representative:</strong> And do you charge an hourly rate or a total for the whole job?</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Customer:</strong> No we charge by the hour. It will work out to about $25 per hour.</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Representative:</strong> Oh that’s quite reasonable, I thought it might be closer to $30. And how long do you expect it to take?</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Customer:</strong> Well you said the house isn’t large, so I’d guess<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"48\" data-index-in-node=\"60\">(10) no more than three hours</strong></span></span> at the most.</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Representative:</strong> We can occasionally finish a three bedroom in two and a half, but that’s probably not too realistic.</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Customer:</strong> Right that sounds good.</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Representative:</strong> OK that’s lovely, thank you very much and we’ll have someone there next week.</p>\n<p data-path-to-node=\"52\"><strong data-path-to-node=\"52\" data-index-in-node=\"0\">Customer:</strong> Thank you.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('f3721166-3b90-4327-8353-194e463cfada', '792bccfb-b70b-41b5-9fe5-dadbbe64ec7b', 'radio', 'Questions 5–7', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "changing the bed linen"}, {"content": "washing the windows"}, {"content": "cleaning the fridge"}], "question": "Which extra service does the agency agree to provide?"}, {"correct": 1, "options": [{"content": "the children’s room"}, {"content": "the carpet"}, {"content": "the bathroom"}], "question": "What will be cleaned more thoroughly every three months?"}, {"correct": 1, "options": [{"content": "do the washing."}, {"content": "iron the clothes."}, {"content": "put the clothes away."}], "question": "The woman would like the cleaners to"}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('8c39e06a-e996-4041-abb8-e6d97aae8f28', '763a1875-90de-4f59-9cc9-70ac74e91247', 'matching', 'Questions 14-20', NULL, '<p>Reading Passage 2 has seven paragraphs.<br>Choose the correct heading for each paragraph from the list of headings below.<br>Choose the correct number, i-ix, in boxes 14-20.</p>', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The theory linking capacity for tool use in birds and survival"}, {"optionText": "ii The influence of humans on tool use"}, {"optionText": "iii The theory linking cognitive ability and living in a society"}, {"optionText": "iv Reviewing long-held beliefs"}, {"optionText": "v Intelligence helps birds to remember"}, {"optionText": "vi How some birds trick each other"}, {"optionText": "vii Physiological evidence of birds’ intelligence"}, {"optionText": "viii Several examples of birds who use tools"}, {"optionText": "ix One species’ multiple tool-using techniques"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph 1 — {iv. Reviewing long-held beliefs}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">\"For centuries, many scholars maintained that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"57\">humans were the only intelligent organism</strong>... However, exciting new research... has <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"140\">called into question</strong> using uniqueness of these traits, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"195\">forcing us to reconsider this opinion</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Long-held beliefs\" chính là quan niệm cho rằng chỉ con người mới có trí thông minh. Việc nghiên cứu mới \"gọi tên\" và \"buộc chúng ta xem xét lại\" (reconsider) chính là hành động \"Reviewing\" (xem xét/đánh giá lại).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph 2 — {viii. Several examples of birds who use tools}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">\"At least <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">three Australian bird species</strong> make tools... <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"65\">white-winged choughs</strong>... use rocks as hammers... <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"113\">black kites</strong> have been reported dropping bait...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này liệt kê một loạt các ví dụ cụ thể về nhiều loài chim khác nhau (chim ở Úc, chough, diều hâu đen) sử dụng các loại công cụ khác nhau (đá, mồi nhử, cành củi đang cháy).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph 3 — {i. The theory linking capacity for tool use in birds and survival}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">\"...food... provide a clue as to how the mental abilities needed for tool use evolved... animals should have evolved only the necessary intellectual capabilities <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"173\">required to overcome the challenges</strong> they face... only the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"231\">smartest in each generation will live and reproduce</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích mối liên hệ giữa trí thông minh và sự sinh tồn (survival). Những loài sống trong môi trường thách thức cần thông minh để tìm thức ăn, từ đó mới có thể sống sót và duy trì nòi giống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph 4 — {ix. One species’ multiple tool-using techniques}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">\"<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"12\">New Caledonian crows</strong> boast <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">many different tools</strong> in their tool kit. They use a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"90\">hooked tool</strong>... fashion <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"113\">serrated rakes</strong>... also make <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"141\">probes</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái với đoạn 2 nói về nhiều loài, đoạn 4 chỉ tập trung vào <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"72\">duy nhất một loài</strong> (New Caledonian crows) nhưng loài này lại có <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"135\">nhiều kỹ thuật</strong> sử dụng công cụ khác nhau (móc, cào, que dò).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph 5 — {vii. Physiological evidence of birds’ intelligence}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">\"...compared the frequency and size of innovations with the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"71\">size of the birds’ forebrain</strong>... relative to the hindbrain. The team uncovered a clear relationship: birds with <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"182\">relatively large forebrains</strong> are able to invent fresh solutions...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Physiological evidence\" (bằng chứng sinh lý) ở đây chính là cấu trúc và kích thước của não bộ (forebrain). Nghiên cứu chứng minh kích thước não có liên quan trực tiếp đến khả năng sáng tạo của chim.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph 6 — {iii. The theory linking cognitive ability and living in a society}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">\"Intelligence in birds may also arise as a result of selection to overcome the dynamic <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"98\">challenges of communal living</strong>. Since this involves competition between <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"169\">group members</strong>... the evolution of a distinctly <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"216\">‘political’ brain</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Living in a society\" tương ứng với \"communal living\" hoặc \"group members\". Đoạn này giải thích trí thông minh tiến hóa để chim có thể tương tác và cạnh tranh trong đời sống bầy đàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. Paragraph 7 — {vi. How some birds trick each other}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">\"What better way to exercise a political brain than to be <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"69\">deceitful</strong>! ...young choughs often <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"103\">act deceptively</strong>... place some food in the mouth of a hungry chick – but it <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"178\">does not release the food</strong>... frantically start to preen the chicks as soon as some of its group members <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"282\">come into view</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Trick each other\" (lừa dối nhau) chính là hành vi \"deceitful / deceptively\". Đoạn này mô tả cách chim chough giả vờ cho ăn hoặc giả vờ chăm sóc chim non để lấy lòng \"xã hội\" khi có kẻ khác đang quan sát.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('09410ee0-4e6f-4dd6-91ed-7bfa90897c32', 'fa9f37de-0f2b-445c-b341-16c9ba71722b', 'matching', 'Questions 36–40', '', '<p data-start="2288" data-end="2351">Complete each sentence with the correct ending, <strong data-start="2336" data-end="2343">A–H</strong>, below.</p>
<p data-start="2353" data-end="2428">Write the correct letter, <strong data-start="2379" data-end="2386">A–H</strong></p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "A an inability to hear when spoken language rises and falls"}, {"optionText": "B considered to be desirable"}, {"optionText": "C an inability to follow the beat of music"}, {"optionText": "D not a problem"}, {"optionText": "E not yet well understood"}, {"optionText": "F a result of injury to the mother"}, {"optionText": "G more marked than with other people"}, {"optionText": "H associated with intelligence"}], "matchingItems": [{"questionPart": "The reason why some people are born with amusia is", "correctAnswer": "E"}, {"questionPart": "One of the difficulties amusics experience is", "correctAnswer": "C"}, {"questionPart": "For amusics, discrimination of meaning in speech is", "correctAnswer": "D"}, {"questionPart": "Certain reactions in the brain of an amusic are", "correctAnswer": "G"}, {"questionPart": "In most cultures, musical ability is", "correctAnswer": "B"}]}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">36. E — The reason why some people are born with amusia is not yet well understood.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"4,0,0\" data-index-in-node=\"26\">“...but recently research has been undertaken in an attempt to discover the cause of congenital amusia (when people are born with the condition)...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói về lý do tại sao một số người sinh ra đã mắc hội chứng amusia (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"87\">born with amusia / congenital amusia</em>). Bài đọc viết rằng gần đây các nghiên cứu mới được thực hiện trong nỗ lực nhằm phát hiện ra nguyên nhân (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"230\">in an attempt to discover the cause</em>). Điều này đồng nghĩa với việc nguyên nhân cốt lõi của nó hiện vẫn chưa được hiểu rõ (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"352\">not yet well understood</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. C — One of the difficulties amusics experience is an inability to follow the beat of music.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“As would be expected, amusics perform significantly worse at singing and tapping a rhythm along with a melody than do non-amusics.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những khó khăn mà người mù nhạc gặp phải (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"64\">difficulties amusics experience</em>) là họ thể hiện tệ hơn rất nhiều trong việc vỗ tay theo nhịp điệu của một giai điệu (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"181\">tapping a rhythm along with a melody</em>). Ý này tương đương với việc không thể theo kịp nhịp điệu, nhịp đập của âm nhạc (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"299\">an inability to follow the beat of music</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">38. D — For amusics, discrimination of meaning in speech is not a problem.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"10,0,0\" data-index-in-node=\"26\">“Amusics who speak tonal languages, such as Chinese, do not report having any difficulty discriminating between words that differ only in their intonation.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với người mù nhạc, việc phân biệt ý nghĩa trong lời nói (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"73\">discrimination of meaning in speech</em>) đối với các ngôn ngữ có thanh điệu là không gặp bất kỳ khó khăn nào (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"179\">do not report having any difficulty</em>). Do đó, điều này hoàn toàn không phải là một trở ngại hay vấn đề đối với họ (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"293\">not a problem</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">39. G — Certain reactions in the brain of an amusic are more marked than with other people.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“When changes in tones are large, their brains overreact, showing twice as much activity on the right side of the brain as a normal brain hearing the same thing.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số phản ứng trong não của người mù nhạc khi nghe các tông nhạc lớn là hiện tượng não bộ phản ứng thái quá (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"123\">overreact</em>), hoạt động mạnh gấp đôi so với não người bình thường nghe cùng một thứ. Phản ứng này biểu hiện rõ rệt, mạnh mẽ hơn nhiều so với người bình thường (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"281\">more marked than with other people</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">40. B — In most cultures, musical ability is considered to be desirable.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“Musical ability is culturally valued, and may have been a factor in survival at one point in human history...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong hầu hết các nền văn hóa, năng lực âm nhạc luôn được tôn trọng và đánh giá cao (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"97\">culturally valued</em>). Vì thế, năng lực này được xem là một đặc điểm tốt, đáng ao ước và đáng hoan nghênh (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"201\">considered to be desirable</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('19acc71f-123a-43fc-8611-e84cbcf0c985', 'b29e4311-1d3f-4a19-a395-a97c9f902f1c', 'checkbox', 'Questions 20–21', NULL, '<p>Which <strong>TWO</strong> of the following are possible causes of an increase in jellyfish numbers?</p>
', 'multiple-select', 'null', '[{"option": "A. a shortage of small fish in the oceans", "correct": true}, {"option": "B. the dumping of chemicals into the oceans", "correct": true}, {"option": "C. a decline in biodiversity in the oceans", "correct": false}, {"option": "D. more competition among other fish in the oceans", "correct": false}, {"option": "E. a decrease in seabird populations", "correct": false}]', 'null', 'null', '[{"content": "<p><strong>20–21. Which TWO of the following are possible causes of an increase in jellyfish numbers?</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong>Đáp án: A (a shortage of small fish in the oceans) và B (the dumping of chemicals into the oceans)</strong></li>\n<li><strong>Dẫn chứng cho A:</strong> (Đoạn D) “<strong>Overfishing has removed fish</strong> from marine ecosystems… small fish appear to keep jellyfish in check by predation (on jellyfish when they are very small) and competition (when feeding). So, <strong>once we remove fish, jellyfish can proliferate</strong>.” (Thiếu cá nhỏ do đánh bắt quá mức).</li>\n<li><strong>Dẫn chứng cho B:</strong> (Đoạn D) “<strong>Eutrophication</strong> is another human-caused change… largely caused by <strong>fertilizer and waste run-off</strong>.” (Phân bón và nước thải chứa hóa chất nitrogen và phosphorus).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('babe6288-26c2-411c-ad6c-4f3d620ba6b6', 'b29e4311-1d3f-4a19-a395-a97c9f902f1c', 'fillup', 'Questions 22–26', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Some fish in the oceans may be unable to sustain population as the jellyfish eat their {eggs}  .</p>
<p>The state of jellyfish becoming the main ocean species has been named {monoculture}   .</p>
<p>Increasing numbers of jellyfish can damage {nets} used for commercial fishing.</p>
<p>Understanding basic facts about jellyfish, such as the {temperature} of the ocean which suits them best, may help control their numbers.</p>
<p>Richardson believes it is better to direct attention to {prevention} , instead of just trying to solve existing problems.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>22. Some fish in the oceans may be unable to sustain population as the jellyfish eat their eggs .</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>eggs</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “…Atlantic Ocean natives… devastated the Black Sea… feeding on anchovy <strong>eggs</strong> and the plankton that young fish rely on.” (Sứa ăn trứng cá cơm).</li>\n</ul>\n<p><strong>23. The state of jellyfish becoming the main ocean species has been named monoculture.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong>Đáp án:</strong> <strong>monoculture</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “This state has been defined as a <strong>‘monoculture of jellyfish’</strong>…”</li>\n</ul>\n<p><strong>24. Increasing numbers of jellyfish can damage nets used for commercial fishing.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong>Đáp án:</strong> <strong>nets</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…shrimp fishermen are struggling with a jellyfish boom that fills <strong>nets</strong>, causing them to break…”</li>\n</ul>\n<p><strong>25. Understanding basic facts about jellyfish, such as the temperature of the ocean which suits them best, may help control their numbers.</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong>Đáp án:</strong> <strong>temperature</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Experts say that a greater understanding of jellyfish, including their ideal water <strong>temperature</strong> and feeding habits, is necessary…”</li>\n</ul>\n<p><strong>26. Richardson believes it is better to direct attention to prevention, instead of just trying to solve existing problems.</strong></p>\n<ul data-path-to-node=\"26\">\n<li><strong>Đáp án:</strong> <strong>prevention</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Due to the difficulty of turning ecosystems around… Richardson and his colleagues propose focusing on <strong>‘prevention’</strong> rather than cure.”</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('4a16e841-3f63-45b6-b862-d884fa5d37b4', 'b34d2f6a-22fc-4d43-b0cf-80732d40dd60', 'matching', 'Questions 14-20', NULL, '<p>Reading passage has seven paragraphs,<strong> A–G</strong></p>
<p>Choose the correct heading for each paragraph from the list of heading below.</p>
<p>Write the correct number, i-viii, in boxes 14-20 on your answer sheet.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i How CSR may help one business to expand"}, {"optionText": "ii CSR in many aspects of a company’s business"}, {"optionText": "iii A CSR initiative without a financial gain"}, {"optionText": "iv Lack of action by the state of social issues"}, {"optionText": "v Drives or pressures motivate companies to address CSR"}, {"optionText": "vi The past illustrates business are responsible for future outcomes"}, {"optionText": "vii Companies applying CSR should be selective"}, {"optionText": "viii Reasons that business and society benefit each other"}], "matchingItems": null}', 'null', '[{"content": "<h4 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Đoạn A: {v Drives or pressures motivate companies to address CSR}</strong></h4>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Nowadays, <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"22\">governments and companies need to account for</strong> the social consequences of their actions&#8230; CSR has become a <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"129\">priority for business leaders</strong>&#8230; every company needs <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"182\">tacit or explicit permission</strong> from governments&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này thảo luận về các động lực (drives) như nghĩa vụ đạo đức, sự bền vững và áp lực (pressures) từ chính phủ/cộng đồng (giấy phép hoạt động) khiến các nhà lãnh đạo phải ưu tiên CSR.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Đoạn B: {viii Reasons that business and society benefit each other}</strong></h4>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;<strong data-path-to-node=\"6,0,0\" data-index-in-node=\"12\">Successful corporations need a healthy society</strong>&#8230; At the same time, <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"80\">a healthy society needs successful companies</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê hàng loạt lý do: Xã hội khỏe mạnh cung cấp lao động năng suất và khách hàng; ngược lại, doanh nghiệp tạo ra việc làm, sự giàu có và đổi mới. Đây là mối quan hệ tương hỗ (benefit each other).</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Đoạn C: {vi The past illustrates business are responsible for future outcomes}</strong></h4>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"12\">Asbestos</strong>, now understood as a serious health risk was thought to be safe in the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"92\">early 1900s</strong>&#8230; firms that failed to anticipated the consequences&#8230; have been <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"170\">bankrupted</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về Amiăng (asbestos) trong quá khứ cho thấy nếu doanh nghiệp không dự đoán được tác động xã hội trong tương lai, họ sẽ phải trả giá đắt (phá sản).</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Đoạn D: {vii Companies applying CSR should be selective}</strong></h4>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;No business can solve all of society’s problems&#8230; Instead, each company <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"85\">must select issues that intersect with its particular business</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định doanh nghiệp không nên làm CSR tràn lan mà phải có tính <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"87\">chọn lọc (selective)</strong>, tập trung vào những vấn đề liên quan trực tiếp đến ngành nghề của mình.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Đoạn E: {iii A CSR initiative without a financial gain}</strong></h4>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;No matter how beneficial the program is, it remains <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"64\">incidental to the company’s business</strong>, and the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"110\">direct effect on GE’s recruiting and retention is modest</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về General Electronics (GE) hỗ trợ trường học. Dù chương trình rất tốt về mặt xã hội, nhưng nó không liên quan trực tiếp đến hoạt động kinh doanh cốt lõi của GE và mang lại lợi ích tài chính/nhân sự rất ít (incidental/modest).</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Đoạn F: {i How CSR may help one business to expand}</strong></h4>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;The <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"16\">shortage of information technology workers</strong> is a significant <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"76\">constraint on Microsoft’s growth</strong>&#8230; Microsoft’s $50 million initiative was aimed at&#8230; having a <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"172\">direct-and potentially significant-impact on the company</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Microsoft đầu tư vào các trường cao đẳng cộng đồng để đào tạo nhân lực IT. Việc này giúp giải quyết sự thiếu hụt nhân lực, từ đó giúp công ty mở rộng (expand) và tăng trưởng.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Đoạn G: {ii CSR in many aspects of a company’s business}</strong></h4>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;In short, <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"22\">nearly every aspect of the company’s value chain</strong> reinforces the social dimensions&#8230; sourcing&#8230; stores construction&#8230; renewable wind energy&#8230; biofuels&#8230; cleaning products&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về Whole Foods Market cho thấy CSR thấm đẫm trong <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"68\">mọi khía cạnh</strong> (many aspects) của doanh nghiệp, từ thu mua, xây dựng cửa hàng, năng lượng đến vệ sinh.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('bb4640d8-0feb-4a8e-977f-4b3be6dd4232', '24e8f2c9-9c65-44aa-a0af-c63187b048aa', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
<div class="txt">
<p><em>Write </em><strong><em>ONE WORD AND/OR A NUMBER</em></strong><em> for each answer.</em></p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>Getting a job with an airline</strong></p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-style: solid;" border="1">
<colgroup>
<col width="143" />
<col width="494" />
<col width="100" /></colgroup>
<tbody>
<tr data-row="row-56bo">
<td colspan="1" rowspan="1" data-row="row-56bo">
<p class="qlbt-cell-line" data-row="row-56bo" data-cell="cell-ed0c" data-rowspan="1" data-colspan="1"><em>Example</em></p>
<p class="qlbt-cell-line" data-row="row-56bo" data-cell="cell-ed0c" data-rowspan="1" data-colspan="1">Job:</p>
</td>
<td colspan="1" rowspan="1" data-row="row-56bo">
<p class="qlbt-cell-line" data-row="row-56bo" data-cell="cell-v1pc" data-rowspan="1" data-colspan="1"><em>Answer</em></p>
<p class="qlbt-cell-line" data-row="row-56bo" data-cell="cell-v1pc" data-rowspan="1" data-colspan="1">cabin crew <em>attendant</em></p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p><strong>Duties include</strong></p>
<p>– giving the safety demonstration</p>
<p>– some responsibility for {money} from sales during the flight</p>
<p>– serving food</p>
<p><strong>Requirements</strong></p>
<p>– must be over age 19 and at least {168} cm tall</p>
<p>– basic academic requirements: English and {maths | mathematics}</p>
<p>– at least one other {language} is desirable</p>
<p>– must be able to {swim}</p>
<p><strong>Training will include</strong></p>
<p>– what to do in case of {illness} during a flight</p>
<p>– awareness of different {cultures}</p>
<p><strong>Application</strong></p>
<p>– the airline is called {EURONTAS}</p>
<p>– can download application form from website</p>
<p>– mention experience of:</p>
<p>+ dealing with questions from supermarket customers</p>
<p>+ working in a {team} (voluntary work)</p>
<p><strong>Other information</strong></p>
<p>– you don’t have to buy a {uniform}</p>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h2 data-path-to-node=\"2\">SECTION 1</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Greg:</strong> hello</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Ellie:</strong> oh hello um this is Ellie Fisher we were at school together</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Greg:</strong> oh hi Ellie how are you what are you doing these days</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Ellie:</strong> well actually I’m looking for a job and I was wondering about applying to an airline you know looking after the passengers and I heard you’re doing something like that</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Greg:</strong> yeah I’m working as a cabin crew attendant</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Ellie:</strong> right so what does that involve</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Greg:</strong> well you might have to give them the initial safety demonstration before take off for example you’ve probably seen that when you’ve made a journey by air</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ellie:</strong> actually I’ve never flown but I’d love to that’s why I’d like a job with an airline</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Greg:</strong> oh right and during the flight you’d also be going round to see if anyone wants to buy anything so I’d be dealing with <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"125\">(1) money</strong></span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Ellie:</strong> that’s right you’d be responsible for that</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Greg:</strong> and then of course you’d be serving meals and snacks and things</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Ellie:</strong> okay so can anyone apply</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Greg:</strong> well there are certain requirements you must be at least 19 years old and there’s also a minimum height that’s <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"117\">(2) 168</strong></span> cm that’s to make sure you can reach the higher cupboards in the plane</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Ellie:</strong> right I’m 169 cm I think what about qualifications</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Greg:</strong> you need to show that you have a good level of English that’s written and spoken and also <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"96\">(3) maths</strong></span> OK</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Ellie:</strong> well I passed my exams in both those subjects fortunately</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Greg:</strong> and it’s an advantage if you can speak another <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"53\">(4) language</strong></span> although for cabin crew it’s not essential</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Ellie:</strong> I can speak Spanish I did that at school until I was 16</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Greg:</strong> excellent that’ll be very useful and I’m pretty fit I don’t have any medical problems OK oh and can you <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"110\">(5) swim</strong></span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Ellie:</strong> yes</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Greg:</strong> good because that’s another requirement</p>\n<hr data-path-to-node=\"24\" />\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Greg:</strong> now if you’re accepted you’ll get a six week training course right so that’ll cover all aspects of the job all the basic things you need to know and then some special things like what action to take if a passenger suddenly has some sort of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"246\">(6) illness</strong></span> while you’re in the air for example</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Ellie:</strong> right I suppose you can’t always count on a doctor being on board</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Greg:</strong> no and then you’ll have to do a lot of work during the training on becoming aware of the variety of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"27\" data-index-in-node=\"106\">(7) cultures</strong></span> that your passengers may come from and the implications of that</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Ellie:</strong> that’s really interesting actually OK well I definitely like to apply um what airline do you actually work for</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Greg:</strong> it’s a small airline called <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"34\">(8) Eurontas</strong></span> that’s e u r o n t a s is that N or m in the middle N for November okay they’re good people to work for have a look at their website you can download the application form from there</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Ellie:</strong> right I don’t have much in the way of experience though</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Greg:</strong> well what have you done since leaving school</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Ellie:</strong> I worked in a supermarket for a bit on the information desk I was helping deal with queries from customers</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Greg:</strong> okay put that down that’s one of the most important aspects of the job in fact</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Ellie:</strong> oh right and last year I also did some voluntary work as part of a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"74\">(9) team</strong></span> should I put that down too</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Greg:</strong> of course that’s something else they’ll be looking for being able to work with others</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Ellie:</strong> right</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Greg:</strong> and a lot of airlines expect you to pay for your own <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"37\" data-index-in-node=\"59\">(10) uniform</strong></span> but the good thing about this airline is that they provide it for you</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Ellie:</strong> great well thanks so much Greg I really…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('afe8f2da-b0df-47d2-8462-463c8cc98983', 'fd10158d-9220-4a87-be0a-e46253c9962b', 'fillup', 'Questions 34–39', '<p>Complete the sentences below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 34–39</p>
<p>South African heathland plants are covered with a substance that appeals to {animals}</p>
<p>The seeds of South African heathland plants are carried into {nests} in the earth.</p>
<p>Animals don’t like to eat {fruit} that is unripe because of the taste.</p>
<p>The quetzal ejects the {stone} of the wild avocado through its mouth.</p>
<p>Pine seeds are contained in their {cones} until they are mature.</p>
<p>The pine tree benefits because the nut-cracker bird has a bad {memory}</p>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p>34. (Đoạn 10: “Many plants that grow in the heathland of South Africa provide their seeds with an edible covering which animals find particularly attractive.”)<br />\n→ Lớp vỏ của hạt cây thu hút động vật ăn.<br />\n→ Đáp án: animals</p>\n<p>35. (Đoạn 10: “These collect the seeds and carry them down to their underground nests, where they eat the covering…”)<br />\n→ Hạt được mang xuống tổ dưới lòng đất.<br />\n→ Đáp án: nests</p>\n<p>36. (Đoạn 11: “While the plant is constructing the seeds, the flesh of the unripe fruit is sour, and animals learn not to eat it.”)<br />\n→ Trái cây chưa chín có vị chua, động vật không thích ăn.<br />\n→ Đáp án: fruit</p>\n<p>37. (Đoạn 11: “&#8230;feeds on the wild avocado, swallowing it whole. It eventually regurgitates the stone&#8230;”)<br />\n→ Chim quetzal nhả hạt (stone) của quả bơ ra ngoài miệng.<br />\n→ Đáp án: stone</p>\n<p>38. (Đoạn 13: “While the seeds of pine trees are developing, they’re protected inside cones.”)<br />\n→ Hạt của cây thông nằm trong nón thông (cones).<br />\n→ Đáp án: cones</p>\n<p>39. (Đoạn 13: “But two out of every three seeds that the bird buries, it never finds again&#8230; relying on the poor memory of the courier&#8230;”)<br />\n→ Cây thông lợi dụng trí nhớ kém của chim để phát tán hạt.<br />\n→ Đáp án: memory</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('feed89bc-cb4f-41b6-abc0-dda6766e7990', 'fd10158d-9220-4a87-be0a-e46253c9962b', 'radio', 'Question 40', NULL, '<p>Choose the correct letter, A, B, C or D.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. The movement of plants provides benefits for animals and other creatures."}, {"content": "B. Plants can move much faster than is generally realised."}, {"content": "C. The methods by which plants move are adapted to their surroundings."}, {"content": "D. Animals play a significant role in the movement of plants."}], "question": "Which of the following best summarises Reading Passage 3?"}]', 'null', 'null', 'null', '[{"content": "<p>40. (Toàn bài: mô tả các cách khác nhau mà thực vật di chuyển hoặc phát tán hạt – bằng gió, nước, động vật, hay tự nổ tung – tùy theo môi trường sống.)<br />\n→ Bài viết nhấn mạnh rằng các phương thức di chuyển của cây phù hợp với điều kiện xung quanh.<br />\n→ Đáp án: C – The methods by which plants move are adapted to their surroundings.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('ccb8577e-3360-460f-9b1c-395fd22ff122', 'b994b6ce-d83c-47c9-8f16-d98446ed3878', 'radio', 'Questions 1–7', '', '<p>Choose <strong data-start="208" data-end="216">TRUE</strong>  if the statement agrees with the information,<strong data-start="266" data-end="275">FALSE</strong>  if the statement contradicts the information,<strong data-start="325" data-end="338">NOT GIVEN</strong>  if there is no information on this</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The city buses start operating later than the trams."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You can get a tram from the airport to the city centre up to midnight."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The 207 bus service stops at the main railway station."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The cost of a tram ticket varies depending on your journey."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Bicycles are allowed on the trams between 7.30 am and 10 am."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Additional trams run during the Gobridge festival period."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cyclists may be asked to leave the tram if they block the exit."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. The city buses start operating later than the trams. — {FALSE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Our first tram… leaves… at 6.30 am, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"52\">half an hour after the first city bus service</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xe điện chạy lúc 6:30 sáng, tức là chạy <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"52\">sau</strong> xe buýt 30 phút. Câu hỏi nói xe buýt chạy muộn hơn xe điện là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. You can get a tram from the airport to the city centre up to midnight. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…trams from the airport… <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"41\">end at 11.35 pm</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chuyến xe điện cuối cùng kết thúc lúc 11:35 đêm, không kéo dài đến tận nửa đêm (midnight).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. The 207 bus service stops at the main railway station. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the number 207 airport bus runs every hour through the night.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói xe buýt 207 chạy xuyên đêm từ sân bay, nhưng <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"73\">không hề đề cập</strong> nó có dừng ở ga tàu chính hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. The cost of a tram ticket varies depending on your journey. — {TRUE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Check your route and make sure you <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"47\">buy the correct price ticket</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc yêu cầu khách kiểm tra lộ trình để mua đúng giá vé cho thấy giá vé thay đổi tùy theo quãng đường đi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Bicycles are allowed on the trams between 7.30 am and 10 am. — {FALSE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Bicycles may only be taken… during off-peak… <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"61\">up to 7.30 am, between 10 am and 2.30 pm</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khung giờ từ 7:30 sáng đến 10:00 sáng là giờ cao điểm, xe đạp <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"74\">không được phép</strong> mang lên xe điện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Additional trams run during the Gobridge festival period. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…trams carry <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"27\">extra passengers</strong> at these times [Festivals].”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói xe điện chở <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"36\">nhiều khách hơn</strong> vào dịp lễ hội, nhưng <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"74\">không khẳng định</strong> là họ có tăng cường thêm số lượng xe điện hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. Cyclists may be asked to leave the tram if they block the exit. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…ensure they do not obstruct the entrance, exit…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nhắc nhở người đi xe đạp không được chắn lối thoát hiểm, nhưng <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"83\">không hề nói</strong> về việc họ sẽ bị yêu cầu rời khỏi xe nếu làm vậy.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('afd1f414-3d9f-4ca6-85dd-bec34f95fbeb', '8756a7ff-0501-40fa-96a3-66b7c2fd933e', 'checkbox', 'Questions 19 and 20', '', '<p data-path-to-node="8">Choose <strong data-path-to-node="8" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="8" data-index-in-node="20">A–E</strong>.</p>
<p data-path-to-node="9">Which <strong data-path-to-node="9" data-index-in-node="6">TWO</strong> pieces of advice does the speaker give to parents about reading?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A Encourage children to write down new vocabulary."}, {"correct": true, "option_text": "B Allow children to listen to audio books."}, {"correct": true, "option_text": "C Get recommendations from librarians."}, {"correct": false, "option_text": "D Give children a choice about what they read."}, {"correct": false, "option_text": "E Only read aloud to children until they can read independently."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('f473b45f-0b79-4b6e-9472-a61bc70a84c3', 'b994b6ce-d83c-47c9-8f16-d98446ed3878', 'matrix', 'Questions 8–14', '', '<p data-start="992" data-end="1062">Write the correct letter, <strong data-start="1018" data-end="1025">A–E</strong>, in boxes 8–14 on your answer sheet.</p>
<p data-start="1064" data-end="1109"><strong data-start="1064" data-end="1070">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The colour of the sweater did not match the website image.", "correctCategoryLetter": "B"}, {"itemText": "The customer took some time to decide on the purchase.", "correctCategoryLetter": "A"}, {"itemText": "The customer initially bought the wrong size.", "correctCategoryLetter": "C"}, {"itemText": "The customer changed her mind about returning a sweater.", "correctCategoryLetter": "E"}, {"itemText": "The customer bought a bigger size than she usually does.", "correctCategoryLetter": "A"}, {"itemText": "The sweater can be worn for smart or casual occasions.", "correctCategoryLetter": "E"}, {"itemText": "The customer was worried that the sweater wouldn’t suit her.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">8. The colour of the sweater did not match the website image. — {B: Davina}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…though I <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"24\">expected a lighter shade from the picture</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Màu sắc thực tế của chiếc áo len tím (purple) không giống như Davina hình dung qua ảnh trên web (cô ấy tưởng nó sẽ nhạt hơn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">9. The customer took some time to decide on the purchase. — {A: Mary-Anne}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “I <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"14\">spent a while thinking about buying</strong> this sweater because of the price…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mary-Anne đã phải cân nhắc, suy nghĩ một thời gian khá lâu mới quyết định mua vì giá của chiếc áo len này khiến cô ấy đắn đo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">10. The customer initially bought the wrong size. — {C: Naga}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “I opted for the medium, but it was <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"47\">too tight so I exchanged it</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Naga ban đầu chọn size M nhưng khi mặc thử thì bị chật, dẫn đến việc cô ấy phải thực hiện thủ tục đổi trả sang size khác (mua sai kích cỡ ban đầu).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">11. The customer changed her mind about returning a sweater. — {E: Laura}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…with <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">every intention of sending one of them back. That didn’t happen, of course!</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lúc đầu Laura mua hai chiếc với ý định sẽ trả lại một chiếc sau khi chọn lựa, nhưng cuối cùng cô ấy đã đổi ý và giữ lại cả hai vì quá ưng ý.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">12. The customer bought a bigger size than she usually does. — {A: Mary-Anne}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “I <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"14\">tend to take medium but went for large</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thói quen thông thường của Mary-Anne là mặc size M, nhưng lần này cô ấy đã chủ động chọn mua size L (size lớn hơn bình thường) để có chỗ mặc thêm áo thun bên trong.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">13. The sweater can be worn for smart or casual occasions. — {E: Laura}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…lovely to wear with <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"35\">jeans</strong> but also <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"50\">stylish enough to wear to work</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chiếc áo này có tính ứng dụng cao, vừa có thể mặc đi chơi thoải mái với quần jeans (casual), vừa đủ lịch sự và phong cách để mặc đi làm (smart/work wear).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">14. The customer was worried that the sweater wouldn’t suit her. — {C: Naga}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…although I <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">wasn’t sure it was going to look right on me</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi mặc thử, Naga đã có tâm lý lo lắng, không chắc chắn liệu kiểu dáng hoặc màu sắc của chiếc áo len sọc này có hợp với vóc dáng của mình hay không.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('2b85bfaa-3935-4622-a435-0f4d67239512', '434607f4-d01e-4b26-9fa0-17e0039b5e45', 'radio', 'Questions 33-37', '', '<p>Choose <strong data-path-to-node="3" data-index-in-node="0">YES</strong> if the statement agrees with the claims of the writer <strong data-path-to-node="3" data-index-in-node="58">NO</strong> if the statement contradicts the claims of the writer <strong data-path-to-node="3" data-index-in-node="115">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "2000 Weeks and its accompanying photo-roman were successful with the public."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Strizic’s portraits in Involvement were exhibited at the National Gallery of Victoria in 1968."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Strizic was one of the first to document the interactive artwork Sculptron."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Strizic’s photographic murals were produced with the help of advanced digital technology."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Strizic is best remembered solely as a nostalgic photographer of Melbourne."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">33. 2000 Weeks and its accompanying photo-roman were successful with the public. — {NO}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“…it <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"27\">failed at the box office</strong>, and Strizic’s book <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"72\">met a similar fate</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định bộ phim thất bại về doanh thu (failed at the box office) và cuốn sách của Strizic cũng chịu số phận tương tự. Điều này trái ngược hoàn toàn với việc nói chúng “thành công với công chúng” (successful with the public).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">34. Strizic’s portraits in Involvement were exhibited at the National Gallery of Victoria in 1968. — {YES}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“These images [the portraits] were exhibited in <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"68\">1968 at the National Gallery of Victoria</strong> under the title Some Australian Personalities…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận các bức chân dung này (nằm trong dự án Involvement) đã được triển lãm tại Phòng trưng bày Quốc gia Victoria vào năm 1968.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">35. Strizic was one of the first to document the interactive artwork Sculptron. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“He also worked with avant-garde artists such as Asher Bilu, producing the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"95\">only surviving photographic record</strong> of Bilu’s interactive electronic work <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"168\">Sculptron</strong> (1967).”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói Strizic là người tạo ra <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"48\">bản ghi chép hình ảnh duy nhất còn sót lại</strong> của tác phẩm Sculptron. Tuy nhiên, bài <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"130\">không đề cập</strong> liệu ông có phải là một trong những người “đầu tiên” (one of the first) thực hiện việc này hay không. Có thể có người khác chụp trước đó nhưng ảnh không còn tồn tại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">36. Strizic’s photographic murals were produced with the help of advanced digital technology. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“In the field of murals, he developed large-scale photographic works… sometimes combining his “photochromes” with paintings.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc ông tạo ra các bức tranh tường khổ lớn (murals) bằng các kỹ thuật thực nghiệm và kết hợp hội họa, nhưng <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"141\">không hề nhắc đến</strong> việc ông có sử dụng “công nghệ kỹ thuật số tiên tiến” (advanced digital technology) hay không. (Lưu ý: Thời điểm năm 1970 công nghệ kỹ thuật số chưa phát triển như hiện nay).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">37. Strizic is best remembered solely as a nostalgic photographer of Melbourne. — {NO}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“Since then, he has often been remembered as a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"67\">nostalgic chronicler</strong> of “old Melbourne”… Yet <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"114\">such a label oversimplifies his contribution</strong>. His career was marked by continuous <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"196\">experimentation</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho rằng việc chỉ coi ông là một nhiếp ảnh gia hoài niệm về Melbourne (nostalgic chronicler) là một sự “đơn giản hóa quá mức” (oversimplifies). Sự nghiệp của ông còn bao gồm cả sự thực nghiệm liên tục và các phong cách tiên phong (avant-garde). Vì vậy, dùng từ “solely” (duy nhất) là sai so với quan điểm của tác giả.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b08dc504-dacd-4987-a9e4-d5ae224a1251', '015e6956-c13d-4443-86a4-db82be9b4b60', 'matching', 'Questions 11–16', '', '<p>What tourist attraction does each of the following locations have?</p>
<p>Choose <strong>SIX </strong>answers from the box and write the corrct letter, A- I, next to Questions 11-16</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-path-to-node=\"1,0,0\"><span style=\"font-size: 12pt;\"><strong>Locations</strong></span></p>\n<p data-path-to-node=\"1,0,0\"> </p>\n<p data-path-to-node=\"1,0,0\">Sheepfold: {I hills}</p>\n<p data-path-to-node=\"1,1,0\"> </p>\n<p data-path-to-node=\"1,1,0\">Brown Mare {H wild flowers}</p>\n<p data-path-to-node=\"1,2,0\"> </p>\n<p data-path-to-node=\"1,2,0\">Doris {B nature reserve}</p>\n<p data-path-to-node=\"1,3,0\"> </p>\n<p data-path-to-node=\"1,3,0\">Lodge Estate {E newly born deer}</p>\n<p data-path-to-node=\"1,4,0\"> </p>\n<p data-path-to-node=\"1,4,0\">Aurden {D old ruins}</p>\n<p data-path-to-node=\"1,5,0\"> </p>\n<p data-path-to-node=\"1,5,0\">Eastlake: {F birds}</p>", "answerOptions": [{"optionText": "A farming life in the past"}, {"optionText": "B Nature reserve"}, {"optionText": "C canoes"}, {"optionText": "D old ruins"}, {"optionText": "E newly born deer"}, {"optionText": "F birds"}, {"optionText": "G waterfalls"}, {"optionText": "H wild flowers"}, {"optionText": "I hills "}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Sally:</strong> Good morning, everyone. I’m Sally, tour guide from Travel-lite Travel Agency. Today, I’m going to introduce a great trip to Southern Scotland for you. I’m sure you will find it a fantastic place. There is lots to see in Southern Scotland.</p>\n<p data-path-to-node=\"4\">To begin with, we will go to Sheepfold, which has one or two beautiful gardens. One thing that’s definitely worth doing is climbing to the top of the mountain. You’ll be fascinated by the beautiful scenery alongside the mountain road. When you get to the top, you can overlook the coastline and enjoy the stunning view. <strong data-path-to-node=\"4\" data-index-in-node=\"320\">{I hills}</strong></p>\n<p data-path-to-node=\"5\">From there, we will go on to Brown Mare. Brown Mare used to be famous for its farm, but it is being refurbished at the moment and isn’t likely to be reopened by the time we go there. But you can walk for hours there in the peaceful green surroundings along a wide variety of tracks. I think you’ll be struck by the beautiful roses and mother nature. <strong data-path-to-node=\"5\" data-index-in-node=\"350\">{H wild flowers}</strong></p>\n<p data-path-to-node=\"6\">In Doris, there were several old barns, but they have been converted into a special section where animals and plants are protected. From there, you can see a range of rare breeds, as well as flowers. This place is usually favored by university students as a destination for their field trips. <strong data-path-to-node=\"6\" data-index-in-node=\"293\">{B nature reserve}</strong></p>\n<p data-path-to-node=\"7\">Then, we will go to Lodge Estate, which is the most favorite location for children, as they can watch the baby deer. But remember, don’t give food to them. Photography is allowed there, and when you leave, you can get one free photo at the exit. But please don’t move rocks or branches to take photos. You should leave the site intact. <strong data-path-to-node=\"7\" data-index-in-node=\"336\">{E newly born deer}</strong></p>\n<p data-path-to-node=\"8\">Our next stop is Orton (Aurden). I strongly recommend that you visit the ancient town which was constructed nearly 1,000 years ago. There is not much of the original buildings left, but still plenty to see. The site is being excavated, and you’ll be able to help out if you want to. <strong data-path-to-node=\"8\" data-index-in-node=\"283\">{D old ruins}</strong></p>\n<p data-path-to-node=\"9\">Finally, we will spend some time in East Lake, which changes with the seasons, with different events happening at different times of the year. At the moment when we arrive there, it will be the most spectacular month with the arrival of Canada geese. I’m pretty sure that this visit will give you an unforgettable experience. <strong data-path-to-node=\"9\" data-index-in-node=\"326\">{F birds}</strong></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">ACCOMMODATION &amp; BENEFITS (Questions 17–20)</strong></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Sally:</strong> Some of you have asked me about the place where we’re going to stay. So next, I will introduce different types of accommodation there.</p>\n<p data-path-to-node=\"13\">First, many tourists may consider visiting a <strong data-path-to-node=\"13\" data-index-in-node=\"45\">bed and breakfast</strong>, also called a B&amp;B, as they don’t have to be worried about what to eat in the morning. But you have to pay attention that this type of accommodation is only available on a daily basis.</p>\n<p data-path-to-node=\"14\">The cheapest possible option is to stay in a <strong data-path-to-node=\"14\" data-index-in-node=\"45\">hostel</strong>, but you should be aware that sometimes you are provided with only a single bed with several people sharing the same room, and meals are not included. But some people think they have never had such an experience before that they want to have a try. More importantly, they don’t have to change accommodation for a whole week.</p>\n<p data-path-to-node=\"15\">For those who want to visit the castles, I recommend you stay in the <strong data-path-to-node=\"15\" data-index-in-node=\"69\">cottages</strong> nearby with beautiful surroundings. The owner promises that the rent can be paid every seven days, so just be relieved to have a peaceful life there.</p>\n<p data-path-to-node=\"16\">For our members, I will introduce some benefits you can get from our travel agency. As for the accommodation I just mentioned, someone has asked if we offer a <strong data-path-to-node=\"16\" data-index-in-node=\"159\">discount</strong>. I’m afraid to tell you this is only for premium members, who can benefit from 10% off the original price.</p>\n<p data-path-to-node=\"17\">For those self-driving travelers, you might be interested in the <strong data-path-to-node=\"17\" data-index-in-node=\"65\">parking space</strong>. This is always limited at the hotel, so we only offer free parking service to premium members as well, I’m afraid. Ordinary members have to pay a fee for parking.</p>\n<p data-path-to-node=\"18\">The good news is, all of you can enjoy your <strong data-path-to-node=\"18\" data-index-in-node=\"44\">guide service</strong> without any charge, including the visit to attractions like the castles. But remember, the entrance fee has to be paid by yourself.</p>\n<p data-path-to-node=\"19\">Oh, I nearly forgot! You can also receive regular copies of <strong data-path-to-node=\"19\" data-index-in-node=\"60\">magazines</strong> about the native food and attractions in Scotland, absolutely for free. It’s a gift for you. I hope you will like it. Okay, that’s all I want to share today. If you have any more questions about the trip, please call me.</p>"}]', 0);
INSERT INTO public.questions VALUES ('e71ad931-0c05-4652-9318-b5d921590cba', 'ec5eba5c-c820-4975-b4cd-340623a2ed46', 'fillup', 'Questions 8-13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 8-13 on your answer sheet.</p>
<p><strong>Challenges faced by RFDS dentists</strong></p>
<ul>
<li>need to bring equipment including {computers} for records aircraft used to carry equipment have restricted {space}</li>
<li>problems offering some services, e.g., fitting {dentures}</li>
<li>people in remote areas are more likely to have infection in their mouth</li>
</ul>
<p><strong>Products supplied by RFDS dentists</strong></p>
<p>If necessary, RFDS provides:</p>
<ul>
<li>{toothpaste} and {toothbrushes} for regular use</li>
<li>{mouthguards} to protect teeth of sports players</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">8. …need to bring equipment including {computers} for records.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…and <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"19\">computers</strong> for keeping track of patients’ treatments.” (Đoạn 5)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">9. …aircraft used to carry equipment have restricted {space}.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…since the small planes that transport dentists have <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"67\">limited space</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Restricted” đồng nghĩa với “limited”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">10. …problems offering some services, e.g., fitting {dentures}.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “For example, <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"25\">dentures</strong> (for artificial teeth) can be very difficult to provide…” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">11. If necessary, RFDS provides: {toothpaste} and…</strong> <strong data-path-to-node=\"25\" data-index-in-node=\"53\">12. …{toothbrushes} for regular use.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…basic dental hygiene items such as <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"50\">toothpaste</strong> and <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"65\">toothbrushes</strong>… If this is the case, the RFDS supplies these.” (Đoạn 8)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">13. {mouthguards} to protect teeth of sports players.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The RFDS also provides <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"35\">mouthguards</strong> for young sports players.” (Đoạn 9)</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('a37e4885-5a07-4a12-a16e-66b3cccccb8d', '38236f7c-e75a-4072-8dfa-a85f03bc2a18', 'matrix', 'Questions 27-32', '', '<p>Which paragraph contains the following information?<br>Write the correct letter, <strong>A</strong>-<strong>F</strong>, in boxes 27-32 on your answer sheet.</p>
<p><strong>NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": " an explanation of why watching sport may be emotionally satisfying", "correctCategoryLetter": "F"}, {"itemText": "an explanation of why beginners find sporting tasks difficult", "correctCategoryLetter": "B"}, {"itemText": "a factor that needs to combine with mirroring to attain sporting excellence", "correctCategoryLetter": "E"}, {"itemText": "a comparison of human and animal mirror neurons", "correctCategoryLetter": "C"}, {"itemText": "the first discovery of brain activity related to mirror neurons", "correctCategoryLetter": "D"}, {"itemText": "a claim linking observation to improvement in performance", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. an explanation of why watching sport may be emotionally satisfying — {F}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This feeling also derives from mirror neurons. …they also allow us to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"84\">share in its feelings</strong>. This is because they are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"132\">directly connected to the amygdala</strong>, one of the main brain regions involved in emotion.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F giải thích mối liên hệ giữa tế bào thần kinh gương và hạch hạnh nhân (amygdala), giúp người xem chia sẻ cảm xúc chiến thắng với vận động viên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. an explanation of why beginners find sporting tasks difficult — {B}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This is because most <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"33\">novices swing with their consciousness</strong>, using an area of brain next to the premotor cortex.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người mới bắt đầu (novices) gặp khó khăn vì họ dùng ý thức để điều khiển hành động, thay vì dùng các phản xạ đã được “lập trình” trong vỏ não tiền vận động như các chuyên gia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. a factor that needs to combine with mirroring to attain sporting excellence — {E}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The best athletes are those with a premotor cortex capable of imagining the movements… together with the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"119\">physical properties to make those movements real</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đạt đến đỉnh cao, khả năng mô phỏng trong não bộ (mirroring) phải kết hợp với các <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"97\">tố chất thể chất</strong> thực tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. a comparison of human and animal mirror neurons — {C}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"12\">Humans have an even more elaborate mirror neuron system</strong> [than monkeys].”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh hệ thống tế bào thần kinh gương của người và khỉ, nhấn mạnh rằng ở người nó phức tạp và tinh vi hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. the first discovery of brain activity related to mirror neurons — {D}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This phenomenon of neural mirror was <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"49\">first discovered in 1954</strong>, when two French physiologists… found that the brains of humans vibrate with two distinct wavelengths…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nhắc về mốc thời gian 1954 và phát hiện về sóng alpha/mu, tiền thân của các nghiên cứu về tế bào thần kinh gương sau này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. a claim linking observation to improvement in performance — {E}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It turns out that <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"30\">watching a great golfer makes us better golfers</strong>, and watching a great sprinter actually makes us run faster.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E khẳng định việc quan sát (watching/observation) giúp cải thiện kỹ năng thực tế của người xem.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2d113169-8631-4da7-a9ce-7c1b4177b9a6', '8850f39d-c4f0-4516-a2cd-0234e74bda36', 'fillup', 'Questions 15–21', '<p data-start="82" data-end="111">Complete the sentences below.</p>
<p data-start="113" data-end="168">Choose <strong data-start="120" data-end="137">ONE WORD ONLY</strong> from the text for each answer.</p>
<ul>
<li data-section-id="vt7ztp" data-start="227" data-end="307">
<p data-start="231" data-end="307">Initially, a leader needs to focus on gaining the {trust} of the staff.</p>
</li>
<li data-section-id="kzpfqu" data-start="308" data-end="388">
<p data-start="312" data-end="388">A leader should decide on {goals} that their staff are happy to fulfil.</p>
</li>
<li data-section-id="mf9iow" data-start="389" data-end="481">
<p data-start="393" data-end="481">Leaders should involve their staff in the process of producing a different {strategy} .</p>
</li>
<li data-section-id="bwh9q9" data-start="482" data-end="575">
<p data-start="486" data-end="575">If tricky issues arise, leaders should give staff the space to find {solutions} to them.</p>
</li>
<li data-section-id="c5ac15" data-start="576" data-end="679">
<p data-start="580" data-end="679">Leaders need to encourage their staff to feel {pride} in the past achievements of the company.</p>
</li>
<li data-section-id="10w0eug" data-start="680" data-end="772">
<p data-start="684" data-end="772">It is important for leaders to agree to a certain degree of {risk} when necessary.</p>
</li>
<li data-section-id="1x9cvx1" data-start="773" data-end="883">
<p data-start="777" data-end="883">If leaders find the {future} of the company exciting, their staff will be more motivated to work hard.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. Initially, a leader needs to focus on gaining the {trust} of the staff.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The first few weeks is when people develop their perceptions of you, so work hard to <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"97\">earn their trust</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Initially” (ban đầu) tương ứng với “The first few weeks”. Để lãnh đạo hiệu quả, bước đầu tiên là phải có được sự tin tưởng (trust) từ nhân viên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. A leader should decide on {goals} that their staff are happy to fulfil.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Part of a leader’s brief is to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"43\">set bold goals</strong>… that everyone in the organisation understands them, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"113\">buys into them</strong>…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Buys into them” có nghĩa là ủng hộ/chấp nhận, tương ứng với “happy to fulfil”. Lãnh đạo cần đề ra các mục tiêu (goals) mà nhân viên sẵn lòng thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Leaders should involve their staff in the process of producing a different {strategy}.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…involve them in making the changes by participating in the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"74\">design of a new strategy</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi cần thay đổi, lãnh đạo nên để nhân viên cùng tham gia vào việc thiết kế một chiến lược (strategy) mới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. If tricky issues arise, leaders should give staff the space to find {solutions} to them.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…give staff time to come up with <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"47\">new ideas and solutions</strong> that will fix new problems.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Tricky issues” tương ứng với “new problems”. Lãnh đạo cần cho nhân viên thời gian để tìm ra các giải pháp (solutions).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. Leaders need to encourage their staff to feel {pride} in the past achievements of the company.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Honour those early pioneers and instil a <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"53\">sense of pride</strong> across the organisation.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tôn vinh những người đi trước giúp tạo ra niềm tự hào (pride) về lịch sử và thành tựu của công ty.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">20. It is important for leaders to agree to a certain degree of {risk} when necessary.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Leaders need to accept that <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"40\">some risk may be required</strong> if the situation calls for it.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Agree to a certain degree” tương ứng với “accept some”. Lãnh đạo không nên quá an toàn mà cần chấp nhận rủi ro (risk) khi cần thiết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">21. If leaders find the {future} of the company exciting, their staff will be more motivated to work hard.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…having a leader who is <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"38\">genuinely thrilled about its future</strong> is hugely inspiring.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Exciting” tương ứng với “thrilled”. Nếu lãnh đạo hào hứng về tương lai (future) của công ty, nhân viên sẽ cảm thấy được truyền cảm hứng (motivated).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d36433b9-9a3d-418c-a906-393f01822462', 'b3ed8ffa-14a8-468d-adc8-5ac3bab65a16', 'checkbox', 'Questions 20–21', '', '<p>Choose <strong>TWO </strong>correct answers</p>
<p>Which <strong>TWO </strong>of the following statements concerning episodic memory are found in the text?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "Dr Tulving believes that most kinds of memory involve aspects of episodic memories"}, {"correct": true, "option_text": "The experimental subject KC was unable to recall the process by which he learned to play a particular board game"}, {"correct": true, "option_text": "In the case of KC, the subject’s episodic memory was affected by his brain injuries"}, {"correct": false, "option_text": "Dr Tulving carried out extensive observations of the episodic memories of animals as well as humans"}, {"correct": false, "option_text": "To test his episodic memory, KC was given various mathematical problems to solve"}]', 'null', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Đáp án đúng: B và C</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">B. The experimental subject KC was unable to recall the process by which he learned to play a particular board game.</strong></p>\n<ul data-path-to-node=\"8,0,1\">\n<li>\n<p data-path-to-node=\"8,0,1,0,0\"><em data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…could play chess with no memory of having ever played it before.” (Đoạn 1).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,0,1,1,0\"><em data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> KC biết chơi cờ nhưng không nhớ quá trình mình đã học nó như thế nào.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">C. In the case of KC, the subject’s episodic memory was affected by his brain injuries.</strong></p>\n<ul data-path-to-node=\"8,1,1\">\n<li>\n<p data-path-to-node=\"8,1,1,0,0\"><em data-path-to-node=\"8,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…certain brain injuries that cause them to forget autobiographical details… KC had lost what psychologists now call ‘episodic memory’.” (Đoạn 1).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,1,0\"><em data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Chấn thương não đã khiến KC mất đi trí nhớ về các trải nghiệm cá nhân.</p>\n</li>\n</ul>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('5c72b181-45c6-463b-ac83-3f90671a8555', '015e6956-c13d-4443-86a4-db82be9b4b60', 'checkbox', 'Questions 17-18', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1310" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="407" data-numctn="17" data-count="17" data-quest="17-18" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">17-18</span> Which TWO types of accommodation are available on a weekly basis?</p>
</div>
</div>
</div>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "lighthouse"}, {"correct": true, "option_text": "hostel"}, {"correct": false, "option_text": "castle"}, {"correct": true, "option_text": "cottages"}, {"correct": false, "option_text": "bed and breakfast"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('3dfdc0a7-12cb-4691-8d86-d4993670bba5', 'c9d07613-5e79-4daf-b759-3d630ae0d100', 'radio', 'Questions 14–17', NULL, '<p>Choose the correct letter, A, B, C or D.</p>
<p>Write the correct letter in boxes 14–17 on your answer sheet.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. the function of seabirds in the ecosystem. "}, {"content": "B. the present condition of the marine life. "}, {"content": "C. the likely location of the next El Niño event. "}, {"content": "D. why El Niño has had little effect there."}], "question": "Scientists are studying Año Nuevo in order to find out "}, {"correct": 0, "options": [{"content": "A. locate marine life. "}, {"content": "B. collect samples of their prey. "}, {"content": "C. conduct better experiments. "}, {"content": "D. relieve famine areas."}], "question": "One advantage of using birds is that they help scientists to "}, {"correct": 2, "options": [{"content": "A. a particular problem for gulls and cormorants. "}, {"content": "B. weaker in California than elsewhere. "}, {"content": "C. more destructive of marine life than previously. "}, {"content": "D. longer lasting than most."}], "question": "This year El Niño seems to be "}, {"correct": 3, "options": [{"content": "A. moving their colonies. "}, {"content": "B. delaying their nesting. "}, {"content": "C. nesting on different islands. "}, {"content": "D. neglecting to feed their young."}], "question": "In the current breeding season on the Farallon Islands, some species "}]', 'null', 'null', 'null', '[{"content": "<p>14. the present condition of the marine life<br />(Đoạn A: “&#8230;scientists are studying to assess the impact of El Niño&#8230; they are building a kind of window from which the health of the region’s entire marine ecosystem can be observed.”)<br />→ Mục đích nghiên cứu tại Año Nuevo là để đánh giá tình trạng hiện tại của hệ sinh thái biển, tức là đời sống sinh vật biển → đáp án là B. the present condition of the marine life.<br /> <br />15. locate marine life<br />(Đoạn B: “Birds are great biological sampling devices&#8230; The birds can track the upper 100 metres of the water columns for us.”)<br />→ Chim giúp các nhà khoa học xác định vị trí sinh vật biển, vì chúng săn mồi theo bản năng trong lớp nước mặt → đáp án là A. locate marine life.<br /> <br />16. more destructive of marine life than previously<br />(Đoạn C: “El Niño, which this year is the harshest ever recorded&#8230; Most of the prey species&#8230; are non-existent, which is unusual.”)<br />→ Năm nay, El Niño mạnh nhất từng được ghi nhận và khiến chuỗi thức ăn biển bị tàn phá nặng nề, nghiêm trọng hơn các năm trước → đáp án là C. more destructive of marine life than previously.<br /> <br />17. neglecting to feed their young<br />(Đoạn D: “Many species&#8230; are abandoning their nesting colonies long before any chicks have fledged&#8230; Where chicks are produced, the mortality rate is high.”)<br />→ Một số loài chim bỏ tổ, không nuôi con non, khiến tỷ lệ chết cao → đáp án là D. neglecting to feed their young.<br /> <br /> <br /> </p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('c8cef6bf-9324-4115-93fb-a5ebacb88f6e', '8850f39d-c4f0-4516-a2cd-0234e74bda36', 'fillup', 'Questions 22–27', '<p>Complete the notes below.</p>
<p>Choose <strong data-start="950" data-end="967">ONE WORD ONLY</strong> from the text for each answer.</p>
<p data-section-id="sa5uoc" data-start="1062" data-end="1091"><span style="font-size: 14pt;"><strong data-start="1065" data-end="1091">The best way to resign</strong></span></p>
<p>Avoid all {temptations} to resign in an angry way. Instead follow this procedure:</p>
<p data-section-id="tuol5x" data-start="1180" data-end="1223"><strong data-start="1184" data-end="1223">Arrange a meeting with the boss to:</strong></p>
<ul data-start="1224" data-end="1443">
<li data-section-id="qduwyi" data-start="1224" data-end="1310">mention any projects which are underway and give ideas for their {completion}</li>
<li data-section-id="1grjxlw" data-start="1311" data-end="1369">discuss how much notice you need to give before you go</li>
<li data-section-id="k467qk" data-start="1370" data-end="1443">request information on the type of {reference} you will receive</li>
</ul>
<p data-section-id="fe1smg" data-start="1450" data-end="1494"><strong data-start="1454" data-end="1494">Steps you can take before you leave:</strong></p>
<ul data-start="1495" data-end="1653">
<li data-section-id="ryv53p" data-start="1495" data-end="1572">work to cause as little {disruption} as possible to the organisation</li>
<li data-section-id="1d3lvve" data-start="1573" data-end="1653">make sure your successor has adequate guidance on the organisation’s systems</li>
</ul>
<p data-section-id="1jhupfp" data-start="1660" data-end="1694"><strong data-start="1664" data-end="1694">In the resignation letter:</strong></p>
<ul data-start="1695" data-end="1910">
<li data-section-id="1g9qos9" data-start="1695" data-end="1757">avoid mentioning any {feelings} in the organisation</li>
<li data-section-id="wbwxnp" data-start="1758" data-end="1853">show appreciation for aspects of the job, e.g. the chance to improve your {skills} indicate your wish to leave everything in good order</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. Avoid all {temptations} to resign in an angry way.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…you might really want to… get your own back by criticising your boss… But you need to <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"105\">resist these temptations</strong>…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Avoid” đồng nghĩa với “resist”. Người lao động cần kiềm chế những sự cám dỗ (temptations) muốn hành xử tiêu cực khi nghỉ việc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. …mention any projects which are underway and give ideas for their {completion}.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…write a list of ongoing tasks along with status updates and <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"75\">suggestions concerning completion</strong>.” (Phần Letting your manager know)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Underway” tương ứng với “ongoing”. Khi họp với sếp, cần đưa ra ý kiến (ideas/suggestions) để hoàn thành (completion) các việc còn dang dở.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">24. …request information on the type of {reference} you will receive.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"26,0,0\" data-index-in-node=\"12\">Ask about a reference too</strong>; your employer may only supply the most basic type…” (Phần Letting your manager know)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Request information” tương ứng với “Ask about”. Bạn nên hỏi về thư giới thiệu/xác nhận công tác (reference).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">25. …work to cause as little {disruption} as possible to the organisation.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Work out how you can ensure a smooth transition and <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"64\">minimise disruption</strong> to your employer.” (Phần Preparation)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “As little… as possible” tương ứng với “minimise”. Mục tiêu là giảm thiểu sự gián đoạn (disruption) cho công ty.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">26. …avoid mentioning any {feelings} in the organisation.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Don’t be tempted to address the <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"44\">feelings of the company</strong> or your boss, either.” (Phần Your letter of resignation)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong thư nghỉ việc, không nên đưa các cảm xúc (feelings) cá nhân hay về công ty vào.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">27. …show appreciation for aspects of the job, e.g. the chance to improve your {skills}.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Mention any… opportunities to <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"44\">develop skills</strong>…” (Phần Your letter of resignation – 2nd paragraph)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Improve” tương ứng với “develop”. Trong thư nên bày tỏ sự trân trọng với cơ hội phát triển kỹ năng (skills).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c0345437-0dda-4e2c-82d1-cad8a3f035db', 'b3ed8ffa-14a8-468d-adc8-5ac3bab65a16', 'checkbox', 'Questions 22–23', '', '<p data-start="791" data-end="822">Choose <strong data-start="798" data-end="805">TWO</strong> correct answers.</p>
<p data-start="824" data-end="839">Which <strong>TWO </strong>of the following statements are true concerning Dr Clayton’s experiments with scrub jays?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "The experiments indicated that the birds could remember how long their food had been buried"}, {"correct": false, "option_text": "In the experiments, the scrub jays preferred burying moth larvae to burying peanuts"}, {"correct": false, "option_text": "In the experiments, the birds were guided by the smell of the hidden food"}, {"correct": false, "option_text": "Scrub jays were taught by Dr Clayton to store food for future use"}, {"correct": true, "option_text": "Scrub jays would rather eat certain nuts than decaying moth larvae"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Đáp án đúng: A và E</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">A. The experiments indicated that the birds could remember how long their food had been buried.</strong></p>\n<ul data-path-to-node=\"12,0,1\">\n<li>\n<p data-path-to-node=\"12,0,1,0,0\"><em data-path-to-node=\"12,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “The time the scrub jays had spent away… affected the type of food they looked for.” (Đoạn 2).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,0,1,1,0\"><em data-path-to-node=\"12,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Chúng biết chọn sâu bướm sau 4 giờ nhưng chọn lạc sau 5 ngày vì biết sâu sẽ hỏng theo thời gian.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">E. Scrub jays would rather eat certain nuts than decaying moth larvae.</strong></p>\n<ul data-path-to-node=\"12,1,1\">\n<li>\n<p data-path-to-node=\"12,1,1,0,0\"><em data-path-to-node=\"12,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…if the larvae have been dead for even a few hours, the jays prefer peanuts.” (Đoạn 2).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,1,1,0\"><em data-path-to-node=\"12,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Lũ chim thích lạc (nuts) hơn là sâu bướm đã bị thối rữa (decaying).</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('5d35b6ce-c485-4830-a8fc-fa201f205bb0', '33dab258-66cc-415c-9d8a-d4e38db8ecb2', 'matching', 'Questions 28–32', '', '<p>Choose the correct heading for each section from the list of headings below.</p>
<p>Write the correct number, i–viii, in boxes 28–32 on your answer sheet.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i. Why emojis may have a short life"}, {"optionText": "ii. Ways in which new emojis are designed and made available"}, {"optionText": "iii. How words and emojis both fulfil new needs in our society"}, {"optionText": "iv. How emojis are regarded in different ways by different cultures"}, {"optionText": "v. The use of emojis in different fields and what this means for us"}, {"optionText": "vi. The rapid spread of a new way of interacting"}, {"optionText": "vii. How and where emojis were first invented"}, {"optionText": "viii. The value of emojis for making feelings clear"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. Section 1: {vi. The rapid spread of a new way of interacting}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…emojis… are at the forefront of this frenzy for change. …only began their growth in 2011. Four years later… used by <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"137\">over 90 per cent of the online population</strong>. In excess of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"193\">six billion were being sent every day</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này tập trung vào sự bùng nổ và tốc độ lan tỏa cực nhanh (rapid spread) của biểu tượng cảm xúc trong giao tiếp trực tuyến (new way of interacting) chỉ trong vòng vài năm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. Section 2: {iii. How words and emojis both fulfil new needs in our society}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Words are being created for these reasons all the time. But what’s interesting about emojis is that they’ve <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"120\">contributed to this ever-expanding storehouse in a different way</strong>… the gaps in our vocabulary are being filled…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này so sánh cách cả từ ngữ (words) và biểu tượng cảm xúc (emojis) đều đang được tạo ra hoặc thích nghi để lấp đầy những khoảng trống (needs) trong cách chúng ta diễn đạt bản sắc và khái niệm mới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. Section 3: {viii. The value of emojis for making feelings clear}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…computer-mediated messaging… can sometimes tend towards <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"73\">emotionally empty</strong>. …Emojis are a means of <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"117\">restoring this emotional framing</strong> to interaction – punctuating your message with a smile.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nhấn mạnh giá trị của emojis trong việc bù đắp sự thiếu hụt cảm xúc của tin nhắn văn bản, giúp thông điệp trở nên rõ ràng về mặt tình cảm (making feelings clear).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. Section 4: {i. Why emojis may have a short life}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…emojis have something akin to a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"47\">built-in obsolescence</strong>. …The emojis you have on your phone now will <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"116\">undergo subtle redesigns… and extra characters will be added</strong>. Because of this, their <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"203\">usefulness is artificially limited</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích lý do tại sao tuổi thọ của emojis lại ngắn (short life) – đó là do sự lỗi thời được lập trình sẵn và việc liên tục bị thay thế bởi các thiết kế hoặc nhân vật mới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">32. Section 5: {v. The use of emojis in different fields and what this means for us}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Finally, there’s the way they’ve become <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"52\">implicated in almost all aspects of modern society</strong>, from <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"109\">politics and marketing to art and entertainment</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn cuối liệt kê hàng loạt các lĩnh vực khác nhau (fields) mà emojis đã xâm nhập vào và khẳng định việc hiểu chúng sẽ giúp chúng ta hiểu về mối quan hệ của mình với xã hội.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d1b5de0f-9496-4a42-be02-9bcd3ca465e8', '33dab258-66cc-415c-9d8a-d4e38db8ecb2', 'fillup', 'Questions 33–37', '<p id="p-rc_c6794951c11f5fdd-174" data-path-to-node="3"><span class="citation-14667 citation-14668 citation-14669 citation-end-14669">Complete the summary below.</span></p>
<p id="p-rc_c6794951c11f5fdd-175" data-path-to-node="4"><span class="citation-14664 citation-14665 citation-14666">Choose </span><strong data-path-to-node="4" data-index-in-node="7"><span class="citation-14664 citation-14665 citation-14666">ONE WORD ONLY</span></strong><span class="citation-14664 citation-14665 citation-14666 citation-end-14666"> from the text for each answer.</span></p>
<p id="p-rc_c6794951c11f5fdd-177" data-path-to-node="6,0"><span style="font-size: 14pt;"><strong data-path-to-node="6,0" data-index-in-node="0"><span class="citation-14658 citation-14659 citation-14660 citation-end-14660">The importance of the ‘face with tears of joy’</span></strong></span></p>
<p id="p-rc_c6794951c11f5fdd-178" data-path-to-node="6,1"><span class="citation-14652 citation-14653 citation-14654 citation-14655 citation-14656 citation-14657 citation-end-14657">It is probable that before</span><span class="citation-14652 citation-14653 citation-14654 citation-14655 citation-14656 citation-end-14656"> long, an emoji such as th</span><span class="citation-14652 citation-14653 citation-14654 citation-14655 citation-end-14655">e ‘face with tears of joy’ wil</span><span class="citation-14652 citation-14653 citation-14654">l seem </span><span class="citation-14652 citation-14653 citation-14654">{dated}.This is of interest as it tells us about developments in </span><span class="citation-14652 citation-14653 citation-14654"><strong data-path-to-node="6,1" data-index-in-node="212">{society}</strong> , providing an effective way to focus on both the </span><span class="citation-14652 citation-14653 citation-14654 citation-end-14654"><strong data-path-to-node="6,1" data-index-in-node="326"><span class="citation-14652 citation-14653 citation-14654">{history}  </span></strong>and the future of human communication.</span></p>
<p id="p-rc_c6794951c11f5fdd-179" data-path-to-node="6,2"><span class="citation-14649 citation-14650 citation-14651 citation-end-14651">Changes in language reflect changes in people’s relationships. They ref</span><span class="citation-14649 citation-14650">lect the ways in which the</span><span class="citation-14649 citation-14650"> {identity}</span><span class="citation-14649 citation-14650 citation-end-14650">of groups and generations changes over time, and they allow </span><span class="citation-14649">new </span><span class="citation-14649 citation-end-14649">{concepts} to be included. However, emojis are interesting as they are a system that expresses these ideas in a completely new way</span>.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">33. It is probable that before long, an emoji such as the ‘face with tears of joy’ will seem {dated}.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the ‘face with tears of joy’ – will also appear to be <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"69\">dated</strong> in a few years.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết dự đoán rằng biểu tượng “cười ra nước mắt” sẽ sớm trở nên lỗi thời (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"89\">dated</em>) sau vài năm nữa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">34. This is of interest as it tells us about developments in {society},</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “But the reasons for this offer a fascinating insight into the way that <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"83\">society</strong> is evolving.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Developments” tương ứng với “evolving”. Việc biểu tượng này thay đổi cho chúng ta thấy cái nhìn thú vị về sự phát triển của xã hội.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">35. providing an effective way to focus on both the {history} and the future of human communication.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…acts as a surprisingly good lens through which to view the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"74\">history</strong> of human communication, and to predict its future.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “An effective way to focus” tương ứng với “a surprisingly good lens”. Emojis là lăng kính để nhìn về cả lịch sử lẫn tương lai của giao tiếp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">36. They reflect the ways in which the {identity} of groups and generations changes over time,</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “As an expression of <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"32\">identity</strong>, language is adapted by different groups and different generations to reflect their own sense of self.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngôn ngữ (và emojis) thay đổi để phản ánh bản sắc (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"63\">identity</em>) của các nhóm và các thế hệ khác nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">37. and they allow new {concepts} to be included.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “It also needs to constantly assimilate fresh <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"57\">concepts</strong> as these evolve.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Include” tương ứng với “assimilate” (đồng hóa/tiếp thu). Ngôn ngữ cần tiếp nhận những khái niệm (<em data-path-to-node=\"14,1,0\" data-index-in-node=\"110\">concepts</em>) mới khi chúng nảy sinh.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('602cfba7-59cd-465b-a3c7-a0e8b88f2fb0', '015e6956-c13d-4443-86a4-db82be9b4b60', 'checkbox', 'Questions 19–20', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1311" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="408" data-numctn="19" data-count="19" data-quest="19-20" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">19-20</span> Which TWO benefits can all the members get?</p>
</div>
</div>
</div>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "free entry to some castles"}, {"correct": true, "option_text": "subscription of Scottish magazines"}, {"correct": false, "option_text": "discount of apartment rent"}, {"correct": true, "option_text": "free visitor guide"}, {"correct": false, "option_text": "free parking"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('8e6cbb1b-5a99-4387-b6e9-0b0a9e9d850a', '33dab258-66cc-415c-9d8a-d4e38db8ecb2', 'radio', 'Questions 38–40', '', '<p data-path-to-node="11">Choose the correct letter, <strong data-path-to-node="11" data-index-in-node="27">A</strong>, <strong data-path-to-node="11" data-index-in-node="30">B</strong>, <strong data-path-to-node="11" data-index-in-node="33">C</strong> or <strong data-path-to-node="11" data-index-in-node="38">D</strong>.</p>
<p data-path-to-node="12">Write the correct letter in boxes 38–40 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A They include increasing numbers of emojis."}, {"option_text": "B They are soon forgotten by the public."}, {"option_text": "C They are required to have social significance."}, {"option_text": "D They are invented by the writers of dictionaries.C They are required to have social significance."}], "question": "What does the writer say about ‘Words of the Year’?"}, {"correct": 0, "options": [{"option_text": "A they are constantly being changed."}, {"option_text": "B they may not be correctly interpreted."}, {"option_text": "C they are difficult for some people to update."}, {"option_text": "D they are linked to specific operating systems."}], "question": "The writer says that the usefulness of emojis is limited because"}, {"correct": 3, "options": [{"option_text": "A Will emojis take over from words one day?"}, {"option_text": "B How can emojis be made more meaningful?"}, {"option_text": "C Are emojis used too much in our society today?"}, {"option_text": "D What do emojis tell us about the world we live in?"}], "question": "What would be the best subtitle for this text?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">38. What does the writer say about ‘Words of the Year’? — {B} They are soon forgotten by the public.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “And often, once that time has passed, they <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"55\">fade from people’s consciousness</strong> almost as quickly as they arose.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fade from consciousness” (phai nhạt khỏi tâm trí) đồng nghĩa với “soon forgotten” (sớm bị quên lãng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">39. The writer says that the usefulness of emojis is limited because — {A} they are constantly being changed.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…emojis have something akin to a <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"47\">built-in obsolescence</strong>… undergo subtle <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"87\">redesigns</strong> over the course of time, and <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"126\">extra characters will be added</strong>. Because of this, their usefulness is artificially limited.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự hữu dụng bị giới hạn là do chúng luôn bị thay đổi, nâng cấp và thiết kế lại thường xuyên (tương ứng với “constantly being changed”).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">40. What would be the best subtitle for this text? — {D} What do emojis tell us about the world we live in?</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Understanding why they’ve become so popular… can also help us to <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"79\">understand our relationship with technology, society and ourselves</strong>.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xuyên suốt bài đọc, tác giả không chỉ nói về emojis như một công cụ mà còn dùng chúng để giải thích về sự tiến hóa của xã hội, công nghệ và con người. Do đó, tiêu đề về việc emojis “kể” gì về thế giới chúng ta đang sống là bao quát nhất.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('ad784e4d-f819-4251-bf8b-5b644fd50f43', 'f1f5bdac-4560-4344-91a7-eac96d51fc38', 'matrix', 'Questions 1–7', '', '<p><span class="citation-19284 citation-19285 citation-19286 citation-19287">Write the correct letter, </span><strong data-path-to-node="5" data-index-in-node="26"><span class="citation-19284 citation-19285 citation-19286 citation-19287">A–E</span></strong><span class="citation-19284 citation-19285 citation-19286 citation-19287 citation-end-19287">, in boxes 1–7 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The site is impossible to get to at certain times.", "correctCategoryLetter": "D"}, {"itemText": "It is in a convenient place for going by car to various tourist spots.", "correctCategoryLetter": "A"}, {"itemText": "You should camp somewhere inside the marked zone.", "correctCategoryLetter": "C"}, {"itemText": "Campers who enjoy a particular physical challenge come here.", "correctCategoryLetter": "E"}, {"itemText": "The difficult journey to the site is worth the effort.", "correctCategoryLetter": "C"}, {"itemText": "Few people have heard of this site.", "correctCategoryLetter": "B"}, {"itemText": "Some physical effort is needed to enjoy nearby coastal areas.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. The site is impossible to get to at certain times. — {D: South Turnbull}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…in periods of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"29\">bad weather it can’t be reached at all</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu này nói rằng vào những lúc thời tiết xấu, địa điểm này hoàn toàn không thể tiếp cận được (“impossible to get to”).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. It is in a convenient place for going by car to various tourist spots. — {A: Prettycoat Farm}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…ideal base for exploring the area and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"53\">driving to the rock museum, the craft workshops or Gaydon Castle</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là địa điểm lý tưởng để từ đó lái xe đi tham quan nhiều điểm du lịch khác nhau (museum, workshops, castle).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. You should camp somewhere inside the marked zone. — {C: Oakerly Estate}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Make sure you stay safe and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"40\">pitch your tent within the white line</strong> around the cliff edge…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Marked zone” (khu vực được đánh dấu) chính là phần bên trong đường kẻ trắng (“white line”) để đảm bảo an toàn cho khách.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Campers who enjoy a particular physical challenge come here. — {E: Boxer Trepis}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…especially attractive to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"40\">rock climbers</strong>, who come here… so that they can <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"89\">attempt the climb</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thử thách thể chất cụ thể ở đây chính là bộ môn leo núi (rock climbing).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. The difficult journey to the site is worth the effort. — {C: Oakerly Estate}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"12\">You won’t be disappointed</strong> when you reach Oakerly, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"62\">despite the problems of getting there by car</strong> on such narrow roads.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dù đường đi khó khăn (narrow roads), nhưng bạn sẽ không thất vọng (worth the effort).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Few people have heard of this site. — {B: Newgammon Wild}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…reviews from the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"32\">handful of campers who know about it so far</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Handful” (một nhúm/một vài) tương ứng với “few people” – chỉ có rất ít người biết đến nơi này vì nó mới mở.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. Some physical effort is needed to enjoy nearby coastal areas. — {B: Newgammon Wild}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…attractive beaches, which can be accessed by <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"60\">steep, narrow cliff steps</strong>. You need a <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"98\">good level of fitness</strong> for these…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để xuống được bãi biển, bạn cần có thể lực tốt (physical effort) để leo các bậc thang dốc.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2b2e3376-5dd3-451d-98dd-32a3f7f41b07', '0ed2539e-aa7d-4760-a637-36285ec31e72', 'fillup', 'Questions 10–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"><strong>Amurca</strong></h3>
<p>In ancient times, this waste liquid was usually thrown away, which led to {pollution}</p>
<p>However, Romans had practical applications for America:</p>
<p>• when dried, created hard surface, so used on {floors} of certain buildings</p>
<p>• used when making {leather}</p>
<p>• into goods to wear fed to livestock</p>
<p>• used on farms as a {pesticide} to stop insects or animals damaging crops</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p><strong>10. In ancient times, this waste liquid was usually thrown away, which led to pollution.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>pollution</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “In many ancient civilisations it was often simply discarded, causing serious <strong>pollution</strong> because of its acidity and high salt content.”</li>\n</ul>\n<p><strong>11. when dried, created hard surface, so used on floors of certain buildings</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>floors</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “When spread on surfaces, amurca forms a hard finish and therefore it was often applied to the <strong>floors</strong> of grain storage buildings…”</li>\n</ul>\n<p><strong>12. used when making leather into goods to wear</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>leather</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “When boiled down amurca was applied to <strong>leather</strong> to soften it so that it was easier to shape into articles of clothing and shoes.”</li>\n</ul>\n<p><strong>13. used on farms as a pesticide to stop insects or animals damaging crops</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>pesticide</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “According to ancient texts, amurca was also utilised in moderate amounts by farmers as a fertiliser or as a <strong>pesticide</strong> helping them to protect their crops from insects and even small rodents.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('cb281b0a-0d67-4403-9799-93e63280e523', 'b3ed8ffa-14a8-468d-adc8-5ac3bab65a16', 'fillup', 'Questions 24–26', '<p data-start="1976" data-end="2052">Complete the summary.</p>
<p data-start="1976" data-end="2052">Write <strong data-start="2004" data-end="2021">ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;" data-start="2059" data-end="2098"><span style="font-size: 12pt;"><strong data-start="2063" data-end="2098">What is ‘true’ episodic memory?</strong></span></p>
<p data-start="2100" data-end="2514">Dr Suddendorf believes that ‘true’ episodic memory requires the ability to use the memory for the future. He cites as evidence ancient {tools} which early humans had taken some distance from where they had been originally fashioned. Dr Suddendorf’s theory is supported by brain scans showing activation of certain networks in particular areas of the brain both by episodic memory and by consideration of the future.</p>
<p data-start="2516" data-end="2832">Do non-human animals also exhibit ‘true’ episodic memory? Cebus monkeys appear to waste food once they are full, indicating that they do not plan for the future. However, in experiments, squirrel monkeys chose not to take the extra {dates} they were offered as food, in anticipation of wanting {water} soon afterwards.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">24. He cites as evidence ancient {tools} which early humans had taken some distance…</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><em data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…discovery of stone <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"34\">tools</strong> which primitive humans used… were moved many kilometres from where they were originally made.” (Đoạn 4).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">25. …squirrel monkeys chose not to take the extra {dates} they were offered…</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><em data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…gave squirrel monkeys a choice of between one or four <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"69\">dates</strong> to eat… The monkeys learned to choose one.” (Đoạn 6).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">26. …in anticipation of wanting {water} soon afterwards.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><em data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “If the monkeys took four, the scientists kept the <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"62\">water</strong> away for three hours. If the monkeys took one, the scientists returned it in half an hour.” (Đoạn 6).</p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('a4545b9e-eaa8-4e78-a2e3-28554ed9c984', '38236f7c-e75a-4072-8dfa-a85f03bc2a18', 'radio', 'Questions 33-35', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>.<br>Write your answers in boxes 33-35 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A a level of sporting skill."}, {"option_text": "B a system of words about movement."}, {"option_text": "C a pattern of connected cells."}, {"option_text": "D a type of golf swing."}], "question": "The writer uses the term ‘grammar of movement’ to mean"}, {"correct": 0, "options": [{"option_text": "A without conscious thought."}, {"option_text": "B by planning each phase of movement."}, {"option_text": "C without regular practice."}, {"option_text": "D by thinking about the actions of others."}], "question": "The writer states that expert players perform their actions"}, {"correct": 2, "options": [{"option_text": "A improve personal performance."}, {"option_text": "B feel linked with people of different nationalities."}, {"option_text": "C experience strong positive emotions."}, {"option_text": "D realize what skill consists of."}], "question": "The writer states that the most common motive for watching sport is to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. The writer uses the term ‘grammar of movement’ to mean — {C} a pattern of connected cells.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…inside these primate brains there were <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"54\">groups of cells</strong> that ‘store vocabularies of motor actions’. Just as there are <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"132\">grammars of movement</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ngữ pháp của chuyển động” ở đây được dùng để ẩn dụ cho các mạng lưới tế bào thần kinh kết nối với nhau để lưu trữ các chuỗi hành động.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. The writer states that expert players perform their actions — {A} without conscious thought.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “For him [the expert], the motor action has become memorized… He hits the ball with the tranquility of his <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"120\">perfected autopilot</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vận động viên chuyên nghiệp thực hiện hành động như một “chế độ lái tự động” (autopilot), tức là không cần suy nghĩ bằng ý thức (conscious thought).</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!---->\n<div class=\"image-container ng-star-inserted\" data-full-size-image-uri=\"https://encrypted-tbn3.gstatic.com/licensed-image?q=tbn:ANd9GcSXaKx7njOJYl9bwiPVMbZhLbw0aVSeWcTeYgnlZVvDq-pzdJs45UwRyDFEl7J9n5BjEMwacecRmzKiT2qQ1mOGg-J-9YwGzxnyAU6hf_hOvOhrbw0\">\n<p><!----><!----></p>\n</div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</div>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. The writer states that the most common motive for watching sport is — {C} experience strong positive emotions.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But how many of us regularly watch sports in order to be a better athlete? <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"87\">Rather, we watch sport for the feeling, the human drama</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Động cơ chính không phải để học tập mà là để trải nghiệm cảm xúc và kịch tính của con người.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('322dab46-f09a-4388-a778-199bf27ddc58', '1917d49b-66e7-4167-837b-de28547e4a60', 'checkbox', 'Questions 11–13', NULL, '<p>Choose <strong>THREE </strong>correct answers.</p>
<p>Which <strong>THREE </strong>of the following are parts of Gilbert’s discovery?</p>
', 'multiple_choice_many', 'null', '[{"option": "Metal can be transformed into another.", "correct": false}, {"option": "Garlic can remove magnetism.", "correct": false}, {"option": "Metals can be magnetised.", "correct": true}, {"option": "Stars are at different distances from the earth.", "correct": true}, {"option": "The earth wobbles on its axis.", "correct": true}, {"option": "There are two charges of electricity.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">C. Metals can be magnetised.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 10–12.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Gilbert also found that <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"36\">metals can be magnetised</strong> by rubbing materials such as fur, plastic or the like on them.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định trực tiếp rằng Gilbert đã phát hiện ra kim loại có thể được từ hóa bằng cách chà xát với các vật liệu khác. Đây là một phần quan trọng trong các thí nghiệm về từ tính của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">D. Stars are at different distances from the earth.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 3–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;he believed that <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"32\">stars are not equidistant</strong> from the earth but have their own earth-like planets orbiting around them.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thuật ngữ &#8220;not equidistant&#8221; có nghĩa là không cách đều. Điều này đồng nghĩa với việc các ngôi sao nằm ở những khoảng cách khác nhau (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"145\">different distances</strong>) so với Trái Đất. Đây là quan điểm tiến bộ của ông so với thiên văn học truyền thống thời bấy giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">E. The earth wobbles on its axis.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 8–12.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Thus a perfectly spherical lodestone&#8230; would <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"58\">wobble all by itself in 24 hours</strong>. Further, he also believed that the sun and other stars <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"147\">wobble just like the earth does</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Gilbert sử dụng mô hình quả cầu từ tính để chứng minh rằng Trái Đất tự quay và có hiện tượng &#8220;đảo&#8221; (wobble) quanh trục của nó. Ông xây dựng toàn bộ triết lý từ tính dựa trên sự tương đồng này giữa nam châm và Trái Đất.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('082b6250-25fd-425f-b9ad-0a12419b5d65', 'b34d2f6a-22fc-4d43-b0cf-80732d40dd60', 'fillup', 'Questions 21-22', '<p>Complete the summary below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage of each answer.</p>
<p>Write your answers in boxes 21-22 on your answer sheet</p>
<p><span style="font-size: 12pt;"><strong>The implement of CSR, HOW?</strong></span></p>
<p>Promotion of CSR requires the understanding of interdependence between business and society. Corporations workers’ productivity generally needs healthcare, education, and given {equal opportunity} Restrictions imposed by government and companies both protect consumers from being treated unfairly. Improvement ofthe safety standard can reduce the {internal costs} of accidents in the workplace. Similarly society becomes a pool of more human needs and aspirations</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong>21. Corporations workers’ productivity generally needs healthcare, education, and given <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> equal opportunity.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>equal opportunity</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Education, health care, and <strong>equal opportunity</strong> are essential lo a productive workforce.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong>22. Improvement of the safety standard can reduce the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> costs of accidents in the workplace.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>internal costs</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Safe products and working conditions not only attract customers but lower the <strong>internal costs</strong> of accidents.”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\">(Lưu ý: Đáp án “internal costs” là chính xác nhất theo văn bản. Tuy nhiên, nếu chỉ được dùng 2 từ, “costs of accidents” cũng là một khả năng. Dựa trên câu hỏi, “internal costs” là cụm 2 từ có ý nghĩa hoàn chỉnh.)</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('22a58961-c2f7-47ca-93c7-cb61b554e178', 'c9d07613-5e79-4daf-b759-3d630ae0d100', 'radio', 'Questions 18–26', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information <strong>FALSE </strong>if the statement contradicts the information <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The food which is found by the birds reflects the health of the sea life."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Birds look for specific characteristics when choosing their prey."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Marine animals can be hard for scientists to find."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "More biologists are involved in monitoring the effect of El Niño than ever before."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Adult sea birds locate prey below 100 metres."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It is difficult to interpret the data on the breeding success of birds."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Birds in Alaska are behaving in a similar way to birds further south."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "El Niño has been held responsible for the loss of bird life in Alaska."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Hatch argues that the constant strong winds that are damaging to wildlife are typically caused by El Niño."}]', 'null', 'null', 'null', '[{"content": "<p>18. TRUE<br />(Đoạn: “&#8230;the idea is that this indicates the state of the marine food web more directly than human devices for sampling populations of sea creatures.”)<br />→ Loài chim săn mồi phản ánh tình trạng sức khỏe của chuỗi thức ăn biển, vì lượng thức ăn chúng tìm được thể hiện mức độ phong phú của sinh vật biển → đáp án TRUE.</p>\n<p> <br />19. TRUE<br />(Đoạn: “Birds may not be unbiased&#8230; They may select certain sizes of fish, or prefer certain species of zooplankton.”)<br />→ Chim có xu hướng chọn con mồi theo kích thước hoặc loại, tức là có tiêu chí cụ thể khi săn → đáp án TRUE.</p>\n<p> <br />20. TRUE<br />(Đoạn: “&#8230;a process that can be very difficult for human scientists who must search a vast area of water to find scattered schools of marine animals.”)<br />→ Việc tìm sinh vật biển là rất khó khăn với các nhà khoa học, vì chúng sống rải rác trong vùng biển rộng lớn → đáp án TRUE.</p>\n<p> <br />21. NOT GIVEN<br />→ Bài không hề đề cập đến việc có nhiều nhà sinh học hơn trước đang nghiên cứu El Niño, mà chỉ nói chung rằng họ đang quan sát tại nhiều địa điểm khác nhau → đáp án NOT GIVEN.</p>\n<p> <br />22. FALSE<br />(Đoạn: “The birds can track the upper 100 metres of the water columns for us.”)<br />→ Chim chỉ tìm mồi trong 100 mét đầu tiên của cột nước, không phải bên dưới độ sâu này → đáp án FALSE.</p>\n<p> <br />23. NOT GIVEN<br />→ Đoạn văn chỉ nói rằng tỉ lệ sinh sản của chim phản ánh tình trạng nguồn thức ăn, chứ không hề nói rằng dữ liệu này khó phân tích → đáp án NOT GIVEN.</p>\n<p> <br />24. FALSE<br />(Đoạn: “El Niño may have little effect on sea life as far north as Alaska. So far, the birds are nesting right on schedule&#8230; it seems to be a normal breeding year.”)<br />→ Chim ở Alaska không bị ảnh hưởng giống chim ở miền Nam, vẫn sinh sản bình thường → đáp án FALSE.</p>\n<p> <br />25. TRUE<br />(Đoạn: “Hundreds of emaciated seabirds washed up dead on Alaska’s beaches&#8230; some observers were quick to pin the blame on El Niño.”)<br />→ Một số người đổ lỗi cho El Niño gây chết chim ở Alaska → đáp án TRUE.</p>\n<p> <br />26. FALSE<br />(Đoạn: “When strong winds are sustained over two or three-week periods&#8230; Since this occurs in years when there is no El Niño, it would be premature to say El Niño is the cause.”)<br />→ Hatch khẳng định gió mạnh gây hại cho chim không phải do El Niño, vì hiện tượng này cũng xảy ra khi không có El Niño → đáp án FALSE.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('b75de161-c2b6-4593-8ac0-60eb88acdee4', 'f1f5bdac-4560-4344-91a7-eac96d51fc38', 'radio', 'Questions 8–14', '', '<p data-path-to-node="13,0,0">Choose<strong data-path-to-node="13,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="13,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="13,2,0" data-index-in-node="0">NOT GIVEN</strong> if the<span class="citation-19260 citation-19261 citation-19262 citation-end-19262">re is no information on this</span></p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The water penetration in some flats is being treated as an emergency."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The southern wall will undergo a permanent repair this year."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some people have failed to pay attention to ''wet paint'' signs."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Air fresheners have caused some damage in the past."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Residents are responsible for removing their own rubbish from the building."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some residents have reported problems with noisy neighbours."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "DIY can take place outside the stated hours if your neighbour agrees."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. The water penetration in some flats is being treated as an emergency. — {TRUE}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “reached a <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"22\">critical level</strong>. A decision has been taken to <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"67\">deal with this immediately</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Critical level” (mức độ nghiêm trọng) và “immediately” (ngay lập tức) cho thấy đây là một tình huống khẩn cấp (emergency).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. The southern wall will undergo a permanent repair this year. — {FALSE}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…will be sealed <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"30\">temporarily</strong> with a waterproof covering… until the <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"82\">major building works take place next year</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Năm nay chỉ sửa chữa tạm thời (“temporarily”), việc sửa chữa lớn (vĩnh viễn) phải chờ đến sang năm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. Some people have failed to pay attention to ‘wet paint’ signs. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Please look out for signs indicating where the paint is wet.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bản tin chỉ dặn cư dân chú ý biển báo sơn ướt, <strong data-path-to-node=\"25,1,0\" data-index-in-node=\"59\">không hề có thông tin</strong> về việc đã có ai phớt lờ biển báo hay chưa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. Air fresheners have caused some damage in the past. — {TRUE}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the liquid in their spray <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"41\">stained the carpets</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nước xịt phòng đã làm ố/hỏng thảm, đây chính là thiệt hại (damage) trong quá khứ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. Residents are responsible for removing their own rubbish from the building. — {FALSE}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…put them in the corridor for <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"44\">collection and disposal by the caretaker</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cư dân chỉ cần để rác ở hành lang, việc thu gom và xử lý rác là trách nhiệm của người quản gia (caretaker).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. Some residents have reported problems with noisy neighbours. — {TRUE}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…we have <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"23\">received complaints from others about out-of-hours drilling</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhận được khiếu nại (complaints) về tiếng khoan ngoài giờ chứng tỏ cư dân đã báo cáo về hàng xóm ồn ào.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">14. DIY can take place outside the stated hours if your neighbour agrees. — {FALSE}</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…can only take place between… [hours]. <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"55\">There can be no exceptions to this rule</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quy định về giờ giấc làm việc nhà (DIY) là tuyệt đối, không có ngoại lệ (no exceptions), kể cả khi hàng xóm đồng ý.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ab9c6682-ea56-46ba-a4a7-0cae79266dd7', '66edec72-e7cc-440a-8e29-b7b59f7b2f69', 'fillup', 'Questions 24-26', '<p>Complete&nbsp;the&nbsp;summary&nbsp;below.</p><p>Choose&nbsp;<strong>ONE&nbsp;WORD&nbsp;ONLY</strong>&nbsp;from&nbsp;the&nbsp;passage&nbsp;for&nbsp;each&nbsp;answer.</p><p><strong>Uses&nbsp;of&nbsp;a&nbsp;popular&nbsp;tree</strong></p><p>For&nbsp;hundreds&nbsp;of&nbsp;years,&nbsp;the&nbsp;only&nbsp;tree&nbsp;that&nbsp;was&nbsp;more&nbsp;popular&nbsp;in&nbsp;Britain&nbsp;than&nbsp;elm&nbsp;was&nbsp;<strong>{oak}&nbsp;</strong>Starting&nbsp;in&nbsp;the&nbsp;Bronze&nbsp;Age,&nbsp;many&nbsp;tools&nbsp;were&nbsp;made&nbsp;from&nbsp;elm&nbsp;and&nbsp;people&nbsp;also&nbsp;used&nbsp;it&nbsp;to&nbsp;make&nbsp;weapons.&nbsp;In&nbsp;the&nbsp;18th&nbsp;century,&nbsp;it&nbsp;was&nbsp;grown&nbsp;to&nbsp;provide&nbsp;wood&nbsp;for&nbsp;boxes&nbsp;and&nbsp;<strong>{flooring}&nbsp;</strong>.&nbsp;Due&nbsp;to&nbsp;its&nbsp;strength,&nbsp;elm&nbsp;was&nbsp;often&nbsp;used&nbsp;for&nbsp;mining&nbsp;equipment&nbsp;and&nbsp;the&nbsp;Cutty&nbsp;Sark’s&nbsp;<strong>{keel}&nbsp;</strong>was&nbsp;also&nbsp;constructed&nbsp;from&nbsp;elm.</p>', '<p></p>', 'gap_filling', NULL, NULL, NULL, NULL, '[{"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('f6f4d0a4-d83e-400f-a992-1c5bdb6a6587', '7f7f39f8-b116-44e0-a6f4-a498a1c9df3c', 'fillup', 'Questions 15–20', '<p>Choose <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p>Write your answers in boxes 15–20 on your answer sheet.</p>
<p style="text-align: center;" data-path-to-node="4"><span style="font-size: 14pt;"><strong data-path-to-node="4" data-index-in-node="0">A day in the life of a care worker</strong></span></p>
<table style="border-collapse: collapse; width: 100.028%; height: 52.8px; border-spacing: 1px; border: 1px solid #000000;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr style="height: 52.8px;">
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;">It’s an early start for the first client. You may have to help the client get up and dressed if they have a {condition} that makes this challenging.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;">The next task may be cooking breakfast and it’s nice to have some {conversation} at this time.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;"> It may be a good idea to do some housework after this, such as {hoovering} and washing up.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;"> You may then visit a second client and help them get a {healthy} lunch ready.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;"> Lunch may be followed by some {shopping}.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 99.8582%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;"> Afterwards, a third client may need help with an activity that involves going out of their home, such as doing their {laundry}.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 100.028%; border-spacing: 1px; border: 1px solid #000000; margin-left: auto; margin-right: auto;" border="1"><colgroup> <col style="width: 100%;"></colgroup>
<tbody>
<tr>
<td style="padding: 1px; border-color: #000000;">
<p style="text-align: center;"> You may cook dinner with the final client of the day and also remind them about their medication.</p>
</td>
</tr>
</tbody>
</table>
<p> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. …if they have a {condition} that makes this challenging.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…they may suffer from a <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"38\">condition</strong> that prevents them from doing this easily.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Challenging” tương ứng với “prevents them from doing this easily”. Nhân viên cần giúp khách hàng mặc đồ nếu họ có một bệnh lý hoặc tình trạng sức khỏe (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"165\">condition</em>) nào đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. …it’s nice to have some {conversation} at this time.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this is often a good time to enjoy a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"52\">conversation</strong> and catch up on how they are feeling.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nấu bữa sáng, đây là lúc thích hợp để trò chuyện (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"66\">conversation</em>) với khách hàng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. …It may be a good idea to do some housework after this, such as {hoovering} and washing up.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Even something as simple as <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"40\">hoovering</strong> the living room can make a huge difference…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê các việc nhà cơ bản bao gồm hút bụi (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"65\">hoovering</em>) và rửa bát đĩa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. You may then visit a second client and help them get a {healthy} lunch ready.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Care workers try to ensure this is <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"47\">healthy</strong> because it is so important to keep clients fit and well.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Midday meal” tương ứng với “lunch”. Nhân viên cần đảm bảo bữa trưa của khách hàng thứ hai phải lành mạnh (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"119\">healthy</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">19. Lunch may be followed by some {shopping}.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the care worker may help the client to carry out their <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"70\">shopping</strong> by going with them to the local supermarket.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi chuẩn bị bữa trưa (midday meal), nhiệm vụ tiếp theo của nhân viên chăm sóc có thể là hỗ trợ khách hàng đi mua sắm (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"135\">shopping</em>) tại các siêu thị địa phương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">20. …an activity that involves going out of their home, such as doing their {laundry}.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…taking the <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">laundry</strong> to the launderette.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Với khách hàng thứ ba, hoạt động ngoài trời có thể là đi dạo hoặc mang đồ đi giặt (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"95\">laundry</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('577ac97f-56c8-4f89-8a3f-0d9541201803', '3bddf77b-e479-402d-938a-f2dd4deb4c5b', 'radio', 'Questions 1-4', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information <strong>FALSE</strong> if the statement contradicts the information<br><strong>NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the past, it was easier for scientists to study the Moon than the oceans."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Techniques for investigating the Moon are the same as techniques for researching the ocean."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Measuring temperature changes in the ocean using sound is more time-consuming than other methods."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Hydrophones can distinguish different kinds of rain.  "}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. In the past, it was easier for scientists to study the Moon than the oceans. — {TRUE}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The Moon has been far more accessible to study because astronomers have long been able to look at its surface… light… cannot penetrate very far in seawater.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặt trăng dễ tiếp cận hơn vì có thể dùng mắt thường hoặc kính thiên văn để quan sát bằng ánh sáng, trong khi ánh sáng không thể đi xa trong nước biển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. Techniques for investigating the Moon are the same as techniques for researching the ocean. — {FALSE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…astronomers have long been able to look at its surface… using instruments that focus <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"102\">light</strong>… it turns out that for penetrating water the best instrument is <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"174\">sound</strong>.” (Đoạn A &amp; B)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu Mặt trăng dùng ánh sáng (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"48\">light</em>), còn nghiên cứu đại dương dùng âm thanh (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"96\">sound</em>). Đây là hai kỹ thuật hoàn toàn khác nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. Measuring temperature changes in the ocean using sound is more time-consuming than other methods. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Thus, the travel time of a wave of sound… is a sensitive indicator of the average temperature along its path.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói về việc dùng âm thanh để đo nhiệt độ, nhưng <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"68\">không hề so sánh</strong> xem phương pháp này có tốn thời gian hơn các phương pháp khác hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. Hydrophones can distinguish different kinds of rain. — {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…Nystuen has used hydrophones… acoustically measuring not only the rainfall rate but also the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"110\">rainfall type, ranging from drizzle to thunderstorms</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Máy thu âm dưới nước (hydrophones) có thể phân biệt được các loại mưa từ mưa phùn đến bão kèm sấm sét.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('84d61764-b110-4bc0-ab37-ae9a6656f49c', '2233b1bc-2fdb-4d24-9641-80c114ebf715', 'fillup', 'Questions 21–23', '<p data-start="93" data-end="157">Complete the notes below.<br data-start="118" data-end="121">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Products using renewable energy sources</span></strong></p>
<p data-start="208" data-end="249"><strong>a) Kites produced by German company</strong></p>
<ul data-start="250" data-end="367">
<li data-start="250" data-end="290">
<p>are attached to ships by long cables</p>
</li>
<li data-start="291" data-end="327">
<p>can use wind power in any {weather}</p>
</li>
<li data-start="328" data-end="367">
<p>could reduce toxic emissions by 50%</p>
</li>
</ul>
<p data-start="369" data-end="411"><strong>b) Sports car produced by US company</strong></p>
<ul data-start="412" data-end="474">
<li data-start="412" data-end="445">
<p>uses {electricity} as a power source</p>
</li>
<li data-start="446" data-end="474">
<p>will have zero emissions</p>
</li>
</ul>
<p data-start="476" data-end="524"><strong>c) Ethanol stoves produced in South Africa</strong></p>
<ul data-start="525" data-end="584">
<li data-start="525" data-end="584">
<p>are safer than paraffin stoves as less likely to {explode}</p>
</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: RENEWABLE ENERGY PROJECT</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Sylvia:</strong> Greg, about this project on renewable energy, we’ve got to look at some products that use it and then see how aware people are of this kind of energy.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Greg:</strong> Well, first we must clarify what renewable energy is.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Sylvia:</strong> I’ve done that. It’s energy from a source which is replaced by a natural process, such as wind, tidal energy from the sea, energy from the sun and so on. And I found some very interesting examples of products using these sources.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Greg:</strong> So have I. What have you got?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Sylvia:</strong> Well, the first one is a company in Germany which is producing huge kites that pull ships along. The kites are attached by long cables and they fly up to 500 meters above the sea.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Greg:</strong> They must be pretty big. And it means that they can be powered by the wind <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"81\">(21) no matter what the weather [Answer: weather]</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Sylvia:</strong> That sounds like a good idea, but will they really help reduce energy use?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Greg:</strong> You bet. As well as that, apparently the shipping industry is one of the worst polluters on the planet as they use cheap diesel fuel which has terrible toxic emissions. The company believes these kites could cut the use of these fuels by 50% and reduce the emissions by the same amount.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Sylvia:</strong> Sounds good. And I found a company in the US which is developing a new type of car. Apparently, they’re producing a sports car which doesn’t use petrol at all, just <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"173\">(22) electricity [Answer: electricity]</strong></span>, but for the US market only.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Greg:</strong> Sounds intriguing. Do we know what it’ll look like?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Sylvia:</strong> They’re very secretive about it, and all they say is that it won’t look ugly and it’ll have zero emissions.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Greg:</strong> Wow, really? So they say. Any other products?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Sylvia:</strong> I found an interesting article about a man in South Africa who’s selling stoves using ethanol to the local people.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Greg:</strong> Ethanol?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Sylvia:</strong> Yes, it’s made from the sugar of certain crops. Most of the local people use paraffin stoves at the moment and they are dangerous because they can <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"155\">(23) explode [Answer: explode]</strong></span> quite easily.</p>\n<hr data-path-to-node=\"18\" />\n<h3 data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">THE SURVEY (Questions 24–30)</strong></h3>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Greg:</strong> Right. Now for the next part, we have to do a survey to find out how aware the public is about this kind of energy. Who shall we approach? Local businesses?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Sylvia:</strong> I think it’s easier to do a survey of the general public rather than local companies. Last time we sent all those email surveys to commercial organizations and we only had replies from 5% of them.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Greg:</strong> Oh, I forgot that. OK then, what about the other students and the lecturer here in the university?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Sylvia:</strong> You know what the lecturers are like, they’re so busy they won’t have the time. But the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"96\">(24 &amp; 25) students [Answer: university students]</strong></span> will, I’m sure.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Greg:</strong> Okay. And as well as that, we could target the local schools like last time. School kids just love doing surveys.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Sylvia:</strong> I think we want to stick to adults for this, don’t you? Maybe we could approach <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"88\">(24 &amp; 25) people who rent or own properties [Answer: local residents]</strong></span> around here, since they’re the ones who have to pay for the energy.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Greg:</strong> Exactly. Now, what about the kind of questions we want to include in the survey?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Sylvia:</strong> Well, we need to find out if they know what renewable energy is. I know it’s been all over the news lately, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"27\" data-index-in-node=\"120\">(26) I think a lot of people are still in the dark about it [Answer: A – Many people know little about it]</strong>.</span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Greg:</strong> Do you think so? I’m not sure I agree, but we can have that in if you want. We also need to find out what they think about traditional energy sources like gas and coal.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Sylvia:</strong> And <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"12\">(27) we ought to see what they think is going to happen to the consumption of traditional energy sources [Answer: B – possible future developments]</strong>.</span></p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Greg:</strong> You’re right. Then there’s nuclear power. That’s an interesting one because it’s cleaner and more efficient in many ways, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"132\">(28) the safety factor has always worried people [Answer: C – Some people think it is unsafe]</strong>.</span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Sylvia:</strong> Yes, I know that the technology has improved greatly, but I don’t think everyone is convinced. Are there any problems with renewable energy?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Greg:</strong> One argument is that it’s going to be too expensive. But <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"63\">(29) once enough people want it, the price is bound to come down [Answer: A – Prices will drop in the future]</strong>.</span></p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Sylvia:</strong> Hmm, that’s true. But the other thing is they don’t like it; they say some of the technology is ugly, like the big windmills used. A lot of people think they spoil the countryside.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Greg:</strong> I agree they’re not that bad, they’re pretty efficient. So perhaps it’s a case of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"88\">(30) choosing the right place for them, where they look least out of place [Answer: B – should be put in carefully selected locations]</strong>.</span></p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Sylvia:</strong> A good point. It’ll be very interesting to see the results of this survey.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('5cae1646-3c61-4263-88da-237c2d192aee', '66edec72-e7cc-440a-8e29-b7b59f7b2f69', 'radio', 'Questions 19-23', '<p></p>', '<p>Look&nbsp;at&nbsp;the&nbsp;following&nbsp;statements&nbsp;(Questions&nbsp;19–23)&nbsp;and&nbsp;the&nbsp;list&nbsp;of&nbsp;people&nbsp;below.</p><p>Match&nbsp;each&nbsp;statement&nbsp;with&nbsp;the&nbsp;correct&nbsp;person,&nbsp;A,&nbsp;B,&nbsp;or&nbsp;C.</p><p><strong>NB&nbsp;</strong>You&nbsp;may&nbsp;use&nbsp;any&nbsp;letter&nbsp;more&nbsp;than&nbsp;once.</p>', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": null}], "question": null}]', NULL, NULL, NULL, NULL, 1);
INSERT INTO public.questions VALUES ('4becc3bf-a3bb-4a68-aab1-b452874af40e', '7f7f39f8-b116-44e0-a6f4-a498a1c9df3c', 'fillup', 'Questions 21–27', '<p data-path-to-node="8">Complete the sentences below.</p>
<p data-path-to-node="8">Choose <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<ul data-path-to-node="9">
<li>
<p id="p-rc_57900076596b5083-370" data-path-to-node="9,0,0"><span class="citation-24324 citation-24325 citation-24326 citation-24327 citation-24328">People who cut down the hours they work gain most from feeling better physically and experiencing an increased sense of {wellbeing}</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-371" data-path-to-node="9,1,0"><span class="citation-24319 citation-24320 citation-24321 citation-24322 citation-24323">It is important that those who work at desks avoid {injuries}</span><span class="citation-24319 citation-24320 citation-24321 citation-24322 citation-24323 citation-end-24323"> by checking their chair, work surface and screen are in th</span><span class="citation-24319 citation-24320 citation-24321 citation-24322 citation-end-24322">e best position.</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-372" data-path-to-node="9,2,0"><span class="citation-24315 citation-24316 citation-24317 citation-24318">Having targets to work towards is useful but they should be {realistic}</span><span class="citation-24315 citation-24316 citation-24317 citation-24318 citation-end-24318">.</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-373" data-path-to-node="9,3,0"><span class="citation-24311 citation-24312 citation-24313 citation-24314 citation-end-24314">When there</span><span class="citation-24311 citation-24312 citation-24313"> are many different tasks to do, the ability to {prioritise | prioritize}</span><span class="citation-24311 citation-24312 citation-24313 citation-end-24313"> them is vital.</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-374" data-path-to-node="9,4,0"><span class="citation-24308 citation-24309 citation-24310 citation-end-24310">People who give up all treats in </span><span class="citation-24308 citation-24309">their personal time may find their {productivity}</span><span class="citation-24308 citation-24309 citation-end-24309"> decreases.</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-375" data-path-to-node="9,5,0"><span class="citation-24306 citation-24307">It is wise to use the full amount of {holiday}</span><span class="citation-24306 citation-24307 citation-end-24307"> allowance eve</span><span class="citation-24306 citation-end-24306">ry year.</span></p>
</li>
<li>
<p id="p-rc_57900076596b5083-376" data-path-to-node="9,6,0"><span class="citation-24305">Making time to do things with close companions, relatives or {pets}</span><span class="citation-24305 citation-end-24305"> is a great way to rel</span>ax.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. …gain most from feeling better physically and experiencing an increased sense of {wellbeing}.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…is an improvement in their general health and <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"61\">wellbeing</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Feeling better physically” tương ứng với “health”. Việc giảm giờ làm giúp cải thiện sức khỏe và sự hạnh phúc/an yên (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"130\">wellbeing</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. It is important that those who work at desks avoid {injuries} by checking their chair…</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…help to minimise the chance of any <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"50\">injuries</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thiết lập vị trí làm việc (workstation) thoải mái giúp giảm thiểu nguy cơ gặp phải các chấn thương (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"112\">injuries</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Having targets to work towards is useful but they should be {realistic}.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Remember though, to make these <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"43\">realistic</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Targets” tương ứng với “goals”. Các mục tiêu cần phải thực tế (<em data-path-to-node=\"24,1,0\" data-index-in-node=\"76\">realistic</em>) để không làm tổn hại đến sự tự tin.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">24. When there are many different tasks to do, the ability to {prioritise} them is vital.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…but if you’re juggling numerous pieces of work on a daily basis, learning to <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"92\">prioritise</strong> is key.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Numerous tasks” tương ứng với “juggling numerous pieces of work”. Kỹ năng ưu tiên công việc (<em data-path-to-node=\"26,1,0\" data-index-in-node=\"106\">prioritise</em>) là cực kỳ quan trọng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">25. People who give up all treats in their personal time may find their {productivity} decreases.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this can easily become overwhelming and ultimately hinder your <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"78\">productivity</strong>.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Hinder” tương ứng với “decreases”. Nếu không có gì vui vẻ để mong đợi, hiệu suất làm việc (<em data-path-to-node=\"28,1,0\" data-index-in-node=\"104\">productivity</em>) sẽ bị giảm sút.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">26. It is wise to use the full amount of {holiday} allowance every year.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…make sure you take your annual <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"46\">holiday</strong> entitlement.” (Đoạn 9)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Full amount… allowance” tương ứng với “entitlement”. Bạn nên tận dụng hết số ngày nghỉ lễ/nghỉ phép (<em data-path-to-node=\"30,1,0\" data-index-in-node=\"116\">holiday</em>) hàng năm của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">27. Making time to do things with close companions, relatives or {pets} is a great way to relax.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Family, friends and favourite <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"42\">pets</strong> are the ultimate life enhancers.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Close companions” tương ứng với “friends”, “relatives” tương ứng với “family”. Dành thời gian cho người thân và thú cưng (<em data-path-to-node=\"32,1,0\" data-index-in-node=\"135\">pets</em>) là cách tốt nhất để thư giãn.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e7c881c8-1493-43f0-b4a5-b8e92dfd2b7b', 'a39a2927-fa38-49de-8500-ce2b13770ce9', 'matrix', 'Question 27–32', NULL, '<p>Reading Passage 3 has six sections <strong>A–F</strong>.</p>
<p>Which section contains the following information?</p>
<p>Write the correct letter <strong>A–F</strong> in boxes 27–32 on your answer sheet.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "positive and negative possibilities for the use of insect-inspired robots", "correctCategoryLetter": "F"}, {"itemText": "how perceived size is used as an aid to navigation", "correctCategoryLetter": "B"}, {"itemText": "an example of decision-making taking place in the limbs", "correctCategoryLetter": "E"}, {"itemText": "a description of a potential aid in space exploration", "correctCategoryLetter": "D"}, {"itemText": "the range of skills that have inspired biorobotics", "correctCategoryLetter": "A"}, {"itemText": "how a variety of navigational methods operate at the same time", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Câu 27: positive and negative possibilities for the use of insect-inspired robots</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> F</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “While some were concerned that the initial applications… may be military, others… predicted swarms of tiny cheap insect-like robots as society’s cleaners and collectors.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F thảo luận về các khả năng tích cực (làm sạch, bảo vệ môi trường) và tiêu cực (mục đích quân sự) của biorobotics.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Câu 28: how perceived size is used as an aid to navigation</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The landmarks are then scaled, from small to large, so that the robot can recognize whether it is getting closer to or further away from them.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B mô tả cách robot của Dr. Zelinsky thay đổi tỉ lệ (scale) kích thước vật thể để xác định khoảng cách khi di chuyển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Câu 29: an example of decision-making taking place in the limbs</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> E</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The key to the cockroach’s remarkable cross-country performance lies partly in the fact that its legs do a lot of the ‘thinking’ without having to consult the brain.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E nói về việc chân của loài gián có khả năng tự “suy nghĩ” (đưa ra quyết định vận động) mà không cần thông qua não bộ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Câu 30: a description of a potential aid in space exploration</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…to design a flying robot that can not only navigate but also stay aloft and hover in the thin atmosphere of Mars.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D mô tả ‘Entomopter’ – một loại robot bay được thiết kế để khám phá sao Hỏa (không gian).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Câu 31: the range of skills that have inspired biorobotics</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> A</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…insects constantly solve complex problems of movement, vision and navigation… How they do it is driving one of the most exciting new fields… biorobotics…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A liệt kê hàng loạt các kỹ năng của côn trùng (di chuyển, thị giác, định vị) là nguồn cảm hứng cho lĩnh vực này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Câu 32: how a variety of navigational methods operate at the same time</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the ant has many separate subroutines going on simultaneously. Using the ant’s ability to steer by polarised light and to store and reuse landscape images…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả cách loài kiến sử dụng đồng thời nhiều phương pháp như ánh sáng phân cực và hình ảnh ghi nhớ để định vị.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('07316e7e-9bd3-4a2a-956b-1d03246e366f', 'aac6c9e0-0787-432b-9cd7-9e089e93cb78', 'radio', 'Questions 28–31', '', '<p>Choose the correct letter, <strong data-path-to-node="2" data-index-in-node="43">A</strong>, <strong data-path-to-node="2" data-index-in-node="46">B</strong>, <strong data-path-to-node="2" data-index-in-node="49">C</strong> or <strong data-path-to-node="2" data-index-in-node="54">D</strong>.</p>
<p>Write the correct letter in boxes 28–31 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A. Its ‘Henry’ programme was recommended to Leeds experts."}, {"option_text": "B. It was the first world city to reduce obesity levels in children."}, {"option_text": "C. It has experienced more severe childhood obesity levels than Leeds."}, {"option_text": "D. Its pattern of success in cutting childhood obesity is like that of Leeds."}], "question": "In the first paragraph, what does the writer say about Amsterdam?"}, {"correct": 1, "options": [{"option_text": "A. She said she had expected it."}, {"option_text": "B. She said she was amazed by the figures."}, {"option_text": "C. She wanted to review some of her team’s data."}, {"option_text": "D. She felt some results were more interesting than others."}], "question": "How did Susan Jebb respond to the fall in childhood obesity among poorer children in Leeds?"}, {"correct": 3, "options": [{"option_text": "A. children should be weighed more frequently."}, {"option_text": "B. most primary school children need to lose weight."}, {"option_text": "C. children from wealthy families have less weight to lose than others."}, {"option_text": "D. the youngest children show the highest levels of weight loss."}], "question": "According to the writer, the NCMP data indicate that"}, {"correct": 2, "options": [{"option_text": "A. They are not representative of the country overall."}, {"option_text": "B. They all joined the ‘Henry’ programme at the same time."}, {"option_text": "C. Their childhood obesity levels have remained the same since 2009."}, {"option_text": "D. They are battling childhood obesity in a different way from Leeds."}], "question": "What links the 15 places listed in the third paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. In the first paragraph, what does the writer say about Amsterdam? — {D} Its pattern of success in cutting childhood obesity is like that of Leeds.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"12\">As in Amsterdam</strong>, the decline in Leeds is most marked among families living in the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"94\">most deprived areas</strong>…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cả Leeds và Amsterdam đều có chung một mô thức thành công (pattern of success) là mức độ giảm béo phì rõ rệt nhất nằm ở những khu vực nghèo khó nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. How did Susan Jebb respond to the fall in childhood obesity among poorer children in Leeds? — {B} She said she was amazed by the figures.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “‘The improvement in the most deprived children in Leeds is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"71\">startling</strong>,’ said Susan Jebb…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “startling” (gây kinh ngạc/giật mình) đồng nghĩa với “amazed”. Cô ấy ngạc nhiên trước sự cải thiện của trẻ em ở các khu vực nghèo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. According to the writer, the NCMP data indicate that — {D} the youngest children show the highest levels of weight loss.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"16\">biggest decline</strong> in obesity in Leeds is 6.4% in the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"67\">reception class</strong>, at about the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"97\">age of four</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhóm trẻ nhỏ tuổi nhất (lớp mầm non/4 tuổi) là nhóm có tỷ lệ giảm béo phì cao nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. What links the 15 places listed in the third paragraph? — {C} Their childhood obesity levels have remained the same since 2009.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The obesity rates <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"30\">there [15 neighbours]</strong> and across the country <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"75\">have not shifted</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Have not shifted” (không thay đổi) đồng nghĩa với “remained the same”. Trong khi Leeds giảm thì 15 thành phố lân cận vẫn giữ nguyên tỷ lệ.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('ba4e4cb5-03e2-46c8-a7a3-6199af1e82de', 'b6ab50b8-ac9f-4a3b-b1e4-a267c6b6981f', 'radio', 'Questions 1-8', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the early 19th century, the port of London was considered a safer destination than other ports"}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "London Bridge provided quick access for cargo being sent to southern Britain"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It was generally believed that a new river crossing would be profitable"}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Building a second bridge crossing was initially considered to be the best solution"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It was believed that coal could be found under the River Thames"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Thames Archway Company was the first group to try tunnelling below the Thames"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Some of Trevithick''s men were injured during a mudslide at his tunnel"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Thames Archway Company ran out of money to finance the tunnel project"}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">1. In the early 19th century, the port of London was considered a safer destination than other ports.</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “At the beginning of the 19th century, the port of London was the busiest in the world. Cargoes that had travelled thousands of miles and survived all the hazards of the sea were unloaded…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu rằng cảng London rất bận rộn và hàng hóa đã vượt qua các nguy hiểm trên biển để đến đây. Tuy nhiên, không có thông tin nào so sánh độ an toàn của cảng London với các cảng khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">2. London Bridge provided quick access for cargo being sent to southern Britain.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…London Bridge, built in the 12th century and as impractical as its early date implies. By 1820, London Bridge had become the centre of the world’s largest traffic jam.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cây cầu này rất bất tiện và là trung tâm của sự tắc nghẽn giao thông lớn nhất thế giới, vì vậy nó không thể cung cấp sự tiếp cận nhanh chóng cho hàng hóa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">3. It was generally believed that a new river crossing would be profitable.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was clear that if private enterprise could build another crossing closer to the docks, there would be good money to be made in tolls paid by users.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản khẳng định rằng nếu xây dựng được một lối băng qua sông mới, chủ đầu tư sẽ thu được rất nhiều tiền từ phí cầu đường của người dân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">4. Building a second bridge crossing was initially considered to be the best solution.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Another bridge was out of the question, as this would deny sailing ships access to the city centre…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc xây một cây cầu khác là “không thể bàn tới” vì nó sẽ ngăn cản tàu buồm đi vào trung tâm thành phố. Do đó, nó chưa bao giờ được coi là giải pháp tốt nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">5. It was believed that coal could be found under the River Thames.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Although increasing demand for coal had meant a great many tunnels had been dug in mines in Britain, working methods remained primitive.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Than đá được nhắc đến như lý do khiến kỹ thuật đào hầm mỏ phát triển ở Anh, nhưng không có thông tin nào nói rằng người ta tin có than dưới lòng sông Thames.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">6. The Thames Archway Company was the first group to try tunnelling below the Thames.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Their ambition was to tunnel below the Thames, but there was little to guide them as there had been no previous attempt to do this.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước dự án của công ty này vào năm 1807, chưa từng có nỗ lực nào khác để đào hầm dưới sông Thames được thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">7. Some of Trevithick’s men were injured during a mudslide at his tunnel.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…things began to go disastrously wrong, with muddy soil pouring into the tunnel.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về sự cố bùn tràn vào hầm, nhưng không đề cập đến việc có công nhân nào bị thương hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">8. The Thames Archway Company ran out of money to finance the tunnel project.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Eventually, the Thames Archway Company had had enough. Its funds were exhausted…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “funds were exhausted” có nghĩa là nguồn vốn đã cạn kiệt hoàn toàn, đồng nghĩa với việc hết tiền để tài trợ dự án.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('50d899ab-ac84-459e-8813-653140b4a6fa', '6204f6ae-328d-4a14-bc38-cfde012e66e7', 'radio', 'Questions 31–35', NULL, '<p>Complete each sentence with the correct ending, A–G, below.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": null}], "question": null}]', NULL, NULL, NULL, NULL, 1);
INSERT INTO public.questions VALUES ('b5dd0af6-a06c-4d6a-bec1-fd8369b9301d', 'aac6c9e0-0787-432b-9cd7-9e089e93cb78', 'matrix', 'Questions 32–35', '', '<p>Match each stat<span class="citation-1757 citation-1758 citation-1759">ement with the correct person, </span><strong data-path-to-node="13" data-index-in-node="143"><span class="citation-1757 citation-1758 citation-1759">A</span></strong><span class="citation-1757 citation-1758 citation-1759">, </span><strong data-path-to-node="13" data-index-in-node="146"><span class="citation-1757 citation-1758 citation-1759">B</span></strong><span class="citation-1757 citation-1758 citation-1759">, </span><strong data-path-to-node="13" data-index-in-node="149"><span class="citation-1757 citation-1758 citation-1759">C</span></strong><span class="citation-1757 citation-1758 citation-1759"> or </span><strong data-path-to-node="13" data-index-in-node="154"><span class="citation-1757 citation-1758 citation-1759">D</span></strong><span class="citation-1757 citation-1758 citation-1759 citation-end-1759">.</span></p>
<p><span class="citation-1754 citation-1755 citation-1756">Write the correct letter, </span><strong data-path-to-node="13" data-index-in-node="183"><span class="citation-1754 citation-1755 citation-1756">A</span></strong><span class="citation-1754 citation-1755 citation-1756">, </span><strong data-path-to-node="13" data-index-in-node="186"><span class="citation-1754 citation-1755 citation-1756">B</span></strong><span class="citation-1754 citation-1755 citation-1756">, </span><strong data-path-to-node="13" data-index-in-node="189"><span class="citation-1754 citation-1755 citation-1756">C</span></strong><span class="citation-1754 citation-1755 citation-1756"> or </span><strong data-path-to-node="13" data-index-in-node="194"><span class="citation-1754 citation-1755 citation-1756">D</span></strong><span class="citation-1754 citation-1755 citation-1756 citation-end-1756">, in boxes 32–35 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "The aim in Leeds was to take steps to stop weight gain among children before it became a real problem.", "correctCategoryLetter": "C"}, {"itemText": "Childhood obesity levels in Leeds have fallen consistently over a period of time.", "correctCategoryLetter": "A"}, {"itemText": "Something that simplifies the struggle to get children to eat well is very helpful to parents.", "correctCategoryLetter": "D"}, {"itemText": "Parents in general are realistic about their potential to make changes to their children’s lifestyle.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Susan Jebb", "categoryLetter": "A"}, {"categoryText": "Kim Roberts", "categoryLetter": "B"}, {"categoryText": "Janice Burberry", "categoryLetter": "C"}, {"categoryText": "Seema Kennedy", "categoryLetter": "D"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('3ae83f34-9d23-4c35-beba-86f8494169a6', 'b34d2f6a-22fc-4d43-b0cf-80732d40dd60', 'matrix', 'Questions 23-26', NULL, '<p><span style="font-family: arial, helvetica, sans-serif;">Look at the following opinions or deeds (Questions 23-26) and the list of companies below.</span></p>
<p><span style="font-family: arial, helvetica, sans-serif;">Match each opinion or deed with the correct company, <strong>A, B </strong>or <strong>C</strong>.</span></p>
<p><span style="font-family: arial, helvetica, sans-serif;">Write the correct letter, <strong>A, B </strong>or <strong>C</strong> in boxes 23-26 on your answer sheet.</span></p>
<p><span style="font-family: arial, helvetica, sans-serif;">NB You may use any letter more than once</span></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "The disposable waste", "correctCategoryLetter": "C"}, {"itemText": "The way company purchases as goods", "correctCategoryLetter": "C"}, {"itemText": "Helping the undeveloped", "correctCategoryLetter": "A"}, {"itemText": "Ensuring the people have the latest information", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "General Electronics", "categoryLetter": "A"}, {"categoryText": "Microsoft", "categoryLetter": "B"}, {"categoryText": "Whole Foods Market", "categoryLetter": "C"}]}', '[{"content": "<p>23. The disposable waste</p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án: C</strong> (Whole Foods Market)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>Spoiled produce and biodegradable waste</strong> are trucked to regional centers for <strong>composting</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong>Giải thích:</strong> Whole Foods xử lý chất thải hữu cơ và sản phẩm hỏng (disposable waste) bằng cách ủ phân (composting).</p>\n</li>\n</ul>\n<p>24. The way company purchases as goods</p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án: C</strong> (Whole Foods Market)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “The company’s <strong>sourcing emphasises purchases from local farmers</strong> through each store’s procurement process. Buyers screen out foods containing any of nearly 100 common ingredients…”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong>Giải thích:</strong> Whole Foods có quy trình tìm nguồn cung ứng (<strong>purchases as goods</strong> / sourcing) rất cụ thể, nhấn mạnh sản phẩm hữu cơ và địa phương.</p>\n</li>\n</ul>\n<p>25. Helping the undeveloped</p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án: A</strong> (General Electronics)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “A good example is General Electronics’s program to <strong>adopt under-performing public high schools</strong> near several of its major U.S. facilities.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong>Giải thích:</strong> GE hỗ trợ các trường học hoạt động kém (under-performing/undeveloped) bằng tài chính, sản phẩm và cố vấn.</p>\n</li>\n</ul>\n<p>26. Ensuring the people have the latest information</p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong>Đáp án: B</strong> (Microsoft)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “Microsoft recognizes, however, that community colleges face special challenges: IT curricula are not standardized, technology used in classrooms is often outdated, and there are no systematic <strong>professional development programs to keep faculty up to date</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong>Giải thích:</strong> Microsoft giải quyết vấn đề tài liệu lỗi thời và thiếu các chương trình phát triển chuyên môn để giữ cho giảng viên “up to date” (có thông tin mới nhất).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('d29e481d-9024-4cf5-af7e-28c6e01d0cb1', 'aac6c9e0-0787-432b-9cd7-9e089e93cb78', 'fillup', 'Questions 36–39', '<p><span class="citation-6673 citation-6674">Choose </span><strong data-path-to-node="20" data-index-in-node="51"><span class="citation-6673 citation-6674">ONE WORD ONLY</span></strong><span class="citation-6673 citation-6674 citation-end-6674"> from the text for each answer.</span></p>
<p><span class="citation-6671 citation-6672 citation-end-6672">Write your answers in boxes 36–39 on your answer sheet.</span></p>
<p id="p-rc_36e9ef002f2fc711-117" style="text-align: center;" data-path-to-node="21,0"><strong data-path-to-node="21,0" data-index-in-node="0"><span style="font-size: 14pt;">The ‘Henry’ programme</span></strong></p>
<p id="p-rc_36e9ef002f2fc711-118" data-path-to-node="21,1"><span class="citation-6667 citation-6668">‘Henry’ was used in Leeds from 2009 in th</span><span class="citation-6662 citation-6663 citation-6664 citation-6665 citation-6666 citation-6667 citation-6668 citation-end-6668">e fight against childhood obesity.</span><span class="citation-6662 citation-6663 citation-6664 citation-6665 citation-6666 citation-6667 citation-end-6667"> The programme focuses on situations such as mealtimes and bedtimes, and it en</span><span class="citation-6662 citation-6663 citation-6664 citation-6665 citation-6666">courages parents to set firm {boundaries}</span><span class="citation-6662 citation-6663 citation-6664 citation-6665 citation-6666 citation-end-6666"> during these periods.</span></p>
<p id="p-rc_36e9ef002f2fc711-119" data-path-to-node="21,2"><span class="citation-6657 citation-6658 citation-6659 citation-6660 citation-6661">According to Kim Roberts, ‘Henry’ aims to help people become more {authoritative}</span><span class="citation-6657 citation-6658 citation-6659 citation-6660"> as parents. In this way, they do not instruct children to do things, nor give them total freedom of choice as in a {permissive}</span><span class="citation-6657 citation-6658 citation-6659"> parenting style. Instead, they allow children to make some decisions for themselves. This might be a choice of vegetable at the dinner table or a decision about where a {story}</span><span class="citation-6657 citation-6658 citation-end-6658"> should be enjoyed in the evening.</span></p>
<p id="p-rc_36e9ef002f2fc711-120" data-path-to-node="21,3"><span class="citation-6655 citation-6656 citation-end-6656">Lisa, a parent who joined the programme, felt enthusiastic about</span><span class="citation-6655 citation-end-6655"> her children’s responses to it and the effect it had overall on her family.</span></p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">36. …and it encourages parents to set firm {boundaries} during these periods.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…help parents <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"28\">set boundaries</strong> for their children…” (Đoạn 1 và 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những cốt lõi của chương trình là giúp cha mẹ thiết lập các giới hạn (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"92\">boundaries</em>) rõ ràng cho con cái, đặc biệt là trong việc ăn uống và giờ giấc sinh hoạt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">37. …aims to help people become more {authoritative} as parents.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The programme encourages <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"37\">authoritative</strong> rather than authoritarian parenting…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Henry hướng phụ huynh theo phong cách “quyết đoán nhưng thấu hiểu” (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"80\">authoritative</em>) — tức là cha mẹ vẫn nắm quyền kiểm soát nhưng có sự lắng nghe và phản hồi lại nhu cầu của con, thay vì chỉ ra lệnh áp đặt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">38. …nor give them total freedom of choice as in a {permissive} parenting style.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"12\">Permissive</strong> parenting is asking children what they want to do.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chương trình không khuyến khích phong cách “nuông chiều” (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"70\">permissive</em>) — nơi mà trẻ được cho phép làm bất cứ điều gì mình muốn (tự do lựa chọn hoàn toàn), vì điều này dễ dẫn đến thói quen ăn uống không lành mạnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">39. …a decision about where a {story} should be enjoyed in the evening.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…they are asked <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"30\">where they want to read their story</strong> beforehand [bedtimes].” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì ra lệnh đi ngủ ngay lập tức, cha mẹ theo phương pháp Henry sẽ cho trẻ một lựa chọn nhỏ mang tính tích cực, ví dụ như chọn địa điểm để đọc truyện (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"166\">story</em>) trước khi ngủ, giúp trẻ cảm thấy mình có quyền tham gia vào quyết định.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('5765ac04-7cc9-40fc-a503-98c5e327d343', '38236f7c-e75a-4072-8dfa-a85f03bc2a18', 'radio', 'Questions 36-40', '', '<p>Choose<strong> YES </strong>if the statement is agrees with the claims of the writer ,<strong>NO </strong>if the statement contradicts the claims of the writer,<strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Inexpert sports players are too aware of what they are doing."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Monkeys have a more complex mirror neuron system than humans."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Looking at a photograph can activate mirror neurons."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": " Gastaut and Bert were both researchers and sports players."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The mu system is at rest when we are engaged in an activity."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">36. Inexpert sports players are too aware of what they are doing. — {YES}</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…most <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"20\">novices swing with their consciousness</strong>…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sử dụng ý thức quá nhiều đồng nghĩa với việc họ quá chú tâm/nhận thức rõ từng cử động mình đang làm, điều này cản trở sự mượt mà.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">37. Monkeys have a more complex mirror neuron system than humans. — {NO}</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"30,0,0\" data-index-in-node=\"12\">Humans have an even more elaborate</strong> mirror neuron system.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định hệ thống của người phức tạp hơn của khỉ, trái ngược hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">38. Looking at a photograph can activate mirror neurons. — {NO}</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If we are staring at a <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"35\">photograph</strong>… our mirror neurons are <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"72\">totally silent</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tế bào thần kinh gương chỉ hoạt động khi thấy hành động thực tế, không phải ảnh tĩnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">39. Gastaut and Bert were both researchers and sports players. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…two French physiologists, Gastaut and Bert, found that…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ giới thiệu họ là nhà sinh lý học, <strong data-path-to-node=\"34,1,0\" data-index-in-node=\"58\">không có thông tin</strong> họ có phải là người chơi thể thao hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">40. The mu system is at rest when we are engaged in an activity. — {YES}</strong></p>\n<ul data-path-to-node=\"36\">\n<li>\n<p data-path-to-node=\"36,0,0\"><strong data-path-to-node=\"36,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The mu system… <strong data-path-to-node=\"36,0,0\" data-index-in-node=\"29\">disappears</strong> [is quiet] whenever we do something active…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"36,1,0\"><strong data-path-to-node=\"36,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “disappears/quiet” tương ứng với trạng thái nghỉ (at rest) khi não bộ chuyển sang trạng thái thực hiện hành động.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('cb9767b1-b2d8-4abd-b1b5-56424748cc32', '763a1875-90de-4f59-9cc9-70ac74e91247', 'matrix', 'Questions 21-26', NULL, '<p>Look at the following characteristics (Questions 21-26) and the list of birds below.<br>Match each characteristic with the correct bird, A, B, or C. Choose the correct letter, A, B, or C</p>
<p>NB You may use any letter more than once.</p>
<p>Characteristics to Match</p>', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of birds", "matrixItems": [{"itemText": "keeping tools that they like to use", "correctCategoryLetter": "C"}, {"itemText": "drawing out their prey by frightening it", "correctCategoryLetter": "B"}, {"itemText": "the use of tools to remove the outer covering from food", "correctCategoryLetter": "A"}, {"itemText": "using food to attract their prey", "correctCategoryLetter": "B"}, {"itemText": "the use of unfamiliar materials to make tools", "correctCategoryLetter": "C"}, {"itemText": "engaging in certain activities for the benefit of observers", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "white-winged choughs", "categoryLetter": "A"}, {"categoryText": "black kites", "categoryLetter": "B"}, {"categoryText": "New Caledonian crows", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. Keeping tools that they like to use — {C. New Caledonian crows}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"The <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"25\">crows carry their favourite tool</strong> from one foraging site to the next. They also <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"104\">store their tools for later re-use</strong> in a secure place...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc mang theo công cụ yêu thích và cất giữ chúng để dùng lại chính là hành động giữ lại công cụ (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"110\">keeping tools</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Drawing out their prey by frightening it — {B. Black kites}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"A kite may also pick up a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"47\">smouldering stick</strong>... and drop the stick on a patch of unburned grass. The bird then feasts on the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"145\">small animals that flee from the subsequent fire</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Flee\" (tháo chạy/chạy trốn) đồng nghĩa với việc bị hoảng sợ (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"74\">frightening</strong>). Con diều hâu dùng lửa để làm con mồi sợ hãi và phải chạy ra khỏi chỗ ẩn nấp (drawing out).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. The use of tools to remove the outer covering from food — {A. Woodpecker finches}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"These tiny birds [woodpecker finches] routinely used <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"74\">twigs to extract grubs from under bark</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Bark\" (vỏ cây) chính là lớp bao phủ bên ngoài (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"60\">outer covering</strong>) của nguồn thức ăn (con ấu trùng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. Using food to attract their prey — {B. Black kites}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"For example, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"34\">black kites</strong> have been reported <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"65\">dropping bait</strong> into lakes to bring fish to the surface of the water...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Bait\" (mồi nhử - thường là thức ăn) được dùng để thu hút (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"71\">attract</strong>) con mồi (cá) nổi lên mặt nước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. The use of unfamiliar materials to make tools — {C. New Caledonian crows}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"Recently, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"31\">New Caledonian crows</strong> were observed moulding a <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"77\">piece of wire</strong>, something they had <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"111\">never seen before</strong>, into a hook...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Unfamiliar materials\" (nguyên liệu lạ) chính là đoạn dây thép (wire) mà loài chim này chưa từng nhìn thấy trước đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. Engaging in certain activities for the benefit of observers — {A White-winged choughs}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">\"Interestingly, it is <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"42\">more likely to preen the chicks if another bird can see it do so</strong>... frantically start to preen the chicks as soon as some of its <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"171\">group members come into view</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài chim này chỉ nhiệt tình rỉa lông cho chim non khi có thành viên khác trong đàn quan sát (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"106\">observers</strong>), nhằm mục đích giữ gìn vị thế xã hội.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('8d36cdb0-a0da-405a-8cfd-6a7a177193b9', '5886a9bd-50fd-4e04-9a10-3c65407c6767', 'fillup', 'Questions 36–40', '<div class="relative basis-auto flex-col -mb-(--composer-overlap-px) pb-(--composer-overlap-px) [--composer-overlap-px:28px] grow flex">
<div class="flex flex-col text-sm">
<div class="qMYqUG_convSearchResultHighlightRoot">
